-- Phase 7 INSERT part 01/6 (250 cards)
-- 자동 생성: scripts_phase7/02_json_to_sql.py

insert into public.qas
  (doctor_id, type, category, status, published,
   question, answer, keywords,
   post_year, post_slug, external_url, pubmed_ref,
   created_at, updated_at)
values
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증은 정말 유전되는 병인가요?$AAQ$, $AAA$백반증은 유전적 경향이 있지만, 부모에게 있어도 자녀에게 생길 확률은 약 6%로 그리 높지 않습니다. 일반인이 백반증에 걸릴 유병률은 약 1%로 알려져 있고, 백반증이 있는 사람의 직계가족에게는 그 6배인 6% 정도가 발병한다고 보고됩니다.

다만 반대로 보면 **100명 중 90명 이상은 자녀에게 백반증이 생기지 않으므로** 너무 걱정하지 않으셔도 됩니다. 또 유전적 형질이 동일한 일란성 쌍둥이에서도 한 명이 백반증일 때 다른 한 명에게 발병하는 비율은 25% 미만으로 알려져 있어요. 즉 **유전 형질이 같아도 75% 이상에서는 백반증이 발생하지 않는다는** 의미이기 때문에, 가족력만으로 지나치게 불안해할 필요는 없습니다.$AAA$, array['백반증', '유전', '가족력', '유병률', '쌍둥이']::text[], 2022, '355XPfOK14s-1', 'https://youtu.be/355XPfOK14s?t=101s', '{"pmid": "12753387", "doi": "10.1034/j.1600-0749.2003.00032.x", "title": "Epidemiology of vitiligo and associated autoimmune diseases in Caucasian probands and their families.", "journal": "Pigment Cell Res", "year": "2003", "authors_short": "Alkhateeb A, Fain PR, Thody A et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/12753387/", "doi_url": "https://doi.org/10.1034/j.1600-0749.2003.00032.x"}'::jsonb, '2022-11-11 00:00:00+00'::timestamptz, '2022-11-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증은 완치 가능한 병인가요?$AAQ$, $AAA$백반증은 불치병이 아니며, 특히 초기에 치료하면 거의 완치에 가깝게 좋아지는 경우도 많습니다. 진료실에서 가장 안타까운 점은 환자분들이 불치병이라 여겨 내원이 늦어지고 치료 시기를 놓치는 경우라고 합니다.

치료는 다른 피부병처럼 먹는 약과 연고를 기본으로 사용하고, 자외선 치료를 추가로 적용해요. 먹는 약은 **번짐을 막아야 하는 결정적 시기에 최소 용량으로 최대한 짧게 사용하는 원칙**으로 처방됩니다. 연고나 자외선 치료처럼 부작용이 적은 방법으로도 충분한 호전을 기대할 수 있고, 이런 방법으로도 잘 반응하지 않을 때는 수술적 치료를 고려하기도 합니다. 물론 **치료가 어려운 경우도 분명히 있지만**, 의료진을 믿고 꾸준히 치료하면 좋은 결과를 얻을 수 있어요.$AAA$, array['백반증치료', '완치가능성', '초기치료', '경구약', '자외선치료']::text[], 2022, '355XPfOK14s-2', 'https://youtu.be/355XPfOK14s?t=178s', '{"pmid": "39734899", "doi": "10.1016/j.mjafi.2022.08.010", "title": "Study to evaluate effect of oral mini pulse corticosteroid therapy for unstable vitiligo on hypothalamic pituitary adrenal axis suppression.", "journal": "Med J Armed Forces India", "year": "2022", "authors_short": "Sinha P, Sood A, Mukherjee B et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/39734899/", "doi_url": "https://doi.org/10.1016/j.mjafi.2022.08.010"}'::jsonb, '2022-11-11 00:00:00+00'::timestamptz, '2022-11-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증은 왜 눈, 코, 입 주변에 잘 생기나요?$AAQ$, $AAA$백반증은 마찰이나 자극이 잦은 부위에 호발하는데, 이를 **쾨브너 현상**이라고 부릅니다. 눈을 비비거나 코와 입 주변을 만지는 동작이 반복되면서 해당 부위가 백반증으로 변하는 거예요.

그래서 얼굴에서는 눈·코·입 주변과 헤어라인, 그리고 손끝과 발끝, 벨트가 닿는 허리 주변, 팔꿈치·무릎 같은 마찰이 많은 부위에 잘 생깁니다. 호발 부위를 보면 백반증이 왜 생겼고 어떤 자극을 줄여야 번짐을 막을 수 있는지 단서를 얻을 수 있어, 부위에 따라 치료 방법이나 예후도 달라집니다. **알레르기로 가렵거나 할 때 비비는 대신 약을 먹고 손을 대지 않는 습관**을 들이는 것이 중요해요. 일상에서 자극 행위를 줄이는 작은 변화가 백반증 관리의 큰 부분을 차지합니다.$AAA$, array['쾨브너현상', '마찰자극', '호발부위', '백반증예방', '생활습관']::text[], 2022, '355XPfOK14s-3', 'https://youtu.be/355XPfOK14s?t=254s', '{"pmid": "41913313", "doi": "10.1093/bjd/ljag113", "title": "Unanchored by two hits: IFNγ and mechanical stress synergize to undermine melanocyte adhesion and promote vitiligo.", "journal": "Br J Dermatol", "year": "2026", "authors_short": "Lee EJ, Kwon IJ, Kim JY et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/41913313/", "doi_url": "https://doi.org/10.1093/bjd/ljag113"}'::jsonb, '2022-11-11 00:00:00+00'::timestamptz, '2022-11-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증 수술은 왜 귀 뒤에서 피부를 떼나요?$AAQ$, $AAA$백반증 수술 중 미세 펀치 시술은 정상 피부를 작게 떼어 백반증 부위에 옮겨 심는 방법이며, 귀 뒤의 정상 피부를 주로 사용합니다. 귀 뒤가 **움직임이 가장 적기 때문에 흉터가 가장 적게 생기고**, 흉터가 남더라도 잘 보이지 않아 채취 부위로 선호됩니다.

과거에 시행하던 피부 이식술은 과정이 힘들고 통증이 심해 지금은 잘 하지 않습니다. 대신 펀칭 기구로 정상 피부를 작게 떼어 백반증 병변에 듬성듬성 심어주고, 이후 자외선 치료나 엑시머 레이저를 병행해 **심어준 부분에서 색깔이 퍼져나가 병변이 채워지는 방식**으로 진행돼요. 이 수술은 통증이 거의 없고 작은 부위도 정밀하게 옮겨 심을 수 있어 어린아이부터 어른까지 부담 없이 받을 수 있다고 합니다.$AAA$, array['미세펀치시술', '백반증수술', '귀뒤피부', '이식부위', '엑시머레이저']::text[], 2022, '355XPfOK14s-4', 'https://youtu.be/355XPfOK14s?t=455s', '{"pmid": "40027529", "doi": "10.25259/JCAS_144_2024", "title": "Customized short punches for mini punch grafting in vitiligo.", "journal": "J Cutan Aesthet Surg", "year": "2025", "authors_short": "Kerure AS, Ghia DH, Sabhandasani SP et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/40027529/", "doi_url": "https://doi.org/10.25259/JCAS_144_2024"}'::jsonb, '2022-11-11 00:00:00+00'::timestamptz, '2022-11-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부과 화이트닝은 정말 하얗게 되는 건가요?$AAQ$, $AAA$피부과 화이트닝은 얼굴을 눈처럼 새하얗게 만드는 게 아니라, 피부의 색소를 제거해 **전체적인 톤을 균일하게 맞춰주는 과정**입니다. 톤이 어둡더라도 얼룩덜룩함이 정리되면 얼굴 자체가 훨씬 깨끗하고 밝아 보여요.

레이저토닝을 반복하면 피부 속 멜라닌 색소의 양이 줄어 어느 정도는 밝아질 수 있지만, 원래 어두운 피부가 하얀 사람처럼 완전히 변하는 것은 아닙니다. 전반적인 톤을 살짝 끌어올리는 정도이며, **얼룩덜룩한 색소를 균일하게 맞춰주는 효과가 본질**입니다. 진료실에서 진단을 위해 특수촬영기로 촬영도 하고 직접 보고 만져보며 색소가 표피에 있는지 진피 깊숙이 있는지 확인하는 이유도 이 때문이에요. 병변의 종류·깊이·피부 노화 상태에 따라 적합한 레이저와 에너지가 달라집니다.$AAA$, array['피부화이트닝', '레이저토닝', '균일한톤', '색소진단', '피부톤']::text[], 2022, 'dmKPwe3bFXI-1', 'https://youtu.be/dmKPwe3bFXI?t=22s', null, '2022-11-11 00:00:00+00'::timestamptz, '2022-11-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레이저토닝은 어떻게 색소를 없애나요?$AAQ$, $AAA$레이저토닝은 **일상생활에 불편함이 없을 만큼 낮은 에너지로 멜라닌 색소만 선택적으로 부수는 레이저 기술**입니다. 토닝 레이저는 Nd:YAG 매질을 이용해 1,064nm 파장을 얼굴 전체에 시술하는데, 이 파장이 멜라닌 색소에 선택적으로 작용해 색소를 잘게 부숴줍니다.

최근에는 나노 단위뿐 아니라 **피코 단위 파장을 이용하는 피코 토닝 레이저도 많이 사용되고** 있어요. 화이트닝 치료에 여러 레이저가 동원되지만 토닝이 가장 많이 쓰이는 건 그만큼 안전성과 효과가 검증되었기 때문입니다. 다만 토닝이 전부는 아니며, 색소가 표피에 있는 병변은 CO2나 어븀 같은 박피 레이저로, 진피 깊숙한 색소는 깊은 파장의 레이저로 여러 번 반복 치료가 필요해요. 홍조나 붉은 자국에는 혈관 레이저를 병행하기도 합니다.$AAA$, array['레이저토닝원리', 'Nd:YAG', '1064nm', '피코토닝', '멜라닌선택성']::text[], 2022, 'dmKPwe3bFXI-2', 'https://youtu.be/dmKPwe3bFXI?t=344s', null, '2022-11-11 00:00:00+00'::timestamptz, '2022-11-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기미 치료는 한 번에 다 없어지나요?$AAQ$, $AAA$대부분의 색소는 **여러 번 반복적인 치료가 필요하고, 한 번에 없어지는 병변은 드뭅니다**. 색소가 피부 바깥층에 있는 병변은 CO2나 어븀 레이저로 표면을 깎아내거나 IPL로 딱지를 지게 만들어 빨리 좋아질 수 있어요.

그러나 색소가 피부 깊숙이 있는 경우에는 표면을 날리는 방법으로는 손상만 초래하고 호전이 어렵습니다. 이때는 **깊은 파장의 레이저로 여러 번 반복 치료를 받아야 좋아지는 병변**이에요. 그리고 치료 후에도 재발할 수 있어요. 색소가 생긴 원인이 자외선에 의한 멜라닌 세포 자극이라, 자외선을 완전히 차단할 수 없는 한 다시 올라올 수 있습니다. 대청소에 비유하자면 한 번 싹 정리한 후에도 약간의 에너지로 꾸준히 정돈해야 깨끗한 상태가 유지된다고 생각하시면 됩니다.$AAA$, array['기미치료', '반복치료', '색소깊이', '재발관리', '유지치료']::text[], 2022, 'dmKPwe3bFXI-3', 'https://youtu.be/dmKPwe3bFXI?t=466s', null, '2022-11-11 00:00:00+00'::timestamptz, '2022-11-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여름에도 레이저토닝을 받아도 되나요?$AAQ$, $AAA$레이저토닝은 여름에도 받을 수 있으며, **레이저 치료 효과는 여름과 겨울에 차이가 나지 않습니다**. 다만 여름에는 해가 떠 있는 시간이 길고 자외선이 강하며 여름휴가로 노출이 많을 수 있어, 직업적으로 야외에서 일하거나 자외선을 많이 받는 분은 일정을 미루는 편이 좋아요.

그 이유는 **치료 후에도 햇빛을 받으면 금방 재발할 수 있고, 피부가 태닝되어 까매지면 레이저가 잘 작용하지 않기 때문**입니다. 반대로 실내에서 주로 일하고 특별히 햇빛 노출이 적다면 여름에도 부담 없이 받을 수 있습니다. 점 빼는 시술은 조금 다른데, 시술 부위에 물이 들어가면 안 되기 때문에 땀이 많이 나는 분은 날씨가 선선해진 뒤로 미루도록 권하기도 해요. 결국 본인의 자외선 노출 상황과 시술 종류에 따라 판단하는 것이 합리적입니다.$AAA$, array['여름레이저', '자외선노출', '태닝주의', '점빼기', '시술시기']::text[], 2022, 'dmKPwe3bFXI-4', 'https://youtu.be/dmKPwe3bFXI?t=663s', null, '2022-11-11 00:00:00+00'::timestamptz, '2022-11-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레이저 받으면 피부가 더 예민해지나요?$AAQ$, $AAA$최근의 레이저 시술 후 피부가 영구히 예민해지는 경우는 드물고, 적절한 관리만 병행하면 부작용 없이 효과를 얻을 수 있습니다. 예전에는 **프락셀 같은 흉터 레이저를 매우 센 에너지로 치료해 홍조가 생기거나 민감해지는 경우**가 있었어요.

그러나 요즘은 레이저 기기 자체가 발전했고, 병원에서도 무리하게 센 에너지로 시술하지 않으며, 시술 후 그에 맞는 관리를 함께 진행하기 때문에 충분히 안전합니다. 다만 원래 피부 장벽이 손상되어 있는 민감 피부라면 다른 사람에게 효과 좋은 레이저도 자극이 될 수 있어요. 이런 경우에는 **피부 장벽을 개선하고 염증을 줄여주는 레이저를 선택**해야 합니다. 따라서 시작 전 본인의 피부 상태를 정확히 판단하고 충분한 상담을 통해 목표를 세운 뒤 치료를 시작하는 것이 중요하며, 경우에 따라 약이나 관리부터 먼저 받는 편이 나을 수도 있어요.$AAA$, array['레이저부작용', '민감피부', '프락셀', '피부장벽', '맞춤레이저']::text[], 2022, 'dmKPwe3bFXI-5', 'https://youtu.be/dmKPwe3bFXI?t=581s', null, '2022-11-11 00:00:00+00'::timestamptz, '2022-11-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$점과 피부암은 어떻게 구분하나요?$AAQ$, $AAA$점과 피부암을 구분하는 가장 흔한 기준은 **A·B·C·D·E 룰**입니다. A(Asymmetry)는 비대칭, B(Border)는 경계 불규칙성, C(Color)는 색상의 혼재, D(Diameter)는 직경, E(Evolution)는 시간에 따른 변화를 의미해요.

일반 점은 보통 좌우와 위아래가 대칭적이지만 피부암은 대칭이 무너집니다. 경계도 일반 점은 규칙적인 반면, 피부암은 울퉁불퉁한 경우가 많아요. 색상은 옅거나 진한 갈색으로 균일하게 보이는 일반 점과 달리, **피부암은 흰색·붉은색·검은색 등 여러 색이 혼재**되어 나타날 수 있습니다. 크기는 **6mm 이상이거나 1mm였던 점이 6mm로 커진 경우** 검사를 권합니다. 시간이 지나면서 점이 커지거나 색이 바뀌거나 피가 나는 등 없던 증상이 생긴다면 진료를 받아야 해요.$AAA$, array['ABCDE룰', '점구분법', '피부암자가진단', '비대칭경계', '직경6mm']::text[], 2022, 'fh3HBBzdzY0-1', 'https://youtu.be/fh3HBBzdzY0?t=66s', null, '2022-11-11 00:00:00+00'::timestamptz, '2022-11-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기저세포암과 편평세포암은 원인이 다른가요?$AAQ$, $AAA$두 암은 자외선 노출 양상이 다른 점에서 본질적으로 구분되는 피부암입니다. **기저세포암은 간헐적으로 짧게 과다 노출되는 자외선이 큰 위험인자**로 알려져 있어요.

예를 들어 평상시에는 실내에 있다가 여름이나 자외선이 강할 때 간헐적으로 태닝을 하는 경우 기저세포암 위험이 높아집니다. 반면 두 번째로 흔한 피부암인 **편평세포암은 꾸준히 장기간 자외선에 노출되는 것이 위험인자**로 알려져 있어요. 직업적 원인으로 자주 외출하거나 야외에서 일하는 분들은 편평세포암 위험이 상대적으로 높습니다. 피부암 발생의 기전은 자외선이 세포 DNA를 손상시키고, 손상된 DNA 복구 기전에 이상이 생기며, 면역 저하가 동반되는 복잡한 과정으로 설명돼요. 노출 양상에 따라 위험이 달라지므로 본인의 생활 패턴을 점검하는 게 중요합니다.$AAA$, array['기저세포암', '편평세포암', '광발암', '간헐적자외선', '장기자외선']::text[], 2022, 'fh3HBBzdzY0-2', 'https://youtu.be/fh3HBBzdzY0?t=170s', null, '2022-11-11 00:00:00+00'::timestamptz, '2022-11-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$흐린 날에도 자외선 차단제를 발라야 하나요?$AAQ$, $AAA$흐린 날에도 자외선 차단제를 예외 없이 발라야 합니다. **자외선은 구름을 뚫고 지표면에 도달**하기 때문에 흐린 날씨라고 안심해서는 안 돼요.

바르는 시점은 외출하기 **20분에서 30분 전이 적당**하며, 번거롭더라도 2~3시간마다 한 번씩 덧발라주는 것이 좋습니다. 자외선 차단제는 단순히 미용 목적이 아니라 피부암 예방의 핵심 수단이에요. 또 한 가지 중요한 점은 자가 검진입니다. 내 몸의 수많은 점을 모두 검사받기는 어렵기 때문에 전신거울을 사용해 스스로 관찰하고, 의심되는 병변은 1개월·3개월·6개월 간격으로 사진을 찍어 변화를 비교해보세요. 점들이 비슷하게 생겼는데 어느 하나만 이상하게 돋보이는 미운 오리 새끼 사인이 보인다면 피부암을 한 번쯤 의심해 볼 수 있습니다.$AAA$, array['자외선차단제', '흐린날', '덧바르기', '자가검진', '미운오리새끼']::text[], 2022, 'fh3HBBzdzY0-3', 'https://youtu.be/fh3HBBzdzY0?t=243s', null, '2022-11-11 00:00:00+00'::timestamptz, '2022-11-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$점이 튀어나오면 피부암인가요?$AAQ$, $AAA$점이 튀어나왔다고 해서 무조건 피부암인 것은 아니며, 일반 점에서도 흔히 관찰되는 모양입니다. 점은 **점세포라는 세포가 증식해 생기는 양성 병변**이에요.

점세포가 조금만 증식되어 있으면 편평하게 관찰되지만, 점세포가 많이 증식되어 있으면 **위로 볼록하게 융기되어 관찰될 수** 있습니다. 즉 융기 자체는 양성 점의 정상 범위 안에 있을 수 있는 변화입니다. 다만 융기와 함께 비대칭이 생기거나 색깔이 혼재되거나 크기가 빠르게 커지거나 피가 나는 등 다른 신호가 동반된다면 진료를 받아보는 게 좋습니다. 또 진료실에서 점을 빼러 왔다가 피부암으로 진단되는 경우도 있어, **단순한 점처럼 보여도 의심 신호가 보이면 검사를 받는 것이** 치료 시기를 놓치지 않는 방법이에요.$AAA$, array['볼록한점', '점세포증식', '양성병변', '융기점', '점검사']::text[], 2022, 'fh3HBBzdzY0-4', 'https://youtu.be/fh3HBBzdzY0?t=334s', null, '2022-11-11 00:00:00+00'::timestamptz, '2022-11-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부 관리에서 가장 중요한 한 가지는 뭔가요?$AAQ$, $AAA$피부 관리에서 가장 중요한 한 가지는 **자외선 차단**입니다. 영상 속 원장님은 늦잠을 자서 5분 안에 나가야 할 때도 다른 건 다 빼더라도 선크림은 꼭 바르고 나가며, 집 앞 마트에 잠깐 갈 때도 선크림과 모자를 챙긴다고 합니다.

그 이유는 우리가 타고난 피부는 바꿀 수 없지만 **후천적으로 노력해 효과를 볼 수 있는 거의 유일한 방법이 자외선 차단**이기 때문이에요. 자외선은 피부 노화, 색소, 광노화의 근본 원인으로 작용하므로 차단을 우선순위에 두는 것이 가장 과학적이고 효과적인 접근입니다. 다른 화장품이나 시술을 더한다 해도 자외선 차단이 빠지면 효과가 상쇄될 수 있어, 모닝 루틴에서 자외선 차단제는 절대 생략하지 않는 한 가지로 강조됩니다.$AAA$, array['자외선차단제', '선크림', '모닝루틴', '광노화예방', '필수단계']::text[], 2022, 'noid-1', null, null, '2022-11-16 00:00:00+00'::timestamptz, '2022-11-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$히알루론산 앰플은 정말 효과가 있나요?$AAQ$, $AAA$히알루론산 앰플은 보습과 화장 밀착감 면에서 체감 차이가 있는 성분입니다. **히알루론산은 자기 분자량의 약 1,000배 정도의 물을 끌어당기는 힘**이 있기 때문이에요.

영상 속 원장님은 아침 루틴으로 약산성 클렌저 세안 후 히알루론산 앰플, 로션과 크림, 자외선 차단제를 차례로 바르는 것이 모닝 루틴이라고 소개합니다. 히알루론산 앰플을 쓴 날과 안 쓴 날을 비교하면 메이크업이 잘 발리는 느낌이 들고 **하루 종일 촉촉한 피부가 유지되는 차이**가 분명하다고 해요. 또 아토피 피부 같은 민감 피부에서도 제형이 묽은 편이라 자극감이 덜한 편이라 사용할 만하다고 합니다. 다만 개인의 피부 상태에 따라 체감 정도가 다르므로 본인에게 잘 맞는 한 가지 제품을 꾸준히 쓰는 편이 좋습니다.$AAA$, array['히알루론산앰플', '분자량1000배', '보습효과', '수분유지', '민감피부']::text[], 2022, 'noid-2', null, null, '2022-11-16 00:00:00+00'::timestamptz, '2022-11-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스크럽 제품은 사용해도 되나요?$AAQ$, $AAA$스크럽 제품은 피부과 의사들이 거의 사용하지 않는 클렌징·각질 제거 제품입니다. 영상 속 두 원장님 모두 **스크럽 제품은 절대 사용하지 않는다**고 답했으며, 다른 피부과 원장님들도 마찬가지라고 알고 있다고 합니다.

이유는 예민하지 않은 피부에서도 **스크럽 입자가 피부에 자극을 강하게 주는 경우가 있기** 때문입니다. 대신 각질이 신경 쓰일 때는 마일드한 AHA 성분이 포함된 제품을 사용해 1~2분 정도 스케일링을 진행하고 이후 씻어낸 다음 보습 크림을 듬뿍 발라주는 방식이 권장돼요. 그래도 해결되지 않을 정도로 피부가 푸석거리거나 피곤할 때는 병원의 보습 관리 장비를 이용하는 편이 안전합니다. 환자분들은 종종 각질 제거를 당연한 절차로 여기지만, 피부과적으로는 자극을 줄이는 방향이 우선입니다.$AAA$, array['스크럽금기', 'AHA스케일링', '각질제거', '마일드필링', '피부자극']::text[], 2022, 'noid-3', null, null, '2022-11-16 00:00:00+00'::timestamptz, '2022-11-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$마스크 팩은 매일 해도 괜찮은가요?$AAQ$, $AAA$마스크 팩은 피부 상태가 좋을 때 하면 도움이 되지만, **피부 상태가 좋지 않을 때 사용하면 오히려 악화될 수** 있습니다. 건강한 피부에서는 팩의 보습과 좋은 성분이 흡수되어 피부에 도움이 됩니다.

그러나 대부분의 사람들은 거꾸로 피부가 거칠어지고 상태가 나빠졌을 때 팩을 시도하는 경우가 많아요. **피부 장벽이 무너져 있는 상태에서 마스크 팩을 사용하면 평소에 효과가 좋았던 성분도 자극이 되어** 더 붉어지거나 트러블이 심해질 수 있습니다. 좋아지려고 또 다른 팩을 시도하면서 악순환이 반복되는 일이 흔해요. 따라서 팩은 피부가 건강한 상태에서 가끔 즐기는 보조 수단으로 활용하고, 피부 컨디션이 좋지 않을 때는 휴식과 보습으로 장벽 회복에 집중하는 편이 낫습니다.$AAA$, array['마스크팩', '피부장벽', '트러블악화', '팩빈도', 'K뷰티']::text[], 2022, 'noid-4', null, null, '2022-11-16 00:00:00+00'::timestamptz, '2022-11-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$메이크업 클렌징은 어떻게 해야 자극이 적나요?$AAQ$, $AAA$메이크업 클렌징의 핵심은 **최대한 피부를 문지르지 않는 것**입니다. 화장은 스스로 지워지지 않아 피부를 문질러야 하는데, 매일 반복되는 이 동작이 누적되면 피부에 자극이 됩니다.

그래서 원장님은 색조 화장을 지울 때 **피부를 많이 문지르지 않아도 되는 클렌징 밀크를 발라 씻어내듯이 사용**합니다. 아이 메이크업은 리무버로 화장솜을 푹 적신 뒤 눈에 잠시 붙여 화장이 불어 떨어지게 만든 다음 부드럽게 닦아내는 방식을 씁니다. 또 얼굴의 가측·턱 밑·입술 밑·코 옆 같은 움푹 패인 부위는 클렌징이 소홀해지기 쉬워 색조 잔여물이 남으면 트러블이 생기기 쉬워요. 충분한 양의 클렌저를 사용해 얼굴 전체를 부드럽지만 꼼꼼하게 세안하는 것이 트러블 예방에 도움이 됩니다.$AAA$, array['클렌징밀크', '이중세안', '아이리무버', '문지름최소화', '트러블예방']::text[], 2022, 'noid-5', null, null, '2022-11-16 00:00:00+00'::timestamptz, '2022-11-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$바디 화이트닝은 얼굴 화이트닝과 어떻게 다른가요?$AAQ$, $AAA$바디 화이트닝은 얼굴과 같은 색소침착 치료 원리지만, **몸은 얼굴보다 모공·피지샘 같은 재생기관 밀도가 떨어져 염증과 색소침착이 오래 가는** 특징이 있습니다. 모공 아래 모낭과 옆 피지샘이 피부 재생을 돕는 샘물 같은 역할을 하는데, 몸에는 이런 구조물이 적어요.

그래서 상처나 염증이 생기면 색소침착이 더 오래 남죠. 대상은 아토피 후 색소침착, 모낭염이 가라앉으며 생긴 얼룩, 상처 자국, 목·겨드랑이·팔·다리·엉덩이·사타구니까지 다양합니다. 그런데 치료 결과를 보면 **바디 토닝은 얼굴 화이트닝보다 오히려 결과가 더 좋고 재발도 드문 편**이에요. 원인이 해결되었다면 남은 재만 청소하면 되기 때문에, 어떤 분은 10번, 어떤 분은 30번 정도면 만족스러운 결과를 얻을 수 있고 만족도도 높다고 합니다.$AAA$, array['바디토닝', '재생기관밀도', '염증후색소침착', '치료효과', '부위차이']::text[], 2022, 'MRTSFYURaHw-1', 'https://youtu.be/MRTSFYURaHw?t=44s', null, '2022-11-18 00:00:00+00'::timestamptz, '2022-11-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$겨드랑이 색소침착도 토닝으로 빠지나요?$AAQ$, $AAA$겨드랑이나 사타구니 같이 살이 겹치는 부위의 색소침착은 단순 토닝만으로는 잘 빠지지 않을 수 있습니다. **이 부위는 곰팡이균 감염인 백선이 잘 생기는데, 곰팡이 치료 없이 토닝만 하면 원인이 남아 있어** 치료가 늦어지기 때문이에요.

살이 겹치고 습한 환경이 곰팡이 번식에 유리해 색소침착이 동반된 피부 질환으로 이어집니다. 또 목에 때처럼 보이는 색소침착 중에는 'Terra firma-forme dermatosis'라는 특이한 질환이 있어, 때수건으로 세게 문질러도 안 빠지지만 **알코올 솜으로 슥 닦으면 금방 지워지는** 경우도 있어요. 그래서 무턱대고 토닝만 받기보다 피부질환 여부를 먼저 진단해야 합니다. 진단 결과에 따라 먹는 약, 연고, 보습제 등을 병행하거나 흑색가시세포증처럼 비만·당뇨 관리가 필요한 경우 생활습관 교정이 함께 가야 재발을 막을 수 있습니다.$AAA$, array['겨드랑이색소침착', '백선', '곰팡이감염', 'Terra firma', '동반질환']::text[], 2022, 'MRTSFYURaHw-2', 'https://youtu.be/MRTSFYURaHw?t=361s', null, '2022-11-18 00:00:00+00'::timestamptz, '2022-11-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$몸 색소침착에 바르는 미백 화장품은 효과가 있나요?$AAQ$, $AAA$미백 기능성 화장품은 보조적 효과는 있지만 **함량이 낮아 몸 색소침착을 완전히 빼기에는 한계**가 있습니다. 니아신아마이드나 비타민C 같은 미백 성분이 들어 있어도 화장품 특성상 농도가 높지 않은 경우가 많아요.

얼굴 기미용 화장품을 아무리 발라도 잘 빠지지 않는 것처럼, 몸 색소도 화장품만으로는 충분한 효과를 보기 어렵습니다. 대신 병원에서 처방받을 수 있는 제품으로 **하이드로퀴논 연고가 멜라닌 합성을 도와주는 효소를 억제**해 화이트닝을 돕고, 트레티노인 성분이 포함된 스티바-에이 연고는 **각질을 필링해 각질층 색소가 빨리 빠져나가도록 하는 효과**가 있어요. 한편 시중의 화이트 태닝은 633nm 근적외선 파장으로 피부 재생을 도와 환해 보이게 할 뿐 실제로 침착된 색소 자체가 빠지는 것은 아니므로, 기대치를 분명히 하고 접근해야 합니다.$AAA$, array['미백화장품', '하이드로퀴논', '스티바에이', '화이트태닝', '근적외선']::text[], 2022, 'MRTSFYURaHw-3', 'https://youtu.be/MRTSFYURaHw?t=566s', null, '2022-11-18 00:00:00+00'::timestamptz, '2022-11-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$운전할 때 한쪽만 색소침착이 생기나요?$AAQ$, $AAA$운전을 하는 분들은 **운전석 방향인 왼쪽으로 색소침착이 더 잘 생기는 경향**이 있으며, 조수석에 자주 타는 분들은 반대로 오른쪽에 색소침착이 잘 생깁니다. 이는 평상시 자외선 노출이 한쪽에 누적되기 때문입니다.

특히 50~60대 여성 환자분들의 손등에 색소침착이 두드러지는 경우가 많은데, 해수욕장 같은 특별한 노출 상황뿐 아니라 평상시 여름에 반팔이나 반바지를 입을 때 팔·다리·목 뒤에 자외선이 누적되어 생긴 결과예요. 우리는 얼굴에는 선크림을 열심히 바르면서 몸에는 잘 안 바르는 경향이 있는데, **팔·다리·목 뒤에도 선크림을 챙겨 바르면 색소침착이 훨씬 덜 생길 수** 있습니다. 평소 자주 노출되는 부위가 어디인지 점검하고 그 부위 위주로 자외선 차단을 강화하는 것이 가장 단순하면서도 효과적인 예방법입니다.$AAA$, array['운전자색소침착', '비대칭', '손등', '팔다리선크림', '광노화']::text[], 2022, 'MRTSFYURaHw-4', 'https://youtu.be/MRTSFYURaHw?t=536s', null, '2022-11-18 00:00:00+00'::timestamptz, '2022-11-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$등 모낭염 자국은 토닝으로 사라지나요?$AAQ$, $AAA$등 모낭염 후 남은 색소침착도 토닝으로 충분히 좋아질 수 있는 병변입니다. 다만 **염증이 남아 있는 상태에서는 색소가 잘 빠지지 않기 때문에, 먼저 약을 사용해 염증을 완전히 가라앉힌 뒤 레이저에 들어가는 것이** 핵심이에요.

영상에서는 대학 입학을 앞둔 남성 환자가 등과 가슴 전체에 모낭염이 심해 색소침착이 달마시안처럼 남았던 사례가 소개됩니다. 일반 약에 잘 반응하지 않다가 곰팡이 향진균제로 바꾼 뒤 염증이 가라앉았고, 붉은 기가 완전히 빠진 다음 레이저를 시작했어요. **처음 10번 시술 후 많이 좋아지고 추가로 10번을 더 받아** 총 20회 정도 치료로 거의 깨끗해진 사례입니다. 결국 원인 치료를 선행하고 색소만 남은 단계에서 토닝을 시작해야 효과적이며, 횟수는 사람마다 다르지만 꾸준한 반복 치료가 필요합니다.$AAA$, array['등모낭염', '색소침착', '20회시술', '원인치료선행', '곰팡이감염']::text[], 2022, 'MRTSFYURaHw-5', 'https://youtu.be/MRTSFYURaHw?t=222s', null, '2022-11-18 00:00:00+00'::timestamptz, '2022-11-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름은 왜 생기나요?$AAQ$, $AAA$여드름은 **모낭에 붙어 있는 피지샘에 생기는 염증**이며, 발생 기전은 네 가지로 정리됩니다. 첫째 피지샘에서 피지가 과다 분비될 때, 둘째 모낭의 각화에 이상이 생기는 과각화로 모공이 막혀 피지 배출이 안 될 때, 셋째 막힌 모공 아래에서 여드름균이 증식할 때, 넷째 이 세 과정이 합쳐져 결국 염증이 생길 때예요.

간단히 정리하면 **피지가 많이 만들어지고 그것이 잘 배출되지 않을 때 여드름이 발생**합니다. 여기에 스트레스, 식습관, 수면 패턴, 유전적 요인도 영향을 줄 수 있어요. 그래서 단순히 화장품으로 해결하기 어렵고, 원인이 무엇인지 정확하게 판단해 그에 맞는 치료를 받는 것이 중요합니다. 무턱대고 짜거나 자가 처치하지 말고 병원에서 진단을 받는 편이 안전합니다.$AAA$, array['여드름원인', '피지과다', '모공과각화', '여드름균', '염증반응']::text[], 2022, 'Yzq717fRvzM-1', 'https://youtu.be/Yzq717fRvzM?t=44s', null, '2022-11-22 00:00:00+00'::timestamptz, '2022-11-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$사춘기 여드름과 성인 여드름은 어떻게 다른가요?$AAQ$, $AAA$두 여드름은 호발 부위와 원인이 다르다는 점에서 본질적으로 구분됩니다. 사춘기 여드름은 **피지 분비가 많은 T존에 잘 생기는 반면, 성인 여드름은 주로 입 주변과 턱에 더 많이 발생**해요.

사춘기에는 2차 성징으로 안드로겐 호르몬 분비가 증가해 피지가 늘어나는 것이 주된 원인입니다. 반면 성인 여드름은 모공이 막히거나 피지 배출이 잘 안 되는 경우가 훨씬 많아 피지 분비가 많지 않은 건성 피부에서도 생길 수 있어요. **장기간 마스크 착용으로 피부 장벽이 무너지거나 메이크업, 음주, 수면 부족, 스트레스, 불규칙한 식습관, 잘못된 세안이 악화 인자**가 됩니다. 그래서 사춘기 여드름과 성인 여드름은 치료 방법도 다르며, 병원에서 정확한 진단과 원인을 찾는 것이 중요합니다.$AAA$, array['사춘기여드름', '성인여드름', 'T존', '안드로겐', '건성여드름']::text[], 2022, 'Yzq717fRvzM-2', 'https://youtu.be/Yzq717fRvzM?t=131s', null, '2022-11-22 00:00:00+00'::timestamptz, '2022-11-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 환자도 우유나 단백질 보충제를 마셔도 되나요?$AAQ$, $AAA$유제품과 단백질 보충제는 여드름을 악화시킬 수 있는 식품군입니다. **우유나 치즈에 든 카제인 성분이 IGF-1 분비를 촉진해 피지 생성과 모낭 과각화를 유도**하기 때문이에요.

특히 무지방·저지방 우유는 지방 함량이 적은 대신 카제인이 더 많이 들어 있어 일반 우유보다 여드름을 더 유발할 수 있다는 점에 유의해야 합니다. 운동인이 즐겨 마시는 단백질 보충제의 **유청단백질도 여드름을 일으키는 식품**으로 분류돼요. 같은 맥락에서 당부하지수가 높은 음식, 탄산음료, 초콜릿, 사탕도 혈당을 빠르게 올려 인슐린과 IGF-1을 자극하므로 여드름을 악화시킵니다. 모두 끊기 어렵다면 일주일에 세 번 먹던 것을 한 번으로 줄이는 식으로 횟수를 점진적으로 조절해 보세요. 잦은 음주도 염증 반응을 증가시키므로 피하는 것이 좋고, 반면 등푸른 생선의 오메가3는 IGF-1 분비와 염증 생성을 억제해 도움이 됩니다.$AAA$, array['유제품', '카제인', 'IGF-1', '당부하지수', '유청단백질']::text[], 2022, 'Yzq717fRvzM-3', 'https://youtu.be/Yzq717fRvzM?t=222s', null, '2022-11-22 00:00:00+00'::timestamptz, '2022-11-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름이 있어도 자외선 차단제를 발라야 하나요?$AAQ$, $AAA$여드름 피부에서도 자외선 차단제는 필수이며, 다만 **제품 선택이 일반인보다 중요**합니다. 햇빛은 피부 재생력을 떨어뜨리고 색소침착을 심화시켜 원래 있던 여드름 자국을 더 두드러지게 만들기 때문이에요.

실제로 피부 온도가 1도 올라갈 때마다 피지 분비가 약 10% 정도 증가한다는 점도 자외선 노출을 피해야 하는 이유 중 하나입니다. 향료나 일부 화학적 성분이 염증을 악화시킬 수 있어, **아보벤존·벤조페논·메톡시시나메이트·파바옥시벤존 성분이 들어가지 않은 제품을 선택**해야 해요. 또 3~4시간 간격으로 덧발라야 하므로 오일 성분이 많은 자외선 차단제는 모공을 막아 여드름을 악화시킬 수 있어 오일프리 제품이 적합합니다. 제형은 크림이나 밤처럼 되직한 타입보다 겔이나 가벼운 로션 타입이 좋습니다.$AAA$, array['여드름선크림', '오일프리', '벤조페논회피', '겔타입', 'non-comedogenic']::text[], 2022, 'Yzq717fRvzM-4', 'https://youtu.be/Yzq717fRvzM?t=444s', null, '2022-11-22 00:00:00+00'::timestamptz, '2022-11-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름이 있으면 보습제를 발라야 하나요?$AAQ$, $AAA$여드름 피부도 **보습제는 꼭 발라야 합니다**. 피지 분비가 많아 보습제가 모공을 막을까 두려워 아무것도 안 바르거나 스킨만 바르는 분들이 많지만 이는 오히려 역효과예요.

보습이 제대로 되지 않으면 **피부가 보상적으로 피지를 더 많이 만들어내고 장벽 회복이 늦어져 여드름이 악화**됩니다. 다만 너무 유분기 많은 제품이나 이것저것 여러 화장품을 동시에 쓰면 여드름이 심해질 수 있어, 'non-comedogenic'이라 표시된 여드름을 유발하지 않는 화장품을 한두 가지만 골라 쓰는 화장품 다이어트가 권장돼요. 건조하다고 느끼면 같은 보습제를 여러 번 덧발라 해결합니다. 또 수면 부족도 피부의 턴오버 주기를 무너뜨려 오래된 각질이 모공을 막으므로, **밤 10시부터 새벽 2시 사이를 포함한 6~7시간의 충분한 수면**이 도움이 됩니다.$AAA$, array['여드름보습', 'non-comedogenic', '화장품다이어트', '수면시간', '피부장벽']::text[], 2022, 'Yzq717fRvzM-5', 'https://youtu.be/Yzq717fRvzM?t=507s', null, '2022-11-22 00:00:00+00'::timestamptz, '2022-11-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$써마지와 울쎄라는 어떻게 다른가요?$AAQ$, $AAA$써마지와 울쎄라는 작용 원리와 효과 방향이 본질적으로 다른 리프팅 장비입니다. **울쎄라는 고강도 집속 초음파(HIFU)로 근막층(SMAS)을 응고시켜 피부를 위로 당겨주는 리프팅 효과**가 핵심이고, 써마지는 단극성 고주파 전류로 진피층 콜라겐을 재생시켜 피부를 쫀쫀하게 만드는 데 포커스가 있어요.

울쎄라는 돋보기로 햇빛을 모아 색종이를 태우는 원리처럼 초음파를 한 점에 집중시켜 원하는 피부층을 응고시킵니다. 반면 써마지는 전류가 저항을 만나며 발생한 열로 콜라겐을 늘려 **피부 자체를 두껍고 탄탄하게 만드는 노화 지연**에 가까운 시술이에요. 두 장비 모두 미국 FDA 승인을 받은 오리지널 장비이며, 효과 방향이 다른 만큼 본인의 고민이 리프팅인지 노화 지연인지에 따라 선택이 달라집니다.$AAA$, array['써마지', '울쎄라', 'HIFU', '단극성고주파', '리프팅비교']::text[], 2022, 'BTGSMbLMhcs-1', 'https://youtu.be/BTGSMbLMhcs?t=160s', null, '2022-11-24 00:00:00+00'::timestamptz, '2022-11-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$써마지를 받았는데 효과가 없는 것 같아요, 왜 그런가요?$AAQ$, $AAA$써마지는 **드라마틱하게 당겨주는 시술이 아니라 노화를 천천히 늦춰주는 시술**이라, 즉각적인 변화를 기대하면 실망할 수 있습니다. 사람은 한두 달 만에 확 늙지 않고 1년, 2년, 5년, 10년이 지나면서 차이가 벌어지는데, 써마지는 그 격차를 천천히 만들어주는 역할이에요.

그래서 이중턱이나 처진 볼살이 즉시 들어가는 시술로 기대하고 받으면 효과가 없는 듯 느껴질 수밖에 없어요. 또 한 가지 이유는 작용 깊이입니다. **전류가 들어가 저항이 가장 많이 걸리는 부위는 진피층이라 거기서 열을 다 소진하고 지방층까지는 들어가지 않습니다**. 따라서 지방으로 인한 처짐은 다른 시술이 더 맞고, 써마지는 표면을 두껍고 탄탄하게 만드는 데 적합해요. 받기 전 본인의 목표가 무엇인지 명확히 하고 전문의와 상담해 결정해야 만족도가 높습니다.$AAA$, array['써마지효과', '노화지연', '진피층작용', '기대치', '지방층한계']::text[], 2022, 'BTGSMbLMhcs-2', 'https://youtu.be/BTGSMbLMhcs?t=181s', null, '2022-11-24 00:00:00+00'::timestamptz, '2022-11-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$마른 사람도 울쎄라를 받을 수 있나요?$AAQ$, $AAA$마른 분도 울쎄라를 받을 수 있지만, **시술 깊이와 부위를 조절해야 볼 패임을 피할 수** 있습니다. 울쎄라의 원리상 작은 점에 강한 초음파가 모여 열 응고가 일어나 수축이 생기기 때문에, 지방이 적은 부위에 들어가면 꺼져 보일 위험이 있어요.

근막층은 한 장의 막이 아니라 얇은 막이 겹친 구조라 초음파가 근막층 외에 인접한 피하지방층에도 영향을 주어 지방이 수축할 수 있습니다. 그래서 지방이 있는 부위는 조금 꺼졌다는 후기가 나오는 거예요. 다만 **울쎄라는 초음파 영상으로 깊이를 보면서 시술할 수 있는 장비라 들어가는 깊이를 조절할 수** 있습니다. 볼 패임이 절대 안 된다면 해당 부위를 피하고 다른 부위 위주로 시술하는 방식으로 진행하므로, 마른 분도 충분히 안전하게 받을 수 있다고 합니다.$AAA$, array['울쎄라볼패임', '마른사람', '깊이조절', '피하지방수축', '근막층']::text[], 2022, 'BTGSMbLMhcs-3', 'https://youtu.be/BTGSMbLMhcs?t=288s', null, '2022-11-24 00:00:00+00'::timestamptz, '2022-11-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$울쎄라 시술은 많이 아픈가요?$AAQ$, $AAA$울쎄라는 아픈 부위가 있지만 마취 크림을 충분히 바르면 견딜 수 있는 정도입니다. **마취 크림을 40분 정도 바르고 받으면 시술 내내가 아니라 특정 부위에서만 시큰한 통증**이 느껴져요.

예를 들어 400샷을 받는다면 400샷 내내 아픈 것이 아니라 턱뼈나 뼈 가까운 부위, 광대뼈 쪽에서 속이 시큰시큰한 통증이 나타나는 식입니다. 환자분마다 통증 체감이 다르긴 하지만, 임상 경험상 **마취 연고를 충분히 바르고 진행하면 도저히 못하겠다고 중단되는 경우는 거의 없습니다**. 시술 효과는 즉각적이지 않아 한 달이 지나면서 변화가 느껴지기 시작해 약 3개월 정도면 효과가 많이 나타났다고 체감할 수 있어요. 콜라겐 재생과 열 응고로 인한 수축이 시간차를 두고 진행되기 때문이며, 시술 자체가 비교적 간단해 일상 회복이 빠른 점도 장점입니다.$AAA$, array['울쎄라통증', '마취크림', '400샷', '시술시간', '회복기간']::text[], 2022, 'BTGSMbLMhcs-4', 'https://youtu.be/BTGSMbLMhcs?t=400s', null, '2022-11-24 00:00:00+00'::timestamptz, '2022-11-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$써마지를 받다가 물집이 생기기도 하나요?$AAQ$, $AAA$써마지는 작은 팁으로 강한 에너지를 전달하는 만큼 **시술 방식이 정확하지 않을 때 물집이 생길 수 있습니다**. 원리상 등에 큰 접지 패드를 붙이고 얼굴의 작은 팁으로 전류를 흘려보내는데, 팁 면적이 작아 한꺼번에 들어가는 에너지가 뜨겁게 느껴질 수 있어요.

팁이 피부에 평평하게 컨택될 때는 안전하지만, **비스듬히 대거나 작은 면적에 에너지가 집중되면 그 부위에 물집이 생길 위험**이 있습니다. 그래서 시술자는 팁의 접촉을 일정하게 유지하며 작업하고, 에너지가 발생할 때마다 순간적으로 차가운 공기를 분사해 표면 화상을 막아요. 통증이 부담스러우면 말을 시키거나 다른 부위에 진동을 주거나 젤을 뿌리는 등 통증을 분산시키는 방법을 사용합니다. 에너지를 무리하게 올리지 않고 환자가 견딜 수 있는 범위에서 최대한 높게 시술하는 것이 효과와 안전의 균형점이에요.$AAA$, array['써마지물집', '팁접촉', '냉각분사', '통증분산', '안전관리']::text[], 2022, 'BTGSMbLMhcs-5', 'https://youtu.be/BTGSMbLMhcs?t=433s', null, '2022-11-24 00:00:00+00'::timestamptz, '2022-11-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$모공이 넓어지는 원인은 무엇인가요?$AAQ$, $AAA$모공이 넓어지는 원인은 크게 **피지 분비 증가와 피부 탄력 저하** 두 가지로 나뉩니다. 사춘기부터 피지 분비량이 늘어나면서 모공이라는 통로로 피지가 계속 나오다 보니 그 통로가 점점 넓어지게 돼요. 또 자외선을 많이 받아 피부 탄력이 떨어지는 경우에도 모공이 더 늘어나 보일 수 있습니다.

특히 30대 이상에서는 **두 가지 원인이 복합적으로 나타나는 경우가 많아** 단일 원인으로 보기 어렵습니다. 모공 주변에 피지가 저류되고 활성산소를 만나면 까만 딱지처럼 보이는 블랙헤드가 생기기도 하고, 피지가 제대로 배출되지 못해 막히면 그 아래로 피지가 쌓이면서 모공이 더 넓어지기도 해요. 또 모공 안에 까만색 솜털이 자라는 소극성 속모증을 블랙헤드로 오인하시는 경우도 있어, 정확한 진단이 먼저입니다.$AAA$, array['모공', '피지분비', '피부탄력', '블랙헤드', '모공확장']::text[], 2022, 'KFIRpYDGeJg-1', 'https://youtu.be/KFIRpYDGeJg?t=81s', null, '2022-11-29 00:00:00+00'::timestamptz, '2022-11-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$넓어진 모공 줄이는 시술은 어떤 게 있나요?$AAQ$, $AAA$넓어진 모공은 원인에 따라 **피지 억제 레이저와 콜라겐 생성 레이저**로 나뉘어 치료합니다. 피지 분비가 과하거나 배출이 안 되는 경우에는 애플 토닝 레이저, 골드 PTT, 아그네스처럼 피지 분비를 억제하는 레이저로 치료하고, 비타민 A 유도체인 이소트레티노인 같은 피지 조절제를 복용해 볼 수도 있어요.

노화로 모공 탄력이 떨어진 경우에는 콜라겐 생성을 촉진하는 시술을 합니다. 피코 프락셀 레이저는 표피에 손상을 주지 않으면서 진피층 재생을 유도해 모공을 축소해주고, 니들 RF는 촘촘한 바늘이 진피층 깊은 곳까지 들어가 고주파 에너지를 전달해 콜라겐과 엘라스틴 생성을 촉진합니다. 또 미라젯에 쥬베룩 같은 자가 콜라겐 생성 약물을 함께 주입하면 **섬유아세포와 콜라겐 생성을 동시에 유도하는 시너지 효과**를 볼 수 있어요. 써마지나 올리지오 같은 고주파 레이저도 진피층에 열을 가해 새 콜라겐 생성을 유도합니다.$AAA$, array['모공축소', '피코프락셀', '니들RF', '써마지', '콜라겐생성']::text[], 2022, 'KFIRpYDGeJg-2', 'https://youtu.be/KFIRpYDGeJg?t=138s', null, '2022-11-29 00:00:00+00'::timestamptz, '2022-11-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$모공 시술 받으면 모공이 완전히 없어지나요?$AAQ$, $AAA$모공 시술은 **모공을 없애는 게 아니라 덜 보이게 만드는 시술**입니다. 모공은 여드름이나 기미처럼 원래 없던 것이 생긴 게 아니라 눈, 코, 입처럼 피부에 꼭 필요한 구조물이기 때문에 없앨 수도 없고 없애서도 안 됩니다.

그래서 시술의 목표는 모공을 좀 덜 보이게 하고 **피부결이 좋아 보이게 만드는 것**이지 모공 자체를 제거하는 것이 아니에요. 환자분들이 생각한 것보다 변화가 적다고 느끼는 경우가 많은데, 이건 모공이 원래 우리 피부에 꼭 필요한 구조물이기 때문입니다. 또 모공 치료도 결국 다른 피부병 치료와 같아서 무조건 특정 레이저를 받겠다고 오시기보다는 내 모공의 원인과 피부 상태를 정확히 진단받고 거기에 맞는 솔루션을 받는 것이 중요해요. 효과에는 개인차가 있습니다.$AAA$, array['모공시술효과', '피부결개선', '모공한계', '시술기대치']::text[], 2022, 'KFIRpYDGeJg-3', 'https://youtu.be/KFIRpYDGeJg?t=246s', null, '2022-11-29 00:00:00+00'::timestamptz, '2022-11-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$모공 관리 위해 생활에서 어떻게 해야 하나요?$AAQ$, $AAA$모공 악화를 막으려면 **세안은 미지근한 물로, 자외선 차단제는 오일 프리로** 사용하시는 게 좋습니다. 따뜻한 물로 모공을 열고 찬물로 조이는 세안법은 갑작스러운 온도 변화가 피부에 스트레스를 유발해 오히려 노화를 촉진하고 모공이 더 넓어지는 요인이 될 수 있어요. 찬물은 혈관을 일시적으로 수축시킬 뿐 모공 자체를 줄이지는 못합니다.

집에서 코팩이나 피지 제거제를 **과도하게 사용하면 자극으로 염증이 유발되어** 오히려 모공이 더 넓어질 수 있어요. 사용 직후엔 깨끗해 보이지만 지속 사용은 피하시는 게 좋습니다. 자외선은 피부 광노화의 주범이라 반드시 차단제를 발라주셔야 하는데, 오일 성분이 많이 함유된 차단제는 모공을 막을 수 있으므로 오일 프리 제품을 선택하세요. 번들거림이 싫다면 가벼운 로션이나 젤타입을 사용해 보시는 것을 권해 드립니다.$AAA$, array['모공관리', '세안법', '자외선차단제', '오일프리', '코팩']::text[], 2022, 'KFIRpYDGeJg-4', 'https://youtu.be/KFIRpYDGeJg?t=311s', null, '2022-11-29 00:00:00+00'::timestamptz, '2022-11-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$브이올렛과 기존 윤곽주사는 어떻게 다른가요?$AAQ$, $AAA$브이올렛은 **지방세포를 파괴하는 시술**인 반면, 기존 윤곽주사는 지방세포를 작아지게 만드는 시술이라는 점이 본질적인 차이입니다. 윤곽주사는 지방세포 내 성분을 분해해 세포 크기를 감소시키는 방식이라, 작아진 세포가 시간이 지나면 다시 커져서 효과 지속성이 떨어지는 단점이 있어요.

브이올렛은 데옥시콜산이라는 단독 성분으로, 이는 담즙에 있는 2차 담즙산 성분이라 인체친화적입니다. 그래서 **부작용 우려가 기존 윤곽주사보다 훨씬 적고**, 지방세포를 비가역적으로 파괴하기 때문에 효과나 유지력에서 차이가 있어요. 또 윤곽주사는 효과를 높이려고 스테로이드를 섞는 경우가 있어 피부 함몰, 부정출혈, 생리 불순 같은 부작용이 생길 수 있는데 브이올렛은 단독 성분이라 이런 문제에서 자유롭습니다. 같은 데옥시콜산 성분의 벨카이라가 먼저 출시됐지만 가격 문제로 수입이 중단된 후, 대웅제약이 2021년 하반기 출시했어요.$AAA$, array['브이올렛', '윤곽주사', '데옥시콜산', '지방파괴', '이중턱']::text[], 2022, 'fSwa9ksaJlU-1', 'https://youtu.be/fSwa9ksaJlU?t=94s', null, '2022-12-01 00:00:00+00'::timestamptz, '2022-12-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$브이올렛은 어떤 분에게 효과가 있나요?$AAQ$, $AAA$브이올렛은 **실제로 턱밑 지방이 많은 분에게 효과적인 시술**입니다. 이중턱 개선 목적으로만 시술 허가를 받은 제품이고, 지방을 파괴하는 역할이기 때문에 단순히 탄력이 떨어져 처져 보이는 분들은 브이올렛을 맞아도 큰 효과가 없을 수 있어요.

병원 방문 전에 스스로 판단해볼 수 있는 기준이 있는데, '으' 발음을 해보았을 때 이중턱 부위가 불룩하게 처지는 분들은 브이올렛이 효과 있을 수 있고, 차이가 없으면 지방 때문이 아닌 경우가 많습니다. 손으로 만져봤을 때 두툼하게 잡히면 지방이 있는 거고, 얇은데 처져 보이기만 하면 단순 처짐이에요. **지방과 처짐이 동반된 분들은 울쎄라·슈링크 같은 하이프 시술을 병행**해야 효과를 보실 수 있어요. 한 병에 2cc가 들어있고 한 번에 한 병에서 두 병까지 사용하며, 4~6주 간격으로 2~4회 정도 시술받으면 효과가 나타납니다.$AAA$, array['브이올렛적응증', '이중턱지방', '처짐구분', '시술횟수']::text[], 2022, 'fSwa9ksaJlU-2', 'https://youtu.be/fSwa9ksaJlU?t=198s', null, '2022-12-01 00:00:00+00'::timestamptz, '2022-12-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$브이올렛 시술 후 통증이나 붓기는 얼마나 가나요?$AAQ$, $AAA$브이올렛 시술 후 통증·붓기·딱딱함은 **보통 1~2주, 길게는 4주까지 지속**됩니다. 시술 당시에는 마취 연고와 얼음팩으로 그리 아프지 않지만, 시술이 끝난 직후 통증이 갑자기 몰려오는 특징이 있어요. 강 원장님 본인도 한 번 맞은 후 3~4주 정도 붓기가 지속되었다고 합니다.

이 현상은 지방세포가 파괴되면서 주변으로 염증세포가 모여드는 **자연스러운 염증 반응이기 때문에 효과가 나는 신호**로 보셔도 됩니다. 그래서 통증이 심하다고 일반 진통소염제를 먹으면 염증 반응을 억제해 오히려 효과가 떨어질 수 있어요. 통증이 심할 때는 냉찜질이 도움이 되고, 그래도 못 참겠다면 소염제 계통이 아닌 타이레놀을 권해 드립니다. 또 한 부위에 한 번 놓는 게 아니라 범위에 걸쳐 여러 번 주사하므로 멍이나 주사 자국이 생길 수 있어요.$AAA$, array['브이올렛부작용', '통증', '붓기지속', '냉찜질', '타이레놀']::text[], 2022, 'fSwa9ksaJlU-3', 'https://youtu.be/fSwa9ksaJlU?t=350s', null, '2022-12-01 00:00:00+00'::timestamptz, '2022-12-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$브이올렛 맞고 피부가 처지지 않을까요?$AAQ$, $AAA$브이올렛 시술 후 **피부가 처져 보이는 경우는 거의 없습니다**. 환자분들이 바람 빠진 풍선처럼 피부가 늘어질까 걱정하시는데, 브이올렛은 지방세포를 비가역적으로 파괴하는 동시에 콜라겐 형성을 유도하는 특징이 있어요.

파괴된 지방세포가 없어진 사이사이로 **콜라겐이 형성되면서 탄력도 함께 좋아지기** 때문에, 실제 시술 후 더 처져 보인다는 경우는 없습니다. 다만 시술 전부터 지방과 처짐이 함께 있던 분들은 지방은 좋아져도 처짐이 남아있을 수 있는데, 이때는 울쎄라·슈링크·더블로 같은 하이프 시술을 병행하시는 게 좋습니다. 또 시술 시 가장 주의해야 할 부작용은 신경 손상으로, 아래턱 경계신경이 손상되면 입 근육 움직임이 비대칭적이 되는 부작용이 생길 수 있어 이 부위는 피해서 시술합니다. 일상에서는 음주·흡연 2주, 사우나·찜질방·뜨거운 욕조는 일주일 정도 삼가시는 게 좋아요.$AAA$, array['브이올렛탄력', '콜라겐형성', '신경손상', '병행시술', '시술후관리']::text[], 2022, 'fSwa9ksaJlU-4', 'https://youtu.be/fSwa9ksaJlU?t=478s', null, '2022-12-01 00:00:00+00'::timestamptz, '2022-12-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$올바른 세안은 어떻게 해야 하나요?$AAQ$, $AAA$세안의 핵심은 노폐물은 씻어내되 **피부에 중요한 성분은 남기는 것**입니다. 색조 화장이나 먼지, 선크림, 노폐물 같은 것은 씻어내고 각질 세포 사이를 연결해주는 세포간 지질이나 천연 보습인자는 남겨야 해요. 과한 세안을 하면 이러한 성분까지 함께 씻겨 나갈 수 있습니다.

세안 시간은 **최대 1분 이내로 완료하는 것이 좋고**, 그 이상은 지나친 러빙으로 피부 자극이 됩니다. 세안 후 기름기가 싹 빠지고 뽀드득 소리가 나면 과한 거고, 약간의 유분기가 남아 있는 듯한 정도가 적당합니다. 피부의 pH는 5.5~6.5 정도의 약산성이라 비슷한 **약산성 클렌저를 사용해 자연스러운 각질 탈락과 피부 장벽 회복을 도와야** 합니다. 손에 힘을 빼고 손끝으로 약하게 문지르되, 클렌징 후 아무것도 바르지 않은 상태에서 얼굴이 많이 당긴다면 세안 방법이 잘못됐거나 세안제가 안 맞는 것일 수 있어요.$AAA$, array['세안법', '세포간지질', '약산성클렌저', '천연보습인자', '1분세안']::text[], 2022, 'RXgHdO2sCGQ-1', 'https://youtu.be/RXgHdO2sCGQ?t=111s', null, '2022-12-06 00:00:00+00'::timestamptz, '2022-12-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부 타입별로 세안제는 어떻게 선택하나요?$AAQ$, $AAA$세안제는 **피부 타입에 따라 1차 세안제를 다르게 선택**하는 것이 좋습니다. 피부가 민감하지 않고 건조한 타입이라면 클렌징 오일로 1차 세안 후 클렌징 폼으로 마무리하면 괜찮아요. 민감하면서 건조한 타입은 클렌징 오일이 자극이 될 수 있으니 클렌징 크림이나 밀크, 로션으로 1차 세안 후 클렌징 폼으로 마무리합니다.

피부가 기름진 타입이라면 **클렌징 젤로 1차, 클렌징 폼으로 마무리**하는 방식이 적합합니다. 화장을 했다면 폼 클렌저 하나만으로는 완전히 지워지지 않으므로 이중 세안이 필요한데, 화장솜이나 티슈로 문질러 닦으면 피부 장벽에 손상을 줄 수 있어요. 클렌징 밀크로 얼굴을 문지른 다음 손에 물기를 살짝 묻혀 유화시켜 닦아낸 뒤 폼 클렌징을 사용하시는 것이 좋습니다. 이 가이드라인은 기본이고 개개인에 따라 차이가 있으니 사용해보며 본인에 맞게 조정해 가시면 됩니다.$AAA$, array['피부타입', '클렌징오일', '클렌징밀크', '이중세안', '화장세안']::text[], 2022, 'RXgHdO2sCGQ-2', 'https://youtu.be/RXgHdO2sCGQ?t=416s', null, '2022-12-06 00:00:00+00'::timestamptz, '2022-12-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름이 있을 때 세안은 어떻게 해야 하나요?$AAQ$, $AAA$여드름이 있을 때 **하루 2회면 세안 횟수로 충분**합니다. 여드름 환자분들이 기름을 없애야 좋아진다고 생각해 하루 10번씩 씻는 경우가 많은데, 안 씻어서 여드름이 나는 게 아닙니다. 과한 세안은 오히려 피부 장벽을 손상시켜 여드름균이 더 쉽게 침투하고 염증이 심해져 여드름을 악화시킬 수 있어요.

같은 이유로 **입자가 큰 알갱이가 든 스크럽제는 여드름 환자에게 권하지 않습니다**. 아침에 물세안만 하는 분도 있는데, 저녁에 바른 보습제 위로 공기 중 먼지, 베개·침구류의 진드기, 자는 사이 분비된 피지·노폐물이 섞여 모공을 막을 수 있으므로 물로만 씻지 말고 약산성 클렌저로 가볍게 세안하시는 것을 권해 드려요. 진료실에서 보면 세안 시간이 15분씩 너무 길거나 티존을 박박 세게 문지르는 분이 많은데, 결국 모세혈관 확장이나 아토피·지루피부염을 악화시키는 자극이 되니 짧고 부드럽게 하시는 게 좋습니다.$AAA$, array['여드름세안', '세안횟수', '스크럽제', '물세안', '약산성']::text[], 2022, 'RXgHdO2sCGQ-3', 'https://youtu.be/RXgHdO2sCGQ?t=607s', null, '2022-12-06 00:00:00+00'::timestamptz, '2022-12-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$클렌징 도구나 진동 클렌저 써도 되나요?$AAQ$, $AAA$클렌징 도구는 **기본적으로 추천하지 않는 편**입니다. 클렌징 도구로 오랫동안 세안하면 피부 장벽이 손상받기 쉬워지기 때문이에요. 피부 장벽이 깨져 있고 염증이 있는 분들에게는 그런 상태를 악화시킬 수 있어 절대 사용하지 못하도록 설명합니다.

다만 클렌징 도구로 피부가 좋아지는 분도 있긴 있어요. **피부 장벽이 원래 튼튼하거나 여드름 없는 두꺼운 지성 피부**라면 주 1~2회 정도 사용해 효과를 볼 수 있습니다. 하지만 진료실에 오시는 분들 대부분은 그렇지 않기 때문에 일반적으로 권하지 않아요. 모공 브러시나 진동 클렌저 같은 도구는 피부에 좋다, 모공 청소가 된다고 알려져 있지만 잘못 사용하면 피부 장벽 손상으로 이어지므로 본인 피부 상태를 정확히 파악한 후 사용 여부를 결정하시는 것이 좋습니다.$AAA$, array['클렌징도구', '진동클렌저', '모공브러시', '피부장벽', '지성피부']::text[], 2022, 'RXgHdO2sCGQ-4', 'https://youtu.be/RXgHdO2sCGQ?t=478s', null, '2022-12-06 00:00:00+00'::timestamptz, '2022-12-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비립종은 어떻게 치료하나요?$AAQ$, $AAA$비립종은 **레이저로 피부에 구멍을 뚫고 안의 케라틴 알갱이를 짜내는 간단한 시술**로 치료합니다. 비립종은 동그랗고 표면이 반질반질하며 안쪽에 하얀색·노란색 알갱이가 들어 있는 것이 특징인데, 이 알갱이는 피부에서 만들어진 케라틴이 밖으로 배출되지 못해 진주 알맹이처럼 쌓인 것입니다.

피부 깊이 있어 손으로 짜지지 않으므로 마취 연고를 바르고 **CO2 레이저나 어븀야그 레이저로 피부에 구멍을 뚫은 후** 안의 내용물을 빼내면 간단히 해결돼요. 깊이까지 파게 되는 경우가 있어 시술 후 재생테이프를 하루 한 번씩 갈아 일주일 정도 붙이고, 떼고 나면 살이 차오른 자국에 약간의 붉은 자국이 남지만 시간이 지나면 자연스럽게 좋아집니다. 빼낸 자리에서 재발은 거의 없고 다만 다른 부위에 새로 생길 수는 있으며, 예방하는 방법은 따로 없어요.$AAA$, array['비립종', 'CO2레이저', '어븀야그', '케라틴', '재생테이프']::text[], 2022, 'ERdbxlnLAtY-1', 'https://youtu.be/ERdbxlnLAtY?t=58s', null, '2022-12-08 00:00:00+00'::timestamptz, '2022-12-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$편평사마귀와 비립종은 어떻게 다른가요?$AAQ$, $AAA$편평사마귀는 **바이러스 감염이어서 번지지만**, 비립종은 안에 케라틴 알맹이가 든 것이라 번지지 않는다는 점이 본질적으로 다릅니다. 편평사마귀는 휴먼파필로마바이러스(HPV) 특정 아형에 의해 생기고, 눈가뿐 아니라 얼굴·턱·목·팔·가슴 온몸에 다 생길 수 있으며 다른 사람에게 옮길 수도 있어요.

그래서 편평사마귀는 미용 치료라기보다는 치료가 필요한 영역에 가깝습니다. 비립종은 하나를 안 없애도 옆에 또 생기는 것과는 관련이 없는 반면, **사마귀는 남아 있으면 주변으로 점점 옮겨가 개수가 늘어나기** 때문에 항상 전체 제거를 권합니다. 다 제거되면 바이러스 총량이 줄어 확 좋아지지만, 바이러스 양이 충분히 줄지 않으면 재발하는 경우도 있어요. 피부 위로 볼록 올라와 있는 병변만 레이저로 살짝 깎으면 되고, 위에만 딱지가 앉았다 떨어져 보통 일주일에서 1~2주면 깨끗하게 좋아지며 흉터도 거의 없습니다.$AAA$, array['편평사마귀', '비립종', 'HPV', '바이러스감염', '사마귀제거']::text[], 2022, 'ERdbxlnLAtY-2', 'https://youtu.be/ERdbxlnLAtY?t=187s', null, '2022-12-08 00:00:00+00'::timestamptz, '2022-12-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$한관종은 왜 치료가 어렵나요?$AAQ$, $AAA$한관종은 **피부 깊은 곳에 퍼져 자라는 덩어리들을 없애야 해서** 치료가 깊고 어렵습니다. 한관종은 땀을 배출하는 관을 만드는 세포들이 피부 밑에서 자라는 것으로, 비립종이나 편평사마귀처럼 피부 위에 올라온 게 아니라 깊숙한 곳에 막 자라 있어요.

게다가 한 자리에 모여 있지 않고 퍼져 있어서 **어디 있는지 정확히 알 수 없다는 점이 가장 큰 어려움**입니다. 없애려면 크고 넓게 파내야 하는데 그러면 아무는 데 오래 걸리고 흉터가 생기며 100% 제거가 어려워 재발도 잘 생겨요. 예전엔 치료를 권하지 않았는데 요즘은 아그네스라는 장비로 치료법이 달라졌습니다. 절연침이 달려 끝에만 전기가 통하므로 피부 겉에는 전기가 안 들어가고 한관종 뿌리에만 에너지가 전달돼 흉터 없이 좋아질 수 있어요. 대신 즉시 효과는 적고 2~3개월에 걸쳐 서서히 좋아지며, 보통 3개월에 한 번씩 3~4번 치료받습니다.$AAA$, array['한관종', '아그네스', '절연침', '땀샘', '흉터예방']::text[], 2022, 'ERdbxlnLAtY-3', 'https://youtu.be/ERdbxlnLAtY?t=386s', null, '2022-12-08 00:00:00+00'::timestamptz, '2022-12-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$쥐젖은 어떻게 생기고 어떻게 제거하나요?$AAQ$, $AAA$쥐젖은 **특별한 원인 없이 피부가 늘어나 튀어나오는 양성 종양**입니다. 정식 의학용어는 연성 섬유종, 피부 폴립, 스킨택이며 사마귀와 달리 바이러스가 아니라 번지지도 않아요. 그냥 피부가 늘어나 튀어나와 있는 거라고 생각하시면 쉽습니다.

눈가 외에 **겨드랑이·사타구니·엉덩이 밑처럼 접히는 부위, 마찰이 많은 부위에 잘 생기는 편**입니다. 치료는 매우 간단해서 그냥 튀어나와 있는 부위를 레이저로 제거해주면 됩니다. 비립종과 비교하면 비립종은 안에 케라틴 알맹이가 든 깊이 있는 병변이라 구멍을 뚫고 짜야 하는 반면, 쥐젖은 피부 위로 솟아난 것이라 표면만 깎아내면 끝나요. 또 사마귀와 다르게 주변으로 번지지 않으니 한꺼번에 전체 제거를 고집할 필요도 없고, 생기는 대로 제거하면 됩니다.$AAA$, array['쥐젖', '연성섬유종', '스킨택', '양성종양', '레이저제거']::text[], 2022, 'ERdbxlnLAtY-4', 'https://youtu.be/ERdbxlnLAtY?t=341s', null, '2022-12-08 00:00:00+00'::timestamptz, '2022-12-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$결혼식 하루 전 받기 좋은 시술은 무엇인가요?$AAQ$, $AAA$결혼식 하루 전이라면 **PHA 필링**을 가장 많이 추천합니다. PHA는 폴리하이드록시산으로, AHA·BHA보다 분자량이 커서 침투가 서서히 이루어져 안전성이 뛰어나기 때문에 피부가 예민하거나 건조한 분도 시술 후 뒤집어질 우려가 적어요.

또 이름 그대로 폴리하이드록신, 즉 **물 분자를 많이 가지고 있어 시술 직후부터 피부가 촉촉해지고 광이 납니다**. 시술을 받고 관리실을 나갈 때부터 광이 나며, 그 효과는 보통 2~3일, 길게는 일주일까지 지속돼요. 산 성분이 모공 각질을 탈락시키고 피부 턴오버를 촉진해 피부가 맑고 밝아 보이게 만드는 원리로, 각질 정리가 깔끔하게 되어 메이크업이 잘 먹고 물광 화장이 가능해집니다. 아프지 않고 바로 예뻐지는 시술로는 PHA 필링만 한 게 없어요. 화장이 뜨는 분들께 권해 드립니다.$AAA$, array['PHA필링', '결혼식시술', '분자량', '보습력', '메이크업']::text[], 2022, 'tUkKrVSezsA-1', 'https://youtu.be/tUkKrVSezsA?t=80s', null, '2022-12-13 00:00:00+00'::timestamptz, '2022-12-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$내일 당장 피부 좋아져야 한다면 어떤 레이저가 좋나요?$AAQ$, $AAA$내일 당장이 일정이라면 **3DEEP 레이저**를 많이 추천합니다. 가장 큰 장점은 안전성으로, 울쎄라·써마지·슈링크 같은 리프팅 장비들은 드물게 물집이나 도트 같은 부작용이 생길 수 있지만 3DEEP은 그런 우려가 적어 중요한 일정 앞에 안심하고 받을 수 있어요.

피부 깊은 층을 리프팅하지는 못해도 **얕은 층과 잔주름은 좋아지고**, 시술 당일이나 2~3일 뒤부터 효과가 보이기 시작합니다. 피부가 부들부들하고 쫀쫀한 느낌이 들고 화장도 잘 먹어요. 눈가에 시술받으면 약간 눈이 커진 느낌이 들기도 합니다. 효과 지속 기간이 길지는 않지만 하루에서 3일 내라는 짧은 시간 안에 효과가 나타나기 때문에 급할 때 유용해요. 코레지 셀핏도 새로 나온 장비로 양자 분자 공명 기술을 이용해 시술 다음 날 피부가 맑아진 느낌을 줍니다.$AAA$, array['3DEEP', '코레지셀핏', '리프팅', '당일시술', '안전성']::text[], 2022, 'tUkKrVSezsA-2', 'https://youtu.be/tUkKrVSezsA?t=188s', null, '2022-12-13 00:00:00+00'::timestamptz, '2022-12-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$보톡스는 행사 며칠 전에 맞아야 하나요?$AAQ$, $AAA$보톡스는 **행사 2주 전에 맞으시는 것이 안전**합니다. 효과가 나타나는 데 일주일 정도 걸리고, 주사로 무언가를 집어넣는 시술이라 주사 자국이 생기고 그 자리에 딱지가 앉고 아무는 시간이 필요하기 때문이에요.

사람마다 다르지만 일반적으로 **2~3일이면 좋아지지만 어떤 분은 일주일까지 회복 시간이 소요**될 수 있어 안전하게는 일주일 정도 전, 가능하다면 2주 정도 전이 훨씬 좋습니다. 또 멍이 들 수도 있는데 멍 빠지는 시간까지 생각하면 2주가 적절해요. 보톡스는 이마·미간 주름을 펴주고, 턱이나 승모근 근육을 줄여 라인을 예뻐지게 하며, 관자나 침샘이 튀어나와 라인이 안 예쁜 분들도 보톡스로 잡아줄 수 있습니다. 부작용이 적고 효과가 비교적 빨라 일주일에서 10일 정도 시간이 있을 때 1순위로 권해 드리는 시술이에요.$AAA$, array['보톡스', '주사자국', '멍', '행사2주전', '주름개선']::text[], 2022, 'tUkKrVSezsA-3', 'https://youtu.be/tUkKrVSezsA?t=278s', null, '2022-12-13 00:00:00+00'::timestamptz, '2022-12-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$결혼식 앞두고 리쥬란은 언제 맞아야 하나요?$AAQ$, $AAA$리쥬란은 **결혼식 2~3주 전에 맞으시는 것을 권해 드립니다**. 리쥬란이 화장이 잘 먹어 결혼식 전 시술로 유행하지만, 회복 기간이 좀 길 수 있기 때문이에요. 주사로 놓는 시술이라 주사바늘 자국이 생기고, 거기에 더해 볼록볼록한 엠보싱 효과가 나타나는 특징이 있습니다.

대부분은 며칠 내에 좋아지지만 **어떤 분은 일주일까지 소요**될 수 있어, 안전하게 시간을 두고 맞으시는 게 좋아요. 그래서 결혼식 2주 전 방문을 권하지만 멍이 생길 가능성까지 고려하면 2~3주가 가장 안전합니다. 리쥬란의 가장 좋은 효과는 화장이 잘 먹는다는 점이라 시술 후 환자분들로부터 "화장이 너무 잘 먹어요", "화장이 뜨질 않아요"라는 피드백을 많이 듣게 됩니다. 단기간에 많은 효과를 볼 수 있어 피부과에서 자주 추천하는 시술 중 하나에요.$AAA$, array['리쥬란', '엠보싱', '결혼식준비', '주사자국', '화장밀착']::text[], 2022, 'tUkKrVSezsA-4', 'https://youtu.be/tUkKrVSezsA?t=474s', null, '2022-12-13 00:00:00+00'::timestamptz, '2022-12-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$필러는 얼굴 어느 층에 맞아야 좋나요?$AAQ$, $AAA$필러는 **제일 깊은 뼈층에 맞을 때 효과가 가장 좋고 오래갑니다**. 피부는 표피층 아래 피하지방층, 근육층, 뼈까지 여러 단계로 이루어져 있는데 어느 층에 어떤 점성의 필러를 얼마만큼 넣느냐에 따라 결과가 천차만별로 달라져요.

얕은 층에 놓을수록 적은 용량으로도 효과가 드라마틱해 잘 맞은 것처럼 보이지만, **피부 속에 히알루론산을 녹이는 효소가 원래 존재해 시간이 지나면 분해되고**, 얼굴이 움직이면서 필러가 이동하기도 합니다. 어느 부위는 먼저 녹고 어느 부위는 남아 울퉁불퉁해지거나, 효과가 떨어지는 것 같아 또 맞다 보면 얼굴이 계속 울퉁불퉁해지는 현상이 생겨요. 반면 뼈 바로 위 깊은 층에 깔아주면 효과가 길게는 10년도 가고 부작용도 적습니다. 노화로 뼈가 흡수되는 부위(이마·관자·코 옆·눈 밑)에 미리 깔아주면 무너지는 골격을 받쳐주는 기둥 역할을 해주기 때문이에요.$AAA$, array['필러주입층', '뼈층필러', '울퉁불퉁부작용', '필러지속력', '히알루론산']::text[], 2022, 'K9eF4f0GenE-1', 'https://youtu.be/K9eF4f0GenE?t=183s', null, '2022-12-15 00:00:00+00'::timestamptz, '2022-12-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$필러는 어떤 부위에 맞으면 좋은가요?$AAQ$, $AAA$필러는 **이마·관자놀이처럼 노화로 뼈가 흡수되는 부위**에 가장 좋습니다. 노화의 방향 자체가 골 흡수 방향이라 미리 깔아두면 효과가 길게는 10년도 가고, 뼈 위에 바로 놓아 울퉁불퉁해지는 부작용도 적어요. 특히 관자놀이는 히알루론산이 주변 수분을 끌어당겨 조직을 함께 끌어올리는 **리프팅 효과가 더해져 얼굴 전체 윤곽이 예뻐집니다**.

코는 콧대를 높이는 데 필러만 한 게 없고, 옆볼처럼 꺼진 부위는 피하지방층에 넣어 지방을 대신해주는 역할로 적합해요. 반면 가장 조심해야 하는 부위는 팔자주름입니다. 팔자주름은 말하고 먹고 웃고 우는 표정에 많이 쓰여 움직임이 큰 다이내믹한 부위이고, 뼈 흡수까지 동반돼 매우 역동적으로 변화하기 때문이에요. 얕은 층에 맞으면 주변으로 이동하거나 흡수 차이로 울퉁불퉁해질 수 있어요. 팔자주름이 처짐·탄력저하·잔주름 중 어떤 원인인지 먼저 피부과 전문의와 상의 후 결정하시는 것이 좋습니다.$AAA$, array['관자놀이필러', '이마필러', '팔자주름', '코필러', '노화방향']::text[], 2022, 'K9eF4f0GenE-2', 'https://youtu.be/K9eF4f0GenE?t=311s', null, '2022-12-15 00:00:00+00'::timestamptz, '2022-12-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$필러는 얼마나 맞아야 효과가 좋나요?$AAQ$, $AAA$필러 용량은 **부위와 나이에 따라 다르며, 깊은 부위는 최소 2cc 이상 넣어야** 효과가 납니다. 관자놀이는 뼈가 깊이 있어 적은 용량으로는 효과가 없고, 시술마다 다르긴 하지만 최소 2cc, 많게는 4cc, 6cc까지 넣어야 충분히 효과가 좋고 오래갑니다.

얼굴 전체에 자연스럽게 펴주는 식으로 시술할 때는 **젊은 분은 1cc, 나이 있는 분은 2cc 정도가 적당**합니다. 노화로 뼈가 흡수되어 골격이 무너지고 그 때문에 얼굴이 나이 들어 보이는 부위가 몇 군데 있는데, 이런 대표적 부위에 기둥을 세우듯 포인트별로 놔주면 텐트 치듯 전체적으로 펴주는 느낌이 나요. 그 부위의 골격은 시간이 지나도 계속 노화로 무너질 것이기 때문에 미리 받쳐주는 식으로 충분히 넣어주는 게 좋습니다. 너무 적은 용량으로 얕은 층에만 맞으면 당장 변화는 커 보여도 시간이 지나며 어색해지거나 부작용이 생길 수 있어 적절한 용량 사용이 중요해요.$AAA$, array['필러용량', '관자놀이용량', '1cc', '2cc', '포인트시술']::text[], 2022, 'K9eF4f0GenE-3', 'https://youtu.be/K9eF4f0GenE?t=458s', null, '2022-12-15 00:00:00+00'::timestamptz, '2022-12-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$필러는 왜 효과가 좋다고 하나요?$AAQ$, $AAA$필러가 좋다고 하는 이유는 **노화로 흡수되는 뼈 자리를 받쳐 골격이 무너지는 걸 막아주는 역할** 때문입니다. 노화는 피부 바깥의 주름·처짐만이 아니라 가장 안쪽 뼈 구조의 변화가 약 70% 이상을 차지할 정도로 가장 크고 중요해요.

그래서 실 리프팅이나 안면 거상술로 피부를 들어 올려도 **밑의 뼈가 변한 상태라 어색해 보이고 별로 젊어 보이지 않는** 경우가 많습니다. 필러를 노화로 흡수되는 부위(관자·이마·코 옆·눈 밑)의 깊은 층에 미리 놔주면 무너지는 기둥을 떠받쳐 골격이 무너지는 걸 방어해줘요. 노화 자체를 막을 순 없지만 덜 보이게 만들고 젊고 어린 얼굴을 유지하게 해줍니다. 시술 시간이 짧고 입원이 없으며 회복도 빠른데 효과는 좋고, 마음에 안 들면 녹일 수도 있어 가성비가 좋아요. 다만 얼굴은 10년·20년 뒤에도 가지고 살아야 하니 계획을 가지고 피부과 전문의와 상의해 맞으시는 것이 좋습니다.$AAA$, array['필러원리', '뼈흡수', '골격유지', '노화방어', '안면거상술']::text[], 2022, 'K9eF4f0GenE-4', 'https://youtu.be/K9eF4f0GenE?t=141s', null, '2022-12-15 00:00:00+00'::timestamptz, '2022-12-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$밀크커피반점은 꼭 치료해야 하나요?$AAQ$, $AAA$밀크커피반점은 **대부분 치료하지 않아도 무관한 양성 반점**입니다. 건강한 성인 세 명 중 한 명이 하나 이상 가지고 있을 정도로 흔하며, 시간이 지나도 피부암으로 진행되지 않기 때문에 특별히 치료하지 않고 둬도 그 자리에서 암이 발생한다든지 하는 문제는 없어요.

다만 **사춘기 이전 5mm 이상 또는 사춘기 이후 15mm 이상의 큰 반점이 여섯 개 이상** 관찰되면 신경섬유종증이라는 질환을 의심해 봐야 합니다. 신경섬유종증은 피부·뼈·신경계 등 다양한 장기를 다발성으로 침범하는 유전 질환으로, 부모님이나 직계 형제자매에게도 있는 경우가 많아요. 사타구니·겨드랑이의 주근깨, 신경섬유종이 동반될 수 있고, 시력장애나 척추측만증, 동맥협착으로 인한 뇌경색 등 합병증이 따를 수 있습니다. 밀크커피반점이 출생 시 발생해 첫 신호로 발견되는 경우가 많아, 큰 반점이 여섯 개 이상이면 꼭 병원 진료를 받으시는 게 좋아요.$AAA$, array['밀크커피반점', '신경섬유종증', '양성반점', '유전질환', '합병증']::text[], 2022, 'mLNXgjEHHzU-1', 'https://youtu.be/mLNXgjEHHzU?t=111s', null, '2022-12-20 00:00:00+00'::timestamptz, '2022-12-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$밀크커피반점은 어떤 레이저로 치료하나요?$AAQ$, $AAA$밀크커피반점은 **저출력 레이저 토닝 방식**으로 치료합니다. 일상생활에 지장을 주지 않을 정도의 낮은 에너지로 수차례 치료하는 방식이며, 1064nm 파장대의 Nd:YAG 레이저를 기본으로 사용합니다.

추가로 **피코 레이저는 레이저빔을 1조 분의 1초 펄스로 나누어** 주변 조직에는 손상을 덜 주고 병변 내 색소만 선택적으로 강력하게 제거할 수 있어요. 저출력 레이저를 주로 쓰니 마취 연고를 바르면 통증이 크지 않고, 시술 후 약간의 붉은 기 외에는 딱지나 출혈 같은 부작용도 특별히 없어 아이들도 충분히 받을 수 있습니다. 보통 100일 정도 지난 후부터는 언제든 레이저 치료를 진행할 수 있어요. 너무 어린 신생아는 마취 연고 자체가 문제가 될 수 있어 시기를 조절합니다.$AAA$, array['밀크커피반점치료', 'Nd:YAG레이저', '피코레이저', '토닝', '마취연고']::text[], 2022, 'mLNXgjEHHzU-2', 'https://youtu.be/mLNXgjEHHzU?t=267s', null, '2022-12-20 00:00:00+00'::timestamptz, '2022-12-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$밀크커피반점 레이저 치료 효과는 어떤가요?$AAQ$, $AAA$밀크커피반점은 **꾸준한 치료로 충분히 좋아질 수 있는 질환**입니다. 보통 20~30회 정도 꾸준히 레이저 치료를 받으면 충분히 치료가 가능해요. 인내심을 갖고 꾸준히 받아야 효과를 보실 수 있다는 점이 중요합니다.

흥미롭게도 **경계가 들쭉날쭉하고 색이 혼재된 반점이 오히려 치료가 잘 됩니다**. 예쁘게 둥글둥글한 반점보다 못 생긴 반점이라고 생각하면 쉬운데, 경계가 들쭉날쭉한 타입, 한 가지 색이 아니라 여러 색상이 혼재된 타입이 비교적 치료가 잘 돼요. 마치 유리창 표면에 먼지가 낀 것처럼 피부 표면 가까이에 색소가 있는 병변도 표면 쪽 색소라 치료가 잘 됩니다. 환자분들이 치료가 안 될 것 같다고 생각하는 경우가 많은데 오히려 그 반대이니 너무 겁먹지 말고 치료를 시작하시는 게 좋아요. 효과에는 개인차가 있을 수 있습니다.$AAA$, array['밀크커피치료효과', '20회치료', '토닝횟수', '치료반응', '표재성색소']::text[], 2022, 'mLNXgjEHHzU-3', 'https://youtu.be/mLNXgjEHHzU?t=386s', null, '2022-12-20 00:00:00+00'::timestamptz, '2022-12-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리쥬란은 어떤 시술이고 어떤 효과가 있나요?$AAQ$, $AAA$리쥬란은 연어에서 추출한 **폴리뉴클레오타이드 성분의** 스킨부스터 시술입니다. 인체 적합성이 가장 우수하다고 알려진 폴리뉴클레오타이드를 피부에 주사하면 조직의 재생과 회복을 돕는 역할을 해요. 피부에 주입되면 톤이 밝아지고 수분 공급이 되며, 피부결이 거칠거나 좋지 않을 때 개선 효과도 기대할 수 있습니다.

특히 염증으로 인해 붉은기가 울긋불긋한 경우에도 도움이 됩니다. 효과 발현에는 시간이 필요해서 한 달 간격으로 세 번 정도 받거나 **3개월 정도 간격으로 꾸준히 맞으시는 걸 권해 드려요**. 보습제를 발라도 개선되지 않는 속건조나 칙칙하고 푸석한 피부에 만족도가 높은 시술입니다.$AAA$, array['리쥬란', '폴리뉴클레오타이드', '스킨부스터', '피부재생', '속건조']::text[], 2022, 'mfUGyYfYPkE-1', 'https://youtu.be/mfUGyYfYPkE?t=67s', null, '2022-12-22 00:00:00+00'::timestamptz, '2022-12-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리쥬란 시술 후 다운타임은 얼마나 가나요?$AAQ$, $AAA$리쥬란 시술 후 회복 기간은 짧으면 3~4일, **길면 1~2주 정도** 소요됩니다. 주사로 인한 자국과 멍이 생길 수 있고, 엠보싱이라 부르는 볼록볼록한 자국이 오래가는 분들도 있어요. 다음 날 메이크업으로 거의 티가 안 나는 분도 있지만, 일주일 정도 울긋불긋하고 자국이 남는 분도 있어 개인차가 큽니다.

엠보싱은 적절한 층에 잘 주사가 돼서 나오는 현상이라 시간이 지나면 자연스럽게 해결되므로 부작용으로 보기는 어렵습니다. 다만 결혼식 같은 중요한 일정이 다음 주에 있다면 시술은 피하는 게 좋고, **충분한 시간을 두고 받으시는 게 안전합니다**. 드물게 알러지 반응 보고도 있으나 흔하지는 않아요.$AAA$, array['리쥬란다운타임', '엠보싱', '회복기간', '주사자국', '시술후관리']::text[], 2022, 'mfUGyYfYPkE-2', 'https://youtu.be/mfUGyYfYPkE?t=118s', null, '2022-12-22 00:00:00+00'::timestamptz, '2022-12-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$무통 리쥬란 HB+와 클래식 리쥬란은 어떻게 다른가요?$AAQ$, $AAA$무통 리쥬란 HB+는 클래식 리쥬란과 성분은 동일하지만 **리도카인과 히알루론산이 추가된** 제품입니다. 리도카인은 마취제로 통증을 줄여주고 히알루론산은 주변 수분을 흡수해 보습감을 높여주는 역할을 해요. 반반 비교 시술을 받아본 결과 통증 차이가 매우 크게 느껴졌습니다.

다만 통증을 줄이기 위해 다른 성분이 추가된 만큼 **폴리뉴클레오타이드 함량은 오리지널에 더 많이 들어 있어요**. 어떤 분들은 무통 리쥬란이 효과가 덜한 것 같다고 느끼시기도 합니다. 다만 물광 효과나 얼굴 반짝해지는 효과는 무통 리쥬란도 충분히 있어, 통증이 너무 부담스러우신 분은 직접 받아 보시고 비교해보시는 게 좋습니다.$AAA$, array['무통리쥬란', '리쥬란HB', '리도카인', '히알루론산', '시술비교']::text[], 2022, 'mfUGyYfYPkE-3', 'https://youtu.be/mfUGyYfYPkE?t=343s', null, '2022-12-22 00:00:00+00'::timestamptz, '2022-12-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리쥬란은 어떤 사람에게 효과가 좋나요?$AAQ$, $AAA$리쥬란은 **속건조가 심한 분들에게** 효과가 가장 좋습니다. 보습제를 아무리 발라도 개선이 안 되는 건조한 경우 시술 후 확연히 좋아지는 경우가 많아요. 피부가 칙칙하고 푸석거리며 피부결이 좋지 않을 때 광나는 것처럼 밝아지는 느낌도 받을 수 있습니다.

또한 **반복되는 피부염으로 약을 끊으면 다시 재발하는 분들에게도 권해 드리는데** 효과를 보는 경우가 많아요. 마스크 착용 등으로 유발요인 제거가 어려운 상황에서 도움이 됩니다. 여드름 치료 중이지만 입 주변 미세 트러블이 반복되거나, 막연히 피부가 좋아지고 싶은 분들에게 만족도가 높은 시술입니다. 효과 체감이 주관적인 면이 있어 직접 경험해보시는 게 좋습니다.$AAA$, array['리쥬란적응증', '속건조', '피부염', '푸석한피부', '피부재생']::text[], 2022, 'mfUGyYfYPkE-4', 'https://youtu.be/mfUGyYfYPkE?t=445s', null, '2022-12-22 00:00:00+00'::timestamptz, '2022-12-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름과 가장 헷갈리는 피부 질환은 무엇인가요?$AAQ$, $AAA$여드름과 가장 혼동되는 피부 질환은 **주사(장미진, rosacea)입니다**. 일반적으로 안면 홍조라고 부르며, 얼굴이 붉어지면서 심해지면 여드름처럼 오돌토돌 올라오는 형태로 나타나요. 여드름과 가장 큰 차이는 발생 시기로, 여드름은 어릴 때 더 심하고 나이가 들수록 좋아지는 반면 주사는 어릴 때보다 **나이가 들수록 오히려 점점 더 심해지는 경향을 보입니다**.

여드름처럼 안에 고름이 차거나 짜서 나오는 것은 없고, 건드릴수록 피부가 더 붉어지는 현상이 특징입니다. 주사는 만성질환이라 제대로 진단을 받고 꾸준한 관리가 필요해요. 또 다른 흔한 오해 질환으로 지루성 피부염이 있는데 코 주변과 T존에 염증과 각질이 생겨 여드름처럼 보이지만 치료법이 완전히 다릅니다.$AAA$, array['주사', '안면홍조', '여드름혼동', '지루성피부염', '장미진']::text[], 2022, 'nC6Z4BR5_Oc-1', 'https://youtu.be/nC6Z4BR5_Oc?t=152s', null, '2022-12-27 00:00:00+00'::timestamptz, '2022-12-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$좁쌀여드름과 편평사마귀는 어떻게 구분하나요?$AAQ$, $AAA$얼굴에 좁쌀처럼 올라온 게 모두 좁쌀여드름은 아니고, **편평사마귀와 구분이 필요합니다**. 편평사마귀는 바이러스 때문에 생기는 질환으로 좁쌀여드름과 생긴 모양 구분이 매우 어려워요. 좁쌀처럼 볼록볼록 올라오는 형태로 심한 경우 50~100개씩 얼굴을 뒤덮기도 합니다.

편평사마귀는 바이러스 질환이라 **괜히 짜거나 건드리면 바이러스를 퍼뜨리는 결과가 생기므로** 주의가 필요합니다. 간단하게 레이저 치료로 해결할 수 있으니 정확한 진단을 먼저 받는 것이 중요해요. 한관종이나 피지샘 증식증 같은 양성종양도 짜도 아무것도 나오지 않고 볼록볼록해 여드름으로 오해되는데, 피부 깊숙한 층의 세포가 모여 종양을 이루기 때문에 시간이 지난다고 없어지지 않습니다.$AAA$, array['좁쌀여드름', '편평사마귀', '한관종', '피지샘증식증', '양성종양']::text[], 2022, 'nC6Z4BR5_Oc-2', 'https://youtu.be/nC6Z4BR5_Oc?t=176s', null, '2022-12-27 00:00:00+00'::timestamptz, '2022-12-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$뾰루지가 났을 때 집에서 어떻게 대처해야 하나요?$AAQ$, $AAA$뾰루지는 여드름이 아니라 **피부의 가벼운 감염 때문에 생기는 종기성 병변입니다**. 코나 볼에 크게 종기가 나는 형태로, 가장 빠른 해결책은 피부과에 내원해 염증 주사를 맞는 것이에요. 염증 주사를 맞으면 비교적 간단하게 해결됩니다.

당장 피부과 방문이 어려운 사정이라면 **집에 있는 후시딘 연고나 에스로반과 같은 항생제 연고를 바르면서 경과를 지켜볼 수 있어요**. 피부 속에서 돌덩이처럼 만져지는 형태의 종기는 표피낭종이나 모기질종 같은 양성종양인 경우가 흔하며 간단한 수술이나 주사로 치료 가능합니다. 어떤 경우든 짜거나 건드리기보다 진료실에서 정확한 진단을 받는 것이 가장 중요해요.$AAA$, array['뾰루지', '염증주사', '후시딘', '에스로반', '항생제연고']::text[], 2022, 'nC6Z4BR5_Oc-3', 'https://youtu.be/nC6Z4BR5_Oc?t=121s', null, '2022-12-27 00:00:00+00'::timestamptz, '2022-12-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 치료해도 안 나으면 어떤 질환을 의심해야 하나요?$AAQ$, $AAA$여드름 치료를 1년 이상 해도 효과 없이 점점 심해진다면 **특수한 림프구 질환을 의심해야 합니다**. 약 복용, 피부 관리, 레이저 등 다양한 치료에도 반응이 없을 경우 5L이라 부르는 림프구가 피부에 침투해 생기는 특수한 질환이 원인일 수 있어요. 이런 경우 조직 검사가 반드시 필요합니다.

드물지만 피부에 세균이 감염되는 연조직염도 얼굴에 생길 수 있어, **치료가 지체되면 발열·오한·두통 같은 전신 증상이나 피부괴사까지 갈 수 있어** 빠른 진단이 필요합니다. 모낭염도 여드름과 모양이 비슷한데 원인이 세균인지 곰팡이균인지에 따라 항생제나 항진균제로 치료법이 달라져요. 여드름처럼 보인다고 다 여드름은 아니므로 잘 낫지 않으면 피부과 전문의 진단을 권해 드립니다.$AAA$, array['림프구질환', '연조직염', '모낭염', '조직검사', '난치여드름']::text[], 2022, 'nC6Z4BR5_Oc-4', 'https://youtu.be/nC6Z4BR5_Oc?t=431s', null, '2022-12-27 00:00:00+00'::timestamptz, '2022-12-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$튼살은 정말 치료가 안 되는 건가요?$AAQ$, $AAA$튼살은 어떤 튼살이냐에 따라 치료 결과가 크게 달라집니다. 튼살은 **붉은 튼살과 흰색 튼살로 나뉘는데**, 생긴 지 얼마 안 된 초기 붉은 튼살은 혈관이 늘어나고 염증 반응이 있는 진행형으로 레이저로 비교적 쉽게 치료가 가능해요. 반면 시간이 지나 위축되며 흉터처럼 남은 흰색 튼살은 치료가 어렵습니다.

흰색 튼살은 **털, 피지샘, 콜라겐, 색소세포 등이 소실되고 피부 재생 능력이 떨어진 상태라** 정상 피부와 100% 똑같아지긴 어렵습니다. 따라서 흰색이 되기 전 붉은 튼살 시기에 빨리 병원에 오시는 게 좋아요. 치료 시기를 놓치면 시간과 비용이 훨씬 많이 들기 때문에, 발생 초기 진단과 치료가 결과를 좌우합니다.$AAA$, array['튼살치료', '붉은튼살', '흰색튼살', '치료시기', '초기치료']::text[], 2022, '9W7BPzzabPk-1', 'https://youtu.be/9W7BPzzabPk?t=114s', null, '2022-12-29 00:00:00+00'::timestamptz, '2022-12-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$미라젯은 어떤 원리로 튼살을 치료하나요?$AAQ$, $AAA$미라젯은 **바늘 없는 주사기 원리의 레이저 약물 주입 장비입니다**. 노즐 가운데에 격막이 있고 두 개의 방으로 나뉘는데, 위쪽 물이 채워진 방에 레이저를 쏘면 에너지가 압력으로 변환되어 격막을 통과해 아래쪽 약물을 피부로 분사시켜요. 약물이 Z에너지 형태로 피부를 뚫고 미세하게 들어갑니다.

기존 공기총 방식과 달리 **레이저 빔이 물에 닿아 반응하는 순간 폭발력을 이용해 일정한 양이 균일하게 주입되는 점이 차이입니다**. 에너지와 분사 횟수, 주입량 조절이 가능해 진피층에 고르게 주입되고, 분당 최대 2400회 속도로 시술 시간이 단축됐어요. 폴리락티애시드와 히알루론산이 결합된 쥬베룩이나 레니스나 같은 콜라겐 생성 유도 스킨부스터를 튼살 부위 진피층에 주입합니다.$AAA$, array['미라젯', '바늘없는주사', '약물주입', '레이저폭발', '스킨부스터']::text[], 2022, '9W7BPzzabPk-2', 'https://youtu.be/9W7BPzzabPk?t=322s', null, '2022-12-29 00:00:00+00'::timestamptz, '2022-12-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$미라젯 튼살 시술의 부작용은 무엇이 있나요?$AAQ$, $AAA$미라젯은 **큰 부작용이 거의 없는 시술입니다**. 기존 프락셔널 레이저 시술은 주변 피부에 열 자극이 가해져 색소침착이 큰 부작용이었지만, 미라젯은 튼살 라인 안쪽으로 정확히 시술 가능하고 열을 이용하는 레이저가 아니라 색소침착 가능성이 매우 낮아요.

다만 **피부톤이 원래 까매서 색소활성도가 높거나 튼살이 일자 라인만 있는 경우에는 일시적으로 까맣게 될 수 있습니다**. 주사가 아니지만 시술 시 붓기, 멍, 붉은 자국이 생길 수 있는데 기존 시술보다는 훨씬 덜해요. 시술 당일에는 미세한 구멍 때문에 감염 우려가 있어 물 닿는 것을 하루 정도 피하고, 열탕 목욕·음주·격렬한 운동은 일주일 정도 피하는 것이 좋습니다.$AAA$, array['미라젯부작용', '색소침착', '시술후관리', '감염예방', '주의사항']::text[], 2022, '9W7BPzzabPk-3', 'https://youtu.be/9W7BPzzabPk?t=594s', null, '2022-12-29 00:00:00+00'::timestamptz, '2022-12-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$미라젯으로 튼살을 완전히 없앨 수 있나요?$AAQ$, $AAA$흰색으로 변한 튼살은 **100% 주변 피부와 똑같아질 수는 없습니다**. 치료 시작 시 현실적인 목표 설정이 중요한데, 환자의 연령, 튼살 발생 시기, 현재 색깔, 부위의 피부 탄력성과 재생 능력, 패임의 깊이와 폭에 따라 치료 강도·횟수·방법이 많이 달라져요.

중요한 판단 기준은 **튼살 라인 안쪽에 털이 보이는지 여부입니다**. 오래된 튼살은 땀샘과 피지샘 같은 피부 부속기가 소실돼 재생이 안 되어 경과가 좋지 않을 수 있어요. 작은 솜털이라도 보이면 재생력이 살아있다는 신호로 결과가 더 좋습니다. 모공이 완전히 소실되면 피부결 자체가 바뀌어 햇빛에 반짝거리거나 매끈한 흉터처럼 느껴지므로, 진피 콜라겐 손실이 심하면 치료 횟수를 늘리고 기대치를 낮춰야 할 필요가 있어요.$AAA$, array['튼살완치', '치료한계', '피부재생', '솜털', '기대치']::text[], 2022, '9W7BPzzabPk-4', 'https://youtu.be/9W7BPzzabPk?t=504s', null, '2022-12-29 00:00:00+00'::timestamptz, '2022-12-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증은 정말 불치병인가요?$AAQ$, $AAA$백반증은 **불치병이 아닙니다**. 과거에는 백반증이 불치병이라는 인식이 많았고 의사들도 치료가 잘 안 된다고 생각했지만, 실제 진료해보면 치료가 되는 백반증이 더 많았습니다. 백반증 상태에 따라 결과는 달라지는데, 암이 조기 발견 여부에 따라 경과가 다른 것과 비슷해요.

조기에 진단되면 **대부분의 피부색이 정상으로 돌아오기도 합니다**. 가장 중요한 치료는 자외선 치료로 통에 들어가는 전신 자외선 치료와 엑시머·팔라스 레이저 같은 국소 치료가 있어요. 통상적으로 일주일에 두 번씩 6개월 이상 받게 되며, 병변이 작고 치료가 잘 될 것 같은 경우에는 한 달 만에 좋아지기도 합니다. 통상적인 치료 기간은 6개월에서 1년 이상이에요.$AAA$, array['백반증', '불치병', '자외선치료', '엑시머레이저', '조기치료']::text[], 2023, '1mGmgXY7MWI-1', 'https://youtu.be/1mGmgXY7MWI?t=32s', null, '2023-01-03 00:00:00+00'::timestamptz, '2023-01-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$엑시머 레이저 치료는 아프지 않나요?$AAQ$, $AAA$엑시머 레이저는 다른 레이저와 달리 **낮은 에너지로 몸에 자극을 주는 치료법입니다**. 일반적인 레이저는 색소나 점 같은 것을 파괴하는 목표로 작용하지만, 엑시머 레이저는 색소 세포를 재생시키는 것이 목표예요. 따라서 강한 자극을 동반하지 않습니다.

에너지 강도가 낮아 **어린아이들도 전혀 부담 없이 치료할 수 있는 안전한 치료입니다**. 백반증이 번지고 있는 경우 자외선 치료만으로는 막기 어려워, 진행을 끊어주기 위해 스테로이드 경구약을 함께 복용하기도 해요. 스테로이드 복용이 어려운 경우 사이클로스포린이나 메토트렉세이트 같은 면역 저하 약제가 도움이 되며, 자외선 치료 효과를 높이기 위해 국소 연고제를 함께 도포하기도 합니다.$AAA$, array['엑시머레이저', '백반증치료', '어린이치료', '색소재생', '통증']::text[], 2023, '1mGmgXY7MWI-2', 'https://youtu.be/1mGmgXY7MWI?t=110s', null, '2023-01-03 00:00:00+00'::timestamptz, '2023-01-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증에 좋은 음식과 피해야 할 음식은 무엇인가요?$AAQ$, $AAA$음식은 백반증과 크게 관계가 없어 **평상시대로 다 드셔도 괜찮습니다**. 백반증 환자는 체내 활성 산소가 크게 증가되어 있기 때문에 항산화 물질이 풍부한 과일, 야채, 채소 등을 충분히 섭취하면 경과를 막고 예방하는 데 도움이 돼요. 흡연은 활성 산소를 크게 증가시켜 백반증이 번지거나 치료가 잘 안 되는 경우가 많아 금연이 필요합니다.

다만 백반증은 자가면역질환이라 **면역력을 올린다는 한약, 인삼, 홍삼 같은 면역증강 약재는 백반증을 악화시킬 수 있어 피하는 것이 좋습니다**. 건강에는 도움이 될 수 있지만 백반증에는 부정적으로 작용할 수 있어요. 햇빛은 백반증 종류에 따라 다른데, 햇빛으로 화상을 입으면 백반증이 생길 수 있어 선크림 사용과 챙 넓은 모자 착용이 재발 방지에 도움이 됩니다.$AAA$, array['백반증음식', '항산화', '금연', '면역증강약재', '햇빛차단']::text[], 2023, '1mGmgXY7MWI-3', 'https://youtu.be/1mGmgXY7MWI?t=198s', null, '2023-01-03 00:00:00+00'::timestamptz, '2023-01-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$아이가 백반증인데 스테로이드 연고 발라도 되나요?$AAQ$, $AAA$아이의 백반증에 **스테로이드 사용을 너무 두려워하실 필요는 없습니다**. 다행히 치료 효과를 보이는 스테로이드가 없는 연고도 많이 있고, 대부분의 경우 아이에게 부작용이 나올 만큼 장기간 사용하지 않아요. 처음 번질 때 단기간 사용하고 유지 요법으로 들어갈 수 있습니다.

또한 **상처가 생기면 그 자리에 백반증이 생기는 경우가 가끔 있어** 아이들이 다치지 않게 신경 쓰고, 넘어졌을 때 상처가 빨리 낫도록 돕는 것이 중요해요. 옷이나 속옷의 반복적 마찰도 백반증 발생과 연관이 있어 겨드랑이나 허리 부위처럼 마찰이 잦은 곳에 백반증이 있다면 헐겁게 입는 것이 좋습니다. 자녀의 백반증으로 고민된다면 피부과 전문의 진단을 권해 드려요.$AAA$, array['소아백반증', '스테로이드연고', '유지요법', '상처관리', '마찰예방']::text[], 2023, '1mGmgXY7MWI-4', 'https://youtu.be/1mGmgXY7MWI?t=320s', null, '2023-01-03 00:00:00+00'::timestamptz, '2023-01-03 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부과 스테로이드 연고는 어떤 질환에 쓰이나요?$AAQ$, $AAA$피부과의 스테로이드는 **다양한 질환에 효과적인 만병통치약 같은 약입니다**. 우리 몸이 스트레스 받을 때 나오는 스테로이드 호르몬과 비슷한 효과를 내며, 피부과에서는 주로 혈관 수축과 염증 억제 작용을 활용해요. 아토피 피부염, 지루성 피부염, 알레르기 접촉 피부염 같은 급성 염증성 피부염에 많이 사용합니다.

이외에도 **백반증, 전신성 홍반성 루프스, 심한 난치성 수포성 질환 등 자가면역질환에도 사용됩니다**. 어떤 피부질환이라도 초기에 잡는 것이 매우 중요한데, 이때 스테로이드를 잘 써야 병변이 번지는 걸 막고 단기간에 증상을 신속하게 가라앉힐 수 있어요. 스테로이드는 절대 써서는 안 되는 약이 아니라, 얼마나 잘 사용하는지가 중요한 약입니다.$AAA$, array['스테로이드연고', '아토피', '지루성피부염', '자가면역질환', '초기치료']::text[], 2023, 'FMxOZqvFU4I-1', 'https://youtu.be/FMxOZqvFU4I?t=109s', null, '2023-01-05 00:00:00+00'::timestamptz, '2023-01-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스테로이드 연고를 안전하게 사용하는 방법은?$AAQ$, $AAA$스테로이드 연고는 **피부 상태에 맞춰 강도 1~7등급을 선택하고 적절한 양을 사용하는 것이 핵심입니다**. 피부염이 심한 첫 일주일은 강한 등급으로 하루 두 번 발라 염증을 빨리 잡고, 호전되면 약한 제재로 바꾸거나 횟수를 줄이는 방식으로 부작용을 줄여요. 얼굴·겨드랑이·사타구니처럼 얇거나 겹치는 부위는 약한 등급을 써야 합니다.

적절한 용량 사용에는 **핑거팁 유닛 기준이 유용한데, 입구 5mm 튜브에서 검지 첫 마디에 짠 양이 한 단위입니다**. 사용 기간은 기본 2주 정도가 권장되지만 질환과 등급에 따라 다르므로 주치의 상담이 필요해요. 제형도 중요한데, 손·발처럼 두꺼운 곳은 연고 타입, 흡수가 부담스러운 경우 로션이나 겔 타입, 두피는 액상 타입을 사용합니다.$AAA$, array['스테로이드강도', '핑거팁유닛', '사용기간', '제형선택', '안전사용']::text[], 2023, 'FMxOZqvFU4I-2', 'https://youtu.be/FMxOZqvFU4I?t=251s', null, '2023-01-05 00:00:00+00'::timestamptz, '2023-01-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스테로이드는 왜 아침에 복용해야 하나요?$AAQ$, $AAA$스테로이드 복용제는 **아침 시간대에 먹는 것이 가장 좋습니다**. 우리 몸에서는 아침에 눈을 떴을 때 스트레스 호르몬인 코티졸 분비가 가장 많이 일어나는데, 이 생체주기 리듬에 맞춰 복용해야 호르몬 축에 미치는 영향이 적어요. 다른 시간대에 계속 복용하면 우리 몸은 스테로이드가 많다고 인지합니다.

그렇게 되면 **뇌의 시상하부와 뇌하수체가 부신에 코티졸을 그만 만들라고 명령을 내리는 부신피질 억제가 발생합니다**. 부신피질 기능에 부전이 오고 그에 따른 부작용이 생길 수 있어요. 또한 고용량을 복용하다 갑자기 끊으면 리바운드로 병변이 나빠지거나 호르몬 분비에 영향을 주므로 천천히 끊는 것이 중요합니다. 장기 복용 시 식욕 증가로 체중 관리와, 골다공증 예방을 위한 비타민 D 섭취도 신경 쓰셔야 해요.$AAA$, array['스테로이드복용', '아침복용', '코티졸', '부신피질억제', '리바운드']::text[], 2023, 'FMxOZqvFU4I-3', 'https://youtu.be/FMxOZqvFU4I?t=420s', null, '2023-01-05 00:00:00+00'::timestamptz, '2023-01-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스테로이드의 대표적인 부작용은 무엇인가요?$AAQ$, $AAA$스테로이드는 **잘 쓰면 명약이지만 잘못 쓰면 독이 될 수 있는 양날의 검입니다**. 대표적인 부작용으로 혈압과 혈당 상승, 식욕 증가로 인한 체중 증가가 있어요. 살이 많이 찌면 이아트로제닉 쿠싱 신드롬이라고 해서 보름달 모양의 얼굴(Moon Face)이 되고 목이 두꺼워지는 변화가 생깁니다.

반면 **피부는 얇아져서 살이 트고 조금만 부딪쳐도 멍이 드는 부작용이 생길 수 있어요**. 안과적으로는 백내장이나 녹내장이 악화될 수 있고, 칼슘 배설 증가로 골다공증이 잘 생깁니다. 무서운 부작용으로 뼈 안 지방세포가 커지면서 압력 증가로 뼈 허혈이나 골절이 쉽게 발생할 수도 있어요. 다만 피부과 전문의는 이런 부작용이 생기지 않게 사용하는 기술을 가지고 있으니 너무 걱정하지 않으셔도 됩니다.$AAA$, array['스테로이드부작용', '쿠싱증후군', '골다공증', '체중증가', '피부위축']::text[], 2023, 'FMxOZqvFU4I-4', 'https://youtu.be/FMxOZqvFU4I?t=193s', null, '2023-01-05 00:00:00+00'::timestamptz, '2023-01-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$화상 입었을 때 집에서 어떻게 응급처치해야 하나요?$AAQ$, $AAA$화상 직후에는 **찬 수돗물을 틀어놓고 흐르는 물에 20분 정도 충분히 냉찜질을 해주세요**. 안쪽에 있는 열기까지 식혀야 하므로 잠깐 틀고 마는 것이 아니라 오래 충분히 식히는 것이 중요해요. 고데기는 180도가 넘는 고온이라 끓는 물보다 훨씬 뜨겁기 때문에 더 적극적인 냉각이 필요합니다.

물집이 생기면 **소독된 바늘로 터뜨리지 말고 그대로 두는 것이 좋습니다**. 물집의 지붕도 피부의 중요한 구조물이라 손상시키지 않는 편이 회복에 도움이 돼요. 물집이 아닌 경우 냉장고 얼음팩을 수건에 싸서 살짝 대주고, 후시딘·에스로반·마데카솔 같은 상처 연고는 큰 문제 없이 쓸 수 있습니다. 실바딘 같은 응급키트 연고는 가정 화상에서는 자극 성분이 오히려 재생을 막을 수 있어 불필요한 경우가 많아요.$AAA$, array['화상응급처치', '냉찜질', '물집관리', '수돗물', '상처연고']::text[], 2023, 'a6yQ_TeVfQc-1', 'https://youtu.be/a6yQ_TeVfQc?t=78s', null, '2023-01-10 00:00:00+00'::timestamptz, '2023-01-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$과산화수소나 빨간약으로 상처 소독해도 되나요?$AAQ$, $AAA$상처 소독에 **과산화수소, 빨간약, 알코올은 절대 사용하면 안 됩니다**. 이런 약물은 세균을 죽이는 데는 탁월하지만 피부 재생을 방해하고 심지어 피부 조직의 단백질을 변성시켜 파괴하는 작용을 해요. 과산화수소를 상처에 바르면 부글부글 올라오는 이유가 바로 단백질이 변성되며 기체가 생기기 때문입니다.

가장 좋은 소독은 **생리식염수이며, 정 안 되면 깨끗한 수돗물로 씻어내는 것이 차라리 낫습니다**. 수돗물은 절대 안 된다고 생각하시는 경우가 많지만, 자극이 강한 소독약보다 깨끗한 물이 조직 재생에 도움이 돼요. 결과적으로는 세균을 죽이는 것보다 조직 재생을 잘 유도하는 것이 훨씬 더 좋은 치료 결과로 이어집니다. 특히 아이들 상처에는 더욱 주의가 필요해요.$AAA$, array['상처소독', '과산화수소', '생리식염수', '수돗물세척', '피부재생']::text[], 2023, 'a6yQ_TeVfQc-2', 'https://youtu.be/a6yQ_TeVfQc?t=187s', null, '2023-01-10 00:00:00+00'::timestamptz, '2023-01-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$1도, 2도, 3도 화상은 어떻게 구분하나요?$AAQ$, $AAA$화상은 깊이에 따라 **1도, 2도, 3도로 구분합니다**. 1도 화상은 약간 빨갛게 되는 정도로 며칠이 지나면 저절로 좋아지는 가벼운 화상이에요. 2도 화상은 너무 뜨겁거나 노출 시간이 길어서 물집이 잡힌 경우로, 물집이 잡혔다면 2도라고 생각하시면 됩니다.

3도 화상은 **일반적인 기름이나 물로는 발생하기 어려우며 피부층 깊이까지 손상되어 색깔 자체가 변해 있습니다**. 까맣거나 하얗거나 누런 색으로 바뀌는 게 특징이에요. 2도 화상은 다시 표재성과 심재성으로 나뉘는데, 처음 화상 입은 시점에는 구분이 어렵고 드레싱 치료 후 흉터가 남았는지 여부로 판단합니다. 또한 온도가 무조건 높지 않아도 40도 정도 저온이라도 오래 노출되면 화상이 생길 수 있어 노출 시간도 중요해요.$AAA$, array['화상등급', '1도화상', '2도화상', '3도화상', '저온화상']::text[], 2023, 'a6yQ_TeVfQc-3', 'https://youtu.be/a6yQ_TeVfQc?t=357s', null, '2023-01-10 00:00:00+00'::timestamptz, '2023-01-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$오래된 화상 흉터도 치료가 가능한가요?$AAQ$, $AAA$오래된 화상 흉터도 **레이저 치료를 통해 어느 정도 개선이 가능하지만 완벽한 제거는 어렵습니다**. 흉터는 정상 피부와 비교해 높이, 색깔, 질감의 세 가지가 다르기 때문에 흉터로 보이는데, 치료의 목표는 이 세 가지를 정상 피부와 최대한 비슷하게 만드는 거예요. 다만 흰 흉터는 색소 세포가 없어진 상태라 치료가 어렵습니다.

중요한 점은 **흉터 발생 직후 염증세포 분비 시기와 흉터 조직이 불어나는 시기에 초기 진압이 핵심이라는 것입니다**. 이 시기에 드레싱 치료로 염증을 처리하고 흉터 세포 증식을 눌러주는 것이 중요해요. 처음에는 진물을 받아주는 메디폼 같은 비접착성 드레싱을 하루 한 번 교체하고, 재생된 후에는 접착력 있는 메디폼을 붙여줘야 조직 재생이 잘 됩니다. 20년 지난 흉터와 두 달 된 흉터는 치료 결과가 매우 달라요.$AAA$, array['화상흉터', '흉터치료', '레이저치료', '메디폼', '초기치료']::text[], 2023, 'a6yQ_TeVfQc-4', 'https://youtu.be/a6yQ_TeVfQc?t=624s', null, '2023-01-10 00:00:00+00'::timestamptz, '2023-01-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$반영구 문신과 영구 문신은 무엇이 다른가요?$AAQ$, $AAA$반영구 문신과 영구 문신은 **잉크가 들어가는 피부 층의 깊이가 다릅니다**. 반영구 문신은 피부 표피층, 즉 제일 바깥층에 가볍게 주입하는 방식이에요. 피부는 턴오버라고 해서 새로운 세포를 만들고 각질층은 탈락하는 과정이 평생 반복되기 때문에 반영구 문신은 조금씩 피부에서 사라지게 됩니다.

영구 문신은 **피부 깊은 층에 큰 잉크 입자를 주입하기 때문에 영원히 남게 됩니다**. 우리 몸에는 대식세포가 외부 물질을 잡아먹는 이물반응 기능이 있지만, 이 잉크는 세포가 제거할 수 없을 만큼 너무 커요. 그래서 반영구 문신은 표피층에 있어 비교적 제거가 수월한 반면, 영구 문신은 깊은 층에 자리 잡아 제거 과정이 훨씬 까다롭습니다.$AAA$, array['반영구문신', '영구문신', '표피층', '턴오버', '대식세포']::text[], 2023, 'LnUPdUa86l4-1', 'https://youtu.be/LnUPdUa86l4?t=68s', null, '2023-01-12 00:00:00+00'::timestamptz, '2023-01-12 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$문신 제거에는 어떤 레이저를 사용하나요?$AAQ$, $AAA$문신 제거 레이저는 **문신 색깔에 따라 다른 파장을 사용합니다**. 가장 많이 쓰는 1064 나노미터 파장은 검정색이나 어두운 색을 잘 흡수하며, 우리가 기미 치료에 사용하는 것과 같은 원리예요. 밝은 붉은색이나 오렌지색 계열은 더 짧은 파장인 532 나노미터를 사용합니다.

청색·초록색·파란색 같은 중간 색깔은 **670 나노미터나 785 나노미터 파장을 사용해 흡수율을 높입니다**. 요즘에는 펄스폭이 더 짧은 피코 레이저가 나와서 부작용을 줄이고 치료 효과를 강하게 낼 수 있어요. 다양한 파장을 한꺼번에 조사하면 더 효과적이라 1064 나노미터 후 785 나노미터를 한 번 더 조사하는 방법도 사용합니다. 어떤 문신이냐에 따라 사용하는 레이저가 달라지므로 진료를 통해 결정해야 합니다.$AAA$, array['문신제거레이저', '피코레이저', '1064나노미터', '532나노미터', '파장선택']::text[], 2023, 'LnUPdUa86l4-2', 'https://youtu.be/LnUPdUa86l4?t=205s', null, '2023-01-12 00:00:00+00'::timestamptz, '2023-01-12 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$문신 제거는 얼마나 오래 걸리나요?$AAQ$, $AAA$문신 제거는 **아무리 짧아도 1년, 길면 몇 년씩 걸리는 시술입니다**. 문신 입자를 제거하는 것뿐 아니라 제거 후 남은 흔적까지 청소하려면 오랜 시간이 필요해요. 2009년 커비·데사히 박사 논문에 따르면 피부 색깔, 문신 위치, 잉크 양, 레이어링, 흉터 유무 등이 제거 기간을 결정합니다.

구체적으로 **피부 톤이 어두울수록 제거가 어렵고, 얼굴 근처는 쉽고 손가락처럼 말단으로 갈수록 어렵습니다**. 잉크 양이 많거나 레이어링 같은 특수 기술이 들어간 멋진 문신일수록 더 까다로워요. 예를 들어 얼굴의 화려한 용 문신이라도 검정색만 사용했다면, 손가락에 여러 색깔로 그린 작은 꽃 문신보다 오히려 제거가 더 빠를 수 있습니다. 위치와 색깔 조합이 기간을 좌우해요.$AAA$, array['문신제거기간', '커비점수', '문신위치', '잉크색깔', '제거난이도']::text[], 2023, 'LnUPdUa86l4-3', 'https://youtu.be/LnUPdUa86l4?t=130s', null, '2023-01-12 00:00:00+00'::timestamptz, '2023-01-12 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$문신 제거 시술의 부작용은 어떤 것이 있나요?$AAQ$, $AAA$문신 제거의 가장 흔한 부작용은 **통증, 흉터, 색소침착입니다**. 피부 깊은 층의 큰 잉크 입자가 부서지면서 여러 개의 입자로 나뉘는 과정에서 통증이 크게 발생해요. 마취 크림이나 주사 마취 등 다양한 방법으로 통증을 줄여드리지만 어느 정도는 동반됩니다.

또한 너무 센 에너지를 사용하거나 **켈로이드 체질로 흉터가 잘 생기는 분들은 열 데미지 때문에 흉터가 생길 수 있고, 물집이나 피부염도 나타날 수 있어요**. 대부분 환자에게 나타나는 흔적 같은 염증 후 색소침착도 있는데, 이는 다른 레이저로 지우는 작업을 반복하면 대부분 해결됩니다. 시술 후에는 음주·흡연·찜질방·격렬한 운동 등 땀나는 활동을 피하고 냉찜질을 해주시면 물집이나 피부염 발생을 예방할 수 있어요.$AAA$, array['문신제거부작용', '통증', '켈로이드', '색소침착', '시술후관리']::text[], 2023, 'LnUPdUa86l4-4', 'https://youtu.be/LnUPdUa86l4?t=337s', null, '2023-01-12 00:00:00+00'::timestamptz, '2023-01-12 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$미라젯은 어떤 원리로 약물을 피부에 넣어주나요?$AAQ$, $AAA$미라젯은 **레이저 열 에너지를 압력으로 변환**해 바늘 없이 약물을 피부 속에 쏴 주는 시술입니다. 제트(jet)라는 이름처럼 압력으로 약물을 분출하는 방식이라, 쉽게 말하면 공기총을 쏘는 것과 비슷해요. 바늘 없이도 원하는 약물을 진피층에 직접 넣어줄 수 있는 점이 가장 큰 특징이에요.

피부가 좋아 보이려면 표피 아래 진피가 건강해야 하지만, 진피에 좋은 성분도 표피를 뚫지 못하면 소용이 없죠. 미라젯은 그 한계를 해결해 주는 장비입니다. 또한 약물이 강한 속도로 들어가며 피부 속에서 "펑!" 하고 터지는데, 이때 **들어갈 때 강한 압력 때문에 피부 속이 찢어진다고** 이해하시면 됩니다. 이런 미세한 박리 효과 덕분에 단순한 약물 주입을 넘어 흉터 치료 원리와 비슷한 효과까지 함께 얻을 수 있어요.$AAA$, array['미라젯', '제트분사', '스킨부스터', '약물주입', '진피층']::text[], 2023, '8PoIxXFv3pc-1', 'https://youtu.be/8PoIxXFv3pc?t=65s', null, '2023-01-17 00:00:00+00'::timestamptz, '2023-01-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$미라젯이 일반 주사보다 어떤 장점이 있나요?$AAQ$, $AAA$미라젯은 **정밀한 깊이와 균일한 분포로 약물을 주입**할 수 있다는 점이 일반 손주사와 가장 큰 차이입니다. 사람이 손으로는 한 포인트에 0.02mm씩 100방을 쏴서 총 20cc를 고르게 놓는 것이 불가능하지만, 기계인 미라젯은 가능해요. 원하는 진피층 깊이에 소량씩 전반적으로 고르게 주사할 수 있죠.

통증도 훨씬 적습니다. 손으로 놓는 피부 주사는 마취크림과 신경마취를 해도 너무 아파서 "다신 안 할래요"라고 하시는 분들이 많았어요. 미라젯은 약물이 피부를 뚫고 들어가기 때문에 따끔한 느낌은 있지만 충분히 참을 수 있는 정도예요. 또한 **이마·눈가·입가처럼 얇고 예민한 부위도 빠짐없이 꼼꼼하게 시술할 수 있다는** 점이 큰 장점이고, 회복 기간도 훨씬 짧습니다.$AAA$, array['미라젯', '주사비교', '통증감소', '균일주입', '회복기간']::text[], 2023, '8PoIxXFv3pc-2', 'https://youtu.be/8PoIxXFv3pc?t=121s', null, '2023-01-17 00:00:00+00'::timestamptz, '2023-01-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$미라젯은 어떤 시술이나 부위에 활용되나요?$AAQ$, $AAA$미라젯은 액체 약물이라면 대부분 주입 가능해 스킨부스터, 흉터, 튼살 등 다양한 영역에서 활용됩니다. 쥬베룩 같은 콜라겐 부스터, 히알루론산, 스킨 보톡스, PDRN, 리쥬란 등 **재생에 도움 주는 약물도 모두 사용할 수 있어요**. 특히 통증이 큰 쥬베룩 시술에서 미라젯이 큰 도움이 됩니다.

움푹 패인 여드름 흉터에도 자주 쓰이는데, 흉터 바닥이 딱딱하거나 질겨서 일반 주사가 잘 들어가지 않을 때 미라젯으로 쏘면 "퍽!" 소리와 함께 약물이 하얗게 잘 주입되는 게 보입니다. **흰 튼살처럼 색소침착 위험으로 치료가 어려웠던 병변에도 효과가 드라마틱하게 나타나는데**, 원하는 부위만 포인트로 치료할 수 있고 색소침착이 최소화된다는 점이 큰 장점이에요. 사진 비교상 양쪽 차이가 확연히 보일 정도로 효과가 확인됩니다.$AAA$, array['미라젯', '여드름흉터', '튼살치료', '쥬베룩', '스킨부스터']::text[], 2023, '8PoIxXFv3pc-3', 'https://youtu.be/8PoIxXFv3pc?t=362s', null, '2023-01-17 00:00:00+00'::timestamptz, '2023-01-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$미라젯 시술 후 회복과 관리는 어떻게 하나요?$AAQ$, $AAA$미라젯 시술은 마취 크림 후 시술 자체가 5~10분 정도로 짧고 관리도 간단합니다. 흉터마다 조금씩 차이는 있지만 한 5분에서 10분 정도면 끝나고, **약간 피가 나서 지혈 후 연고와 거즈만** 붙여주면 됩니다. 피가 많이 나지 않아 후처치가 어렵지 않아요.

당일 샤워만 피하시면 되고 다음 날부터는 가벼운 샤워가 충분히 가능합니다. 시술 후 통증 양상도 다른 레이저와 다른데, 보통 레이저들은 시술 후에도 화끈하고 따끔따끔한 증상이 남지만 미라젯은 **시술이 끝난 직후엔 통증이 하나도 없다는 점이** 큰 메리트예요. 다만 튼살 치료처럼 압축된 에너지를 분사하는 경우엔 시술 중 주먹을 꽉 쥐게 할 정도의 통증은 있을 수 있어요. 가족분들도 3~4일 후 붉은기가 가라앉으며 피부가 촉촉하고 탱탱해진다는 평가를 주셨습니다.$AAA$, array['미라젯', '시술후관리', '다운타임', '샤워', '회복']::text[], 2023, '8PoIxXFv3pc-4', 'https://youtu.be/8PoIxXFv3pc?t=521s', null, '2023-01-17 00:00:00+00'::timestamptz, '2023-01-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$콜라겐은 피부에서 어떤 역할을 하나요?$AAQ$, $AAA$콜라겐은 **피부 진피층의 80~90%를 차지하는** 주된 단백질로 탄력 있는 피부를 유지해주는 핵심 구조 단백질입니다. 몸 전체 단백질의 30% 정도를 차지하고 피부, 혈관, 뼈, 치아, 근육 등 모든 결합조직에 사용돼요. 세포와 세포 사이를 촘촘하게 연결함으로써 피부가 처지지 않게 지지하는 역할을 합니다.

안타깝게도 콜라겐 체내 생산량은 **20대 중반부터 매년 1%씩 떨어지기 시작해**, 나이가 들수록 감소 속도가 가속화됩니다. 그 결과 피부 탄력이 빠르게 떨어지고 주름이 발생하게 되죠. 아침에 베갯자국이 잘 안 사라지기 시작하는 시점이 관리를 시작할 때라고 환자분들께 설명드려요. 이런 이유로 콜라겐 식품, 바르는 제품, 붙이는 제품들이 꾸준히 관심을 받고 있어요.$AAA$, array['콜라겐', '진피층', '피부탄력', '노화', '단백질']::text[], 2023, 'XF2b5HOVPkA-1', 'https://youtu.be/XF2b5HOVPkA?t=72s', null, '2023-01-19 00:00:00+00'::timestamptz, '2023-01-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$바르는 콜라겐 화장품은 정말 효과가 있나요?$AAQ$, $AAA$**콜라겐 생성을 목적으로 한다면 바르는 콜라겐 제품은 효과가 없습니다**. 바르는 콜라겐이 효과를 내려면 각질층을 뚫고 진피에 도달해야 하는데, 흡수되기 위해서는 분자량이 500달톤 이하여야 해요. 그런데 일반적인 콜라겐의 분자량은 30만 달톤 이상이라 피부에 흡수될 수가 없습니다.

잘게 부순 콜라겐 제품도 일부분만 흡수되고 대부분은 각질층을 통과하지 못해요. 통과한 작은 조각이 진피에 도달했다 해도 본래의 콜라겐 형태로 복구돼 기능할지는 또 다른 문제입니다. 밀가루가 있다고 칼국수 면이 바로 만들어지진 않는 것과 같은 원리예요. 다만 분자량이 작아진 콜라겐 화장품은 표피 흡수율은 높아졌고 **수분 증발을 막아 보습을 유지하고 피부를 촉촉하게 만드는 데는** 도움이 될 수 있어요.$AAA$, array['바르는콜라겐', '흡수율', '분자량', '화장품', '보습']::text[], 2023, 'XF2b5HOVPkA-2', 'https://youtu.be/XF2b5HOVPkA?t=137s', null, '2023-01-19 00:00:00+00'::timestamptz, '2023-01-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$먹는 콜라겐은 피부에 효과가 있나요?$AAQ$, $AAA$**먹는 콜라겐은 눈에 띌 만족스러운 효과를 보긴 어렵습니다**. 콜라겐은 분자량이 커서 몸속에 쉽게 흡수되지 않고, 소화효소를 통해 아미노산, 디펩타이드, 트리펩타이드 형태로 잘게 분해되어야 흡수될 수 있어요. 소화 작용을 거쳐도 분자량이 큰 육류 콜라겐의 체내 흡수량은 약 2% 정도밖에 안 됩니다.

흡수돼도 콜라겐이 피부에만 있는 게 아니라 뼈나 연골 등 다른 곳으로도 가기 때문에 피부에 가는 직접적 영향은 작을 수밖에 없죠. 다만 흡수율을 높인 저분자 콜라겐이 출시되며 **피부 탄력과 수분 공급이 개선되고 진피 콜라겐 밀도가 증가했다는 논문들이** 보고되는 추세입니다. 어느 정도 기여한다고 생각되지만 약이 아니라 건강보조식품이라 개인차가 클 수 있어 복용 여부를 잘 판단하시는 것이 좋아요.$AAA$, array['먹는콜라겐', '저분자콜라겐', '흡수율', '건강기능식품', '피부탄력']::text[], 2023, 'XF2b5HOVPkA-3', 'https://youtu.be/XF2b5HOVPkA?t=314s', null, '2023-01-19 00:00:00+00'::timestamptz, '2023-01-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$콜라겐을 지키는 가장 좋은 방법은 무엇인가요?$AAQ$, $AAA$콜라겐은 늘리기 어렵기 때문에 **현재 있는 것을 최대한 잘 지키는 것이 중요합니다**. 피부 재생이 활발한 밤 10시부터 새벽 2시를 포함해 충분한 수면과 휴식, 그리고 철저한 보습 관리가 기본이에요. 노화 방지의 출발점은 결국 생활습관입니다.

피부 노화의 가장 중요한 원인은 자외선인데, **자외선은 콜라겐을 직접 파괴하고 감소시키므로 모자·양산·자외선 차단제가 필수입니다**. 비타민 C, E 같은 항산화 성분은 콜라겐 분해를 억제하는 데 도움이 되어 항산화 제품 사용도 좋아요. 시술로는 비타민 A 유도체 연고, 울쎄라 같은 초음파 장비, 써마지 같은 고주파 레이저, 진피 DNA 합성과 섬유아세포·성장인자 분비를 촉진하는 리쥬란 같은 스킨부스터, 그리고 실 리프팅도 도움이 될 수 있어요.$AAA$, array['콜라겐관리', '자외선차단', '항산화', '울쎄라', '리쥬란']::text[], 2023, 'XF2b5HOVPkA-4', 'https://youtu.be/XF2b5HOVPkA?t=433s', null, '2023-01-19 00:00:00+00'::timestamptz, '2023-01-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$발에 무좀이 생기면 식초나 목초액을 써도 되나요?$AAQ$, $AAA$**식초나 목초액 같은 민간요법은 권하지 않습니다**. 식초가 일부 미생물의 증식을 억제해 무좀에 효과가 있다는 연구는 있지만, 실제 항진균 효과를 내려면 물에 몇 방울 떨어뜨리는 수준이 아니라 화상을 입을 수 있을 정도의 농도가 필요해요. 목초액은 나무로 숯을 만드는 과정에서 나오는 연기를 액화시킨 액체로 pH 3 정도의 산성을 띱니다.

화상을 입지 않더라도 **피부장벽이 무너지면서 2차 세균감염을 유발할 수 있어서** 위험합니다. 특히 당뇨가 있는 분들은 2차감염으로 말초부위 괴사로 이어질 수 있어 더더욱 조심해야 해요. 실제로 발목까지 물집이 다 생겨 발이 퉁퉁 부어 오시는 경우들이 있습니다. 발 무좀은 바르는 연고만으로도 좋아지는 경우가 많고, 안 되면 먹는 약을 1~2주 짧게 복용해도 좋아져요.$AAA$, array['무좀민간요법', '식초', '목초액', '2차감염', '당뇨주의']::text[], 2023, 'sojGGgO_3I0-1', 'https://youtu.be/sojGGgO_3I0?t=121s', null, '2023-01-24 00:00:00+00'::timestamptz, '2023-01-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$무좀약은 정말 독한가요? 부작용이 걱정돼요.$AAQ$, $AAA$**현재 사용되는 무좀약은 예전만큼 독하지 않습니다**. 무좀약이 독하다는 인식은 케토코나졸 성분의 경구 제재 때문인데, 이 약은 2013년에 시장에서 퇴출당해 현재는 사용되지 않아요. 옛 인식에 갇혀 민간요법에 의지하다가 일을 키우시는 경우가 안타까울 만큼 많습니다.

지금 사용되는 경구 제재들은 주로 간을 통해 대사·배출되어 다른 약과 같이 먹을 때 주의가 필요한 약들이 있고요. 간이 원래 안 좋으신 분들도 **의사 진료하에 간 수치를 체크하면서 복용하면 큰 문제 없이** 복용할 수 있습니다. 발 무좀은 바르는 연고만으로도 좋아지는 경우가 많고, 연고로 호전이 안 될 때는 먹는 약을 1~2주 정도만 짧게 복용해도 충분해요. 약이 정 싫으시면 레이저 치료도 있으니 민간요법 대신 병원 진료를 받으시는 것이 좋습니다.$AAA$, array['무좀약', '케토코나졸', '경구항진균제', '간기능', '약독성']::text[], 2023, 'sojGGgO_3I0-2', 'https://youtu.be/sojGGgO_3I0?t=200s', null, '2023-01-24 00:00:00+00'::timestamptz, '2023-01-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$발톱 무좀은 왜 치료 기간이 그렇게 긴가요?$AAQ$, $AAA$**발톱은 처음부터 끝까지 자라나는 데에 1년이 걸리기 때문**입니다. 무좀약을 먹으면 발톱에 있는 균이 그냥 없어지는 게 아니라, 무좀균이 위쪽으로 먹어가는 걸 약이 억제하고 새로운 발톱이 깨끗하게 자라나는 원리예요. 그래서 끝까지 깨끗하게 자라나는 시간이 곧 발톱이 새로 나는 시간과 같습니다.

참고로 피부 자체의 턴오버 주기는 보통 4주라서 발 무좀은 비교적 짧게 잡혀요. 발톱 무좀은 일반적으로 **9개월에서 12개월이 걸리고 짧으면 6개월, 길게는 1년 넘게** 약을 드시는 분도 있어요. 또한 무좀이 심하면 발톱이 빨리 자라나지 않아 더 오래 걸립니다. 심하신 경우 약과 함께 발톱을 갈고 레이저 시술을 병행하기도 하는데, 레이저는 비용이 20~30만원대고 먹는 약을 못 먹는 경우에 한해 실비 적용이 됩니다.$AAA$, array['발톱무좀', '치료기간', '턴오버', '발톱레이저', '재발']::text[], 2023, 'sojGGgO_3I0-3', 'https://youtu.be/sojGGgO_3I0?t=305s', null, '2023-01-24 00:00:00+00'::timestamptz, '2023-01-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 압출은 꼭 피부과에서 해야 하나요?$AAQ$, $AAA$꼭 피부과에서 압출해야 하는 건 아니고 **집에서도 가능합니다**. 중요한 건 짜야 할 여드름과 짜지 말아야 할 여드름을 구분하는 것이 어렵다는 점이에요. 집에서 짤 수 있는 형태는 빨갛게 염증이 생긴 뒤 끝에 노랗거나 하얗게 고름이 맺힌 여드름인데, 면봉 두 개로 살짝 눌러서 짜고 피가 나면 지혈해주시면 됩니다.

짠 뒤에는 에스로반 같은 상처 연고를 발라 상처가 잘 아물게 해주세요. 반면 좁쌀 여드름, 결절성 여드름, 뾰루지처럼 부어오르는 형태는 일일이 짜면 **표피층을 벗겨내는 압력으로 파인 흉터가 생길 수 있습니다**. 어떤 여드름인지 모르겠다면 상처 연고를 바르며 지켜보거나 피부과에 오시는 것이 가장 좋아요. 짤까 말까 망설여질 때는 짜지 않는 것이 정답입니다.$AAA$, array['여드름압출', '홈케어', '면봉압출', '에스로반', '흉터예방']::text[], 2023, 'E-DF_a5WGgM-1', 'https://youtu.be/E-DF_a5WGgM?t=60s', null, '2023-01-26 00:00:00+00'::timestamptz, '2023-01-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$압출 받고 더 흉터가 생기는 이유는 무엇인가요?$AAQ$, $AAA$**압출 자체보다 염증이 너무 심해진 상태로 오신 경우가 더 흔한 원인입니다**. 압출하는 관리사의 경험·능력 부족으로 흉터가 생기는 경우도 있지만, 더 중요한 건 이미 여드름 염증이 너무 심해서 압출을 하지 않았어도 흉터가 생길 병변이었을 가능성이 많아요.

색소침착도 마찬가지인데, **염증이 생기고 나면 색소침착이 필연적으로 따라오기 때문에** 압출 때문이 아니라 자연 경과로 생긴 경우가 더 많습니다. 그래서 "손도 안 댔는데 색소침착과 흉터가 남았어요"라고 하시는 분들이 많아요. 염증은 최대한 빨리 없애줘야 색소침착도 덜 남기 때문에 빨리 치료하는 것이 좋습니다. 결절성 여드름이나 뾰루지처럼 붓기만 하는 여드름은 압출 대신 염증주사만으로도 충분히 잘 가라앉아요.$AAA$, array['압출흉터', '색소침착', '여드름염증', 'PIH', '염증주사']::text[], 2023, 'E-DF_a5WGgM-2', 'https://youtu.be/E-DF_a5WGgM?t=193s', null, '2023-01-26 00:00:00+00'::timestamptz, '2023-01-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 압출 후 어떻게 관리해야 하나요?$AAQ$, $AAA$**압출 후 피부는 상처가 많이 생긴 상태**이므로 상처 관리에 준해 다뤄야 합니다. 시술 직후엔 크림만 바르고 선크림도 바르지 말고 바로 집으로 가시는 게 좋고, 집에서 가볍게 물세안 후 첫날엔 상처 연고를 바르세요. 그 뒤로는 재생크림을 자주자주 발라 상처가 잘 아물도록 도와주는 것이 가장 중요해요.

처음 하루 이틀은 외출과 화장을 자제하시고, 피부가 어느 정도 아물면 가벼운 화장이나 선크림 후 외출이 가능합니다. **상처난 상태에서 햇빛을 보면 색소침착이 훨씬 더 많이 생기므로** 선크림·선글라스·모자로 자외선을 최대한 피하셔야 해요. 또 음주는 혈관 확장·염증 유발, 흡연은 담배연기 자극으로 트러블을 키울 수 있으니 당일과 다음 날엔 줄여주세요. 각질이 보기 싫다고 뜯거나 각질제거제를 쓰면 오히려 염증이 심해지니 금물입니다.$AAA$, array['압출후관리', '재생크림', '자외선차단', '금주금연', '각질제거금지']::text[], 2023, 'E-DF_a5WGgM-3', 'https://youtu.be/E-DF_a5WGgM?t=270s', null, '2023-01-26 00:00:00+00'::timestamptz, '2023-01-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 압출을 꼭 받아야 하는 이유는 무엇인가요?$AAQ$, $AAA$모든 여드름을 다 압출해야 하는 건 아닙니다. 결절성 여드름이나 뾰루지처럼 붓기만 하는 여드름은 **염증주사만으로도 충분히 잘 가라앉아요**. 하지만 빨리 제거해 줘야 하는 여드름들은 압출이 필요합니다.

이유는 명확합니다. **염증이 피부에 오래 남아 있을수록 색소침착도 더 많이 생기고**, 그 염증이 주변 피부조직을 파괴하면서 파인 흉터까지 더 많이 생길 수 있기 때문이에요. 빨리 제거해줘야 흉터가 적게 남는 거죠. 집에서 압출할 수 있는 노란 고름 형태가 아니라면 피부과에서 압출 받는 걸 권해 드려요. 압출을 정기적으로 잘 해주는 것만으로도 훨씬 깨끗한 피부를 유지할 수 있는 건 사실이에요. 다만 어떤 여드름은 짜고 어떤 건 놔둘지 구분이 어려우므로 진료를 받아보시는 것이 좋습니다.$AAA$, array['여드름압출', '흉터예방', '염증제거', '결절성여드름', '치료필요성']::text[], 2023, 'E-DF_a5WGgM-4', 'https://youtu.be/E-DF_a5WGgM?t=419s', null, '2023-01-26 00:00:00+00'::timestamptz, '2023-01-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$발 무좀은 어떤 부위에 잘 생기나요?$AAQ$, $AAA$**발과 같이 접혀 있고 습한 부위에 백선균이 잘 자랍니다**. 발은 신발 안에서 통풍이 잘 되지 않아 습해지기 쉬워 가장 흔한 부위이고, 겨드랑이·사타구니·남자분의 음낭 주변처럼 접혀 있는 부위도 습하기 때문에 무좀균이 잘 생기는 곳이에요. 정상 면역을 가진 사람이라도 장화나 군화처럼 오래 신고 통풍이 안 되면 얼마든지 무좀에 걸릴 수 있습니다.

부위별로 명명이 다른데, **발에 생긴 족부 백선, 손발톱 백선, 머리에 생기는 두부 백선, 몸통의 체부 백선**으로 구분해요. 음부나 엉덩이에 백선이 있어 피부과에 오시면 발에도 무좀이 있는지 한번 확인해 보는 것이 좋아요. 많은 경우 접촉을 통해 옮기 때문에 한쪽만 치료해서는 재발할 수 있습니다.$AAA$, array['무좀호발부위', '백선분류', '족부백선', '체부백선', '발톱무좀']::text[], 2023, 'PJPU_hI_fUs-1', 'https://youtu.be/PJPU_hI_fUs?t=106s', null, '2023-01-31 00:00:00+00'::timestamptz, '2023-01-31 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$무좀균은 피부에서 어떻게 자라나요?$AAQ$, $AAA$**백선균은 케라틴네이즈라는 효소를 분비해 각질을 녹이고 침투합니다**. 무좀균이 우리 몸을 침입할 때 케라틴네이즈를 분비하면 그 효소가 각질을 녹여 구멍을 뚫고, 녹은 각질을 케라틴네이즈가 먹고 살아가는 구조예요. 현미경으로 보면 길쭉한 나뭇가지 모양의 진균 균사가 레고 이어놓은 것처럼 세포 하나하나 연결돼 있습니다.

그래서 **피부장벽이 무너져 있으면 무좀균이든 세균이든 침입하기 쉬워지죠**. 면역력이 항암 치료나 장기이식 후 면역억제제 복용 수준으로 많이 떨어진 경우엔 발에 있던 무좀이 간·식도·폐로 옮겨가기도 합니다. 다만 일반적으론 정상 면역을 가진 사람도 통풍 안 되는 환경에서 충분히 걸리니, 너무 면역 문제로만 보지 않아도 돼요. 백혈구가 외부 세균·진균·이물질을 제거하는 면역 기능을 하기에 평소 컨디션 관리도 중요합니다.$AAA$, array['백선균', '케라틴네이즈', '진균균사', '피부장벽', '면역력']::text[], 2023, 'PJPU_hI_fUs-2', 'https://youtu.be/PJPU_hI_fUs?t=247s', null, '2023-01-31 00:00:00+00'::timestamptz, '2023-01-31 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$바르는 무좀약은 어떻게 곰팡이를 죽이나요?$AAQ$, $AAA$**아민계열 항진균제인 부테나핀 염산염은 진균의 세포막 합성 효소를 억제합니다**. 진균이 생성하는 세포막의 합성에 필요한 효소를 억제해 주는 성분이라, 약을 맞은 진균은 세포막이 형성되지 않게 되죠. 만화에서 무좀약을 뿌리자 무좀균이 녹는 것처럼 표현된 장면이 실제 작용을 잘 묘사한 거예요.

그 결과 **세포 안의 중요한 물질들이 밖으로 유출되면서 진균이 죽는** 원리입니다. 발톱 무좀의 경우엔 발톱 무좀 레이저도 많이 쓰여요. 피부 백선엔 일반적인 레이저는 잘 쓰지 않지만, 발톱 무좀 레이저는 임상에서 사용 중이라 빛이 발톱을 통과해 균을 공격하는 표현이 그쪽을 가리킬 수 있습니다. 따라서 무좀이 걱정될 때는 자가 진단이나 민간요법보다 피부과의 항진균 제제와 적절한 치료 옵션을 받아 보시는 것이 좋아요.$AAA$, array['부테나핀', '항진균제', '세포막억제', '발톱무좀레이저', '치료원리']::text[], 2023, 'PJPU_hI_fUs-3', 'https://youtu.be/PJPU_hI_fUs?t=185s', null, '2023-01-31 00:00:00+00'::timestamptz, '2023-01-31 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 흉터와 여드름 자국은 어떻게 다른가요?$AAQ$, $AAA$**여드름 자국은 평평하고 색깔만 바뀐 것**, 여드름 흉터는 정상 살보다 패이거나 튀어나온 것을 말합니다. 둘을 구분하는 가장 쉬운 방법은 만져 보는 것이에요. 여드름 자국은 튀어나오거나 패인 게 없이 빨갛거나 까만 색깔만 남아 있고, 여드름 흉터는 볼 쪽엔 주로 폭폭 패인 모양, 턱·목 라인엔 울퉁불퉁 튀어나오는 모양으로 나타나요.

둘을 나눠 알아야 하는 이유는 **예후와 치료 방법이 다르기 때문**입니다. 여드름 자국은 치료하지 않아도 시간이 지나면 저절로 상당 부분 해결돼 신경 쓰이지 않으면 굳이 치료하지 않아도 돼요. 다만 한두 달 만에 사라지는 것도 있지만 1년, 2년, 수년이 걸리기도 해 빨리 없애려면 붉은 자국엔 혈관 레이저, 색소침착엔 토닝 레이저를 합니다. 반면 여드름 흉터는 저절로 좋아지지 않으므로 치료가 반드시 필요해요.$AAA$, array['여드름흉터', '여드름자국', 'PIE', 'PIH', '흉터구분']::text[], 2023, '2vDXUTxNIbs-1', 'https://youtu.be/2vDXUTxNIbs?t=46s', null, '2023-02-02 00:00:00+00'::timestamptz, '2023-02-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$프락셀 같은 레이저는 어떻게 흉터를 채워 올리나요?$AAQ$, $AAA$**프랙셔널 레이저는 빔을 바둑판 모양으로 쪼개 일부만 조사하는 방식**입니다. 흉터에 쓰이는 레이저들은 피부에 미세한 상처를 내는 거라, 피부가 가진 재생력으로 살을 채워 올리는 원리예요. 흉터를 치료하기 위해 아이러니하게 다시 상처를 내는 셈입니다.

예전에는 패인 흉터를 치료하려고 레이저로 그 부위 전체를 깎았는데, 진물·딱지·예민함 등 부작용이 너무 심했어요. 프랙셔널 레이저는 빔을 쪼개 몇 군데에만 들어가고 **주변의 정상 부위가 레이저 빔이 들어간 부위의 회복을 도와주는** 구조라 효과는 비슷하면서 부작용은 훨씬 적습니다. 종류로는 프락셀 외에도 CO2 레이저를 이용한 CO2 프랙셔널, 피코 레이저를 이용한 피코 프랙셔널이 있어요. 레이저마다 깊이·특징은 조금씩 다르지만 효과와 원리는 비슷합니다.$AAA$, array['프락셀', '프랙셔널레이저', 'CO2프랙셔널', '피코프랙셔널', '흉터레이저']::text[], 2023, '2vDXUTxNIbs-2', 'https://youtu.be/2vDXUTxNIbs?t=202s', null, '2023-02-02 00:00:00+00'::timestamptz, '2023-02-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 흉터에는 어떤 치료 방법들이 있나요?$AAQ$, $AAA$여드름 흉터 치료는 **크게 레이저, 채워 넣는 주사, 크로스(도트필), 서브시전 4가지**로 나눌 수 있습니다. 어떤 방법을 쓰든 목표는 동일해요. "살을 채워 올리는 것"입니다. 흉터에 따라 적절한 방법이 달라지죠.

주사 종류로는 흉터 필러로 공간을 들어 올리거나, **쥬베룩(PLA) 성분이 피부 속에서 콜라겐을 재생시켜 꺼진 흉터에 좋은 효과를 내요**. 크로스(Chemical Reconstruction of Skin Scar)는 TCA 약물을 좁고 깊은 흉터에만 발라 화학적으로 부식시키는 방법으로, 좁은 흉터엔 레이저를 정확히 바닥에 쏘기 어렵기에 도트필이 유용합니다. 서브시전은 피부 밑에서 밧줄처럼 잡아당기는 섬유질을 끊어 살이 차오르게 하는 방법이에요. 그 밖에 니들 고주파, 플라즈마, 펀치로 부위를 뚫어 새살이 차오르게 하는 방법까지 활용됩니다.$AAA$, array['여드름흉터치료', '흉터필러', '쥬베룩', '크로스', '서브시전']::text[], 2023, '2vDXUTxNIbs-3', 'https://youtu.be/2vDXUTxNIbs?t=170s', null, '2023-02-02 00:00:00+00'::timestamptz, '2023-02-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 흉터 연고와 패치는 효과가 있나요?$AAQ$, $AAA$**패인 여드름 흉터에는 연고와 패치 모두 효과가 없습니다**. 콘트라투벡스, 스카겔, 노스카나겔 같은 흉터 연고는 여드름 자국이나 튀어나온 흉터에는 어느 정도 도움이 될 수 있지만, 여드름 흉터의 대부분을 차지하는 패인 흉터에는 도움이 되지 않아요.

노스카나겔에는 헤파린 나트륨이나 알란토인처럼 흉터를 부드럽게 풀어주는 성분과 피부 장벽을 회복시키는 덱스판테놀이 들어 있어요. 그래서 **울퉁불퉁 튀어나온 흉터엔 어느 정도 도움이 되지만 패여 있는 흉터엔 크게 도움이 안 됩니다**. 여드름 패치도 마찬가지로 패인 흉터엔 효과가 없고, 생긴 지 얼마 안 된 작은 여드름이나 자국 단계에선 도움이 될 수 있어요. 손으로 만지지 않게 막아주는 효과와 자외선 차단 효과도 일부 있어서 못 참겠으면 붙여도 된다고 안내합니다.$AAA$, array['흉터연고', '노스카나겔', '여드름패치', '콘트라투벡스', '패인흉터']::text[], 2023, '2vDXUTxNIbs-4', 'https://youtu.be/2vDXUTxNIbs?t=434s', null, '2023-02-02 00:00:00+00'::timestamptz, '2023-02-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$블랙헤드는 왜 생기고 화이트헤드와 어떻게 다른가요?$AAQ$, $AAA$블랙헤드는 **피지가 모공에 쌓여 공기와 접촉해 산화되며 검게 변한 것**이고, 같은 피지가 안쪽으로 막혀 공기와 접촉하지 않아 하얗게 보이는 것이 화이트헤드입니다. 피지는 피지선과 연결된 모공에서 분비되는데, 과도하게 생성되면 배출통로인 모공이 넓어지고 그 안에 피지가 쌓이게 되죠.

블랙헤드는 특히 **얼굴의 중심부 코쪽, 피지 분비가 많은 부위에 딸기 씨처럼 잘 발생합니다**. 마스크를 오래 쓰면서 모공이 더 커지고 피지가 늘어났다고 호소하시는 분이 많아진 것도 환경 영향이에요. 짜면 일시적으로 시원하지만 다음 날 또 그대로 돌아오는 이유는 피지가 자연스럽게 분비되는 정상 생리이기 때문입니다. 피지는 보습·항염·면역기능 조절 등 다양한 작용을 해 완전히 없앨 수 있는 존재도, 없애야 할 존재도 아니에요.$AAA$, array['블랙헤드', '화이트헤드', '피지산화', '모공', '코블랙헤드']::text[], 2023, 'RGh52QITCmw-1', 'https://youtu.be/RGh52QITCmw?t=63s', null, '2023-02-07 00:00:00+00'::timestamptz, '2023-02-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$블랙헤드를 손이나 압출기로 짜도 되나요?$AAQ$, $AAA$**손이나 압출기로 짜는 것은 권하지 않습니다**. 손을 아무리 깨끗이 씻어도 세균이 있고, 짜다가 피부에 상처가 나면서 세균감염이 되기 쉽기 때문이에요. 압출기로 과도하게 누르면 주변 피부가 손상을 입을 수 있습니다.

더 큰 문제는 **이런 행위가 피지선과 피부를 과도하게 자극해 모공이 더 넓어지고 유수분 밸런스가 깨지며 피지가 더 많이 생성되는 악순환을** 겪을 수 있다는 점입니다. 코팩도 비슷한 맥락인데, 접착제 성분이 피지를 빼는 데는 도움이 되지만 정상 피부에 자극을 줘 장기 사용 시 피부 장벽을 손상시킬 수 있어요. 민감성 피부는 코팩을 피하고, 그래도 쓰고 싶다면 일주일 정도 간격을 두고 사용한 뒤 보습제로 손상된 장벽 회복을 돕는 것이 가장 중요합니다. 집에서 쓰는 필링 스크러버도 블랙헤드가 있는 부위에만 자극 없이 조심해 써야 해요.$AAA$, array['블랙헤드짜기', '압출기', '코팩', '피부장벽', '악순환']::text[], 2023, 'RGh52QITCmw-2', 'https://youtu.be/RGh52QITCmw?t=98s', null, '2023-02-07 00:00:00+00'::timestamptz, '2023-02-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$엑스 로션 같은 블랙헤드 제거 제품은 안전한가요?$AAQ$, $AAA$**엑스 로션은 자극이 강해 민감성 피부에는 사용하지 않는 것이 좋습니다**. 주성분은 트리에탄올아민이라는 피지 연화제로 pH 10 정도의 알칼리성 물질이에요. 피지의 지방산과 만나 블랙헤드를 녹이는 작용을 하지만 자극이 강합니다.

특히 **자극이 심하고 접촉 피부염을 유발할 수 있어 민감성 피부엔 사용하지 않는 것이 좋아요**. 블랙헤드가 너무 심하고 피부가 튼튼하신 경우엔 가끔 사용해 볼 수 있지만, 장기적으로 사용하면 피부 장벽을 손상시킬 수 있어 일반적으로 권하지 않습니다. 코팩 역시 정상 피부에 자극을 주어 장기 사용 시 장벽 손상을 일으킬 수 있으니 민감성 피부는 피하고, 코팩 후엔 보습제로 손상된 장벽 회복을 도와줘야 해요. 결국 블랙헤드 제거는 한번에 큰 충격을 주기보다 일상 관리로 부드럽게 다루는 편이 더 안전합니다.$AAA$, array['엑스로션', '트리에탄올아민', '민감성피부', '접촉피부염', '알칼리성']::text[], 2023, 'RGh52QITCmw-3', 'https://youtu.be/RGh52QITCmw?t=242s', null, '2023-02-07 00:00:00+00'::timestamptz, '2023-02-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$블랙헤드를 줄이는 일상 클렌징 방법은 무엇인가요?$AAQ$, $AAA$**피지는 기름이라 물로는 녹지 않고 오일 성분에 녹기 때문에 클렌징 오일이 핵심**입니다. 메이크업을 하시는 분은 이중 세안의 1차 세안 때 클렌징 오일을 사용해 피지가 자연스럽게 오일에 녹아 나오도록 관리해 주세요. 다만 오일 잔여물이 다시 모공을 막을 수 있어 약산성 클렌저로 2차 세안을 꼭 해주셔야 해요.

메이크업을 안 하시는 분은 매일 이중 세안을 하기 어려우니 블랙헤드 부위만 오일로 관리하거나, **일주일에 1~2번 따뜻한 물로 샤워 후 모공이 열린 상태에서 클렌징 오일로 부드럽게 마사지하시면** 도움이 됩니다. 너무 오래 세게 문지르면 정상 피부에 자극이 되니 주의해야 해요. 오일이 안 맞는 분은 살리실산(BHA)이 포함된 클렌저 제품이 각질·피지를 녹여줘 도움이 되지만, 민감성 피부는 빈도를 줄이고 빨개지거나 가려우면 사용을 중단하셔야 합니다.$AAA$, array['클렌징오일', '이중세안', '살리실산BHA', '약산성클렌저', '블랙헤드관리']::text[], 2023, 'RGh52QITCmw-4', 'https://youtu.be/RGh52QITCmw?t=346s', null, '2023-02-07 00:00:00+00'::timestamptz, '2023-02-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$블랙헤드 예방에 도움이 되는 성분이 있나요?$AAQ$, $AAA$**비타민 A 유도체와 항산화 성분이 블랙헤드 예방에 도움이 됩니다**. 여드름이 심한 경우엔 이소트레티노인 같은 피지 억제제를 복용하면 도움이 될 수 있는데, 비타민 A 유도체로 피지 분비량 자체를 줄여 여드름 발생도 막고 모공 관리에도 도움을 줘요. 다만 입술·눈·손등의 건조증이 함께 와 블랙헤드만으로 약을 복용하기엔 권하기 어렵습니다.

바르는 비타민 A로는 화장품에 들어 있는 레티놀이나 스티바에이 연고의 레티노익애시드가 있는데, **과도하게 쌓인 각질도 정리하고 피지 분비를 조절하며 모공 탄력을 높여** 블랙헤드 발생을 예방합니다. 단 저녁에만 사용, 자외선 차단제 병용, 보습제와 소량 섞어 시작 후 점차 늘리고, 따갑거나 부으면 2~3일에 한 번으로 빈도를 조절해야 해요. 비타민 C·E·나이아신아마이드 같은 항산화제 성분이 피지 분비를 조절해 도움이 된다고 알려져 있어 성분이 함유된 제품 사용도 좋습니다.$AAA$, array['레티놀', '레티노익애시드', '이소트레티노인', '나이아신아마이드', '항산화']::text[], 2023, 'RGh52QITCmw-5', 'https://youtu.be/RGh52QITCmw?t=440s', null, '2023-02-07 00:00:00+00'::timestamptz, '2023-02-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$사마귀와 쥐젖, 물사마귀는 어떻게 다른가요?$AAQ$, $AAA$사마귀와 물사마귀는 바이러스 감염 질환이지만, 쥐젖은 바이러스와 무관한 피부 돌출입니다. 사마귀는 인유두종 바이러스(HPV) 감염으로 생기고, 물사마귀의 정확한 명칭은 전염성 연속종으로 Molluscum Contagiosum Virus라는 **다른 바이러스에 의해** 발생합니다. 쥐젖은 바이러스 병변이 아니어서 전염되지 않고 유전적 요인, 비만, 당뇨와 연관이 있습니다.

외형도 차이가 있어요. 쥐젖은 피부가 뽕 튀어나와 있어 목을 묶으면 피가 안 통해 떨어질 수 있지만, 사마귀는 혈관이 발달한 병변이어서 묶는 것만으로 떨어지지 않습니다. 물사마귀는 **3mm에서 6mm 정도의 붉은색이나 살색을 띠는 반구 모양 구진**으로 가운데가 함몰된 형태로 생기고, 주로 영아·소아에 발생합니다. 사마귀는 치료를 안 하면 계속 전염되지만, 쥐젖은 미관상 이유 외에는 꼭 제거할 필요가 없는 병변입니다.$AAA$, array['사마귀', '쥐젖', '물사마귀', '인유두종바이러스', '전염성연속종']::text[], 2023, 'Kc76PHeRE3E-1', 'https://youtu.be/Kc76PHeRE3E?t=18s', null, '2023-02-09 00:00:00+00'::timestamptz, '2023-02-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$사마귀에 율무가 효과 있나요?$AAQ$, $AAA$율무로 사마귀 바이러스를 없앨 수는 없다는 게 결론입니다. 율무나 티트리 오일에 효과가 있다는 보고가 일부 논문에 있긴 하지만, 의사가 효과가 있다고 얘기할 정도로 **유의미한 결과는 아닙니다**. 감기에 걸려도 바이러스를 직접 없애는 게 아니라 증상 치료를 하는 것처럼, 사마귀도 율무로 바이러스를 없앤다는 건 맞지 않아요.

다만 사마귀는 저절로 없어지기도 합니다. 그래도 발바닥이나 손에 생긴 사마귀는 걷는 데 불편함을 주고, **바이러스 감염이기 때문에 다른 부위로 번지거나 다른 사람에게 옮길 수 있어** 치료가 필요합니다. 병원에서는 주로 냉동 치료나 레이저 제거술을 시행하는데, 통증이 있고 한 번에 끝나지 않아 반복 치료가 필요해 민간요법을 더 많이 찾으시는 경향이 있어요. 율무·티트리 오일을 보조적으로 시도할 수는 있지만 정식 치료를 대체하지는 않습니다.$AAA$, array['율무사마귀', '민간요법', '사마귀치료', '냉동치료', '레이저제거술']::text[], 2023, 'Kc76PHeRE3E-2', 'https://youtu.be/Kc76PHeRE3E?t=148s', null, '2023-02-09 00:00:00+00'::timestamptz, '2023-02-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$물사마귀 병원 치료는 어떻게 하나요?$AAQ$, $AAA$물사마귀의 병원 치료는 국소마취제를 바른 뒤 큐렛이나 핀셋으로 긁어내 따는 방법이 기본입니다. 바이러스 감염이기 때문에 한 번에 끝나지 않고 여러 번 제거해야 하는 경우가 많아요. 연고를 바르고 따더라도 피부를 긁어내는 것이라 **통증이 있고 피가 나기 때문에**, 아이가 다음번에 치료를 거부하는 경우가 흔합니다.

치료를 너무 힘들어할 때는 보조적으로 페디오와트·돌피니와트 같은 율무 성분 캔디나, 티트리 오일·호호바씨 오일이 든 피토버, 달맞이꽃 종자유로 만든 소아용 에보프림 등을 시도할 수 있어요. 에보프림을 병변에 **하루 두 번씩 세 달 정도 발랐을 때 환자의 3분의 1 정도에서 호전됐다는 연구**가 있습니다. 또한 피부 면역력이 떨어지면 잘 번지므로 보습을 잘 해주고 유산균·비타민 복용도 도움이 될 수 있어요.$AAA$, array['물사마귀치료', '큐렛제거', '에보프림', '피토버', '보습관리']::text[], 2023, 'Kc76PHeRE3E-3', 'https://youtu.be/Kc76PHeRE3E?t=300s', null, '2023-02-09 00:00:00+00'::timestamptz, '2023-02-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$물사마귀는 자연 치유 기다려도 되나요?$AAQ$, $AAA$물사마귀는 6~12개월 정도면 결국 자연 치유가 되기 때문에 기다려도 되긴 하지만, 초기에 치료하는 게 권장됩니다. 수개월에 걸쳐 거의 자연 치유되지만 **수년 걸리는 경우도 있고**, 얼굴 같은 곳에 생기면 미용적 문제가 될 수 있어요. 전신으로 많이 번지면 치료가 꼭 필요합니다.

특히 피부 장벽이 무너진 아토피 아이들은 가려워서 긁다 보면 자가 감염이 일어나 옆으로 번지는 경향이 큽니다. **너무 많이 번져서 고생하는 아이들을 많이 봤기 때문에**, 의사들 중에는 따지 말고 두라는 의견도 있지만 초기에 떼는 게 맞다는 입장도 있어요. 피토버 같은 제품은 물사마귀 자체를 없애는 건 아니지만 염증과 가려움을 완화해 덜 번지게 하는 데 사용해 볼 수 있고, 사용 중 빨개지거나 가려워하면 바로 중단하시는 게 좋습니다.$AAA$, array['물사마귀자연치유', '조기치료', '아토피', '자가감염', '전염성연속종']::text[], 2023, 'Kc76PHeRE3E-4', 'https://youtu.be/Kc76PHeRE3E?t=253s', null, '2023-02-09 00:00:00+00'::timestamptz, '2023-02-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증 수술은 어떻게 하나요?$AAQ$, $AAA$백반증 수술은 멜라닌 세포가 살아 있는 정상 피부를 떼어 백반증 부위에 옮겨 심는 표피 이식 수술입니다. 가장 많이 사용하는 방법이 미세 펀치 이식술로, **직경 0.5~0.8mm 정도의 펀치 기구**를 사용해 건강한 피부를 채취해 모내기하듯 환부에 심어줍니다. 이식된 멜라닌 세포가 주변 피부로 점점 퍼져나가 백반증 부위가 정상 피부로 회복되는 원리예요.

기존 1~2mm 펀치 이식술에 비해 흉터 발생이 현저히 줄었고 전용 전동 펀처를 사용해 수술 시간도 크게 단축됐습니다. 그 외에 흡입 물질 이식이나 세포 이식처럼 멜라닌 세포를 한꺼번에 많이 옮기는 방법도 있지만 시간이 오래 걸리는 단점이 있어요. **수술은 보통 백반증이 멈춰 있는 분들에게 시행**하며, 적절한 적응증에서는 드라마틱한 효과를 낼 수 있어 백반증 수술을 고민하는 분들에게 적합한 치료입니다.$AAA$, array['백반증수술', '미세펀치이식술', '표피이식', '멜라닌세포', '백반증치료']::text[], 2023, 'Xn015HsPxUk-1', 'https://youtu.be/Xn015HsPxUk?t=72s', null, '2023-02-14 00:00:00+00'::timestamptz, '2023-02-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증 수술 후 생착률은 얼마나 되나요?$AAQ$, $AAA$백반증 수술의 생착률은 부위에 따라 차이가 크며, 얼굴과 목은 80~90%까지 나오는 편입니다. 팔다리는 50% 정도, 손발은 생착률이 떨어져 **20~30% 정도로 설명**드리고 있어요. 메타 분석에서도 효과가 좋지 않은 부위는 20~30%, 효과가 좋은 부위는 80~90%까지 나올 정도로 부위별 편차가 분명합니다.

수술이 멜라닌 세포가 없는 부위에 세포를 이식해 심어주는 것이라 백반증을 일으키는 면역 반응 자체를 없애는 시술은 아닙니다. 따라서 **백반증이 원래 가지고 있는 재발률만큼은 재발 가능성이 있지만** 수술 때문에 더 많이 재발하지는 않아요. 100개 중 5개 정도가 생착에 실패해 얼룩덜룩해질 수 있는데, 실패한 부분은 다른 치료를 병행하거나 시간이 지난 뒤 한 번 더 수술해 보완합니다.$AAA$, array['생착률', '백반증재발', '수술성공률', '얼굴생착', '손발생착']::text[], 2023, 'Xn015HsPxUk-2', 'https://youtu.be/Xn015HsPxUk?t=345s', null, '2023-02-14 00:00:00+00'::timestamptz, '2023-02-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증 수술 후 관리는 어떻게 해야 하나요?$AAQ$, $AAA$백반증 수술 후에는 세포를 이식한 수여부와 피부를 떼어낸 공여부 모두 일정 기간 보호가 필요합니다. 수여부는 새로운 세포가 생착해야 하기 때문에 **5일에서 일주일 정도는 물이 닿지 않게** 밀폐 드레싱을 하고 최대한 움직이지 않도록 합니다. 공여부에는 방수 테이프를 붙여 일주일 정도 유지하고, 이후에는 흉터 예방 연고를 사용해요.

수술이라는 행위 자체가 어느 정도 상처를 남기기 때문에 흉터 발생이 필연적이고, 흉터가 잘 생기시는 분들은 더 신경 써야 합니다. 생착과 **흉터 발생 억제를 위해 수술 후 1주는 최대한 움직이지 않도록** 조심하고 흉터 억제 연고를 잘 발라주는 게 도움이 됩니다. 계절은 사계절 모두 수술 가능하지만 일주일간 물도 안 닿게 해야 하므로 땀이 많이 나는 분은 다른 계절을 택하거나 본인 스케줄에 맞춰 조절할 수 있어요.$AAA$, array['수술후관리', '밀폐드레싱', '흉터예방', '방수테이프', '백반증회복']::text[], 2023, 'Xn015HsPxUk-3', 'https://youtu.be/Xn015HsPxUk?t=212s', null, '2023-02-14 00:00:00+00'::timestamptz, '2023-02-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증 수술 비용은 얼마인가요?$AAQ$, $AAA$노출 부위 백반증 수술은 건강보험이 적용되어 본인 부담금이 10~20만 원 정도입니다. 보험이 적용되는 노출 부위는 얼굴과 목, 팔 끝에서부터 겨드랑이까지, **다리 끝에서 무릎까지가 해당**돼요. 이 범위 안에서 수술을 받으면 비용 부담이 크게 줄어드는 편입니다.

마취는 수면 마취가 아니라 부위 마취로 진행되며, 주사로 해당 수술 부위를 마취해요. 주사 마취 시 통증이 있지만 **마취 연고를 바르거나 마취액을 최대한 천천히 주입**해 통증을 줄이는 노력을 합니다. 부위 마취이기 때문에 안전하게 시술할 수 있어요. 수술 시기·부위 선택, 언제 어떻게 수술하는지가 모두 결과에 영향을 주므로 피부과 전문의 진료를 통해 본인에게 백반증 수술이 적합한지 먼저 확인하는 게 중요합니다.$AAA$, array['백반증수술비용', '건강보험적용', '노출부위', '부위마취', '마취연고']::text[], 2023, 'Xn015HsPxUk-4', 'https://youtu.be/Xn015HsPxUk?t=190s', null, '2023-02-14 00:00:00+00'::timestamptz, '2023-02-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$눈가 주름은 왜 생기나요?$AAQ$, $AAA$눈가 주름은 안륜근이라는 근육이 표정을 지을 때 수축하면서 피부를 함께 밀어내 생깁니다. 우리 눈 주변에는 마치 판다처럼 동그랗게 안륜근이 있는데, 웃을 때 이 근육이 수축하면 **피부가 같이 밀리면서** 까마귀 발 모양(Crow's Feet)의 주름이 생기는 거예요. 주름 모양은 사람마다 달라 가로 일자형이나 사선형으로 나타납니다.

20~30대 젊을 때는 표정을 풀면 주름이 다시 펴지지만, 같은 부위 근육이 십수 년간 계속 수축하다 보면 피부 주름이 고정됩니다. **종이접기를 같은 부위에 수차례 반복하면 선명하게 선이 남는 것처럼**, 표정 주름이 반복되면서 결국 고정 주름으로 자리 잡는 거죠. 그래서 같은 사람도 나이가 들수록 표정을 풀어도 주름이 남는 형태로 변하게 됩니다.$AAA$, array['눈가주름', '안륜근', 'Crow''sFeet', '표정주름', '눈웃음주름']::text[], 2023, 'nPp5sdjQzEk-1', 'https://youtu.be/nPp5sdjQzEk?t=87s', null, '2023-02-16 00:00:00+00'::timestamptz, '2023-02-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$눈 밑 잔주름은 왜 생기나요?$AAQ$, $AAA$눈 밑 잔주름은 피부 자체가 얇고 건조해지기 쉬운 부위적 특성 때문에 잘 생깁니다. 눈 아래는 우리 몸의 피부 중 가장 얇은 피부에 해당하고, **피지샘 밀도도 낮아 건조해지기 쉬운 부위**예요. 얇은 한지가 조금만 자극을 줘도 구깃해지는 것처럼, 눈가의 얇은 피부는 잔주름이 잘 생기고 노화가 진행되면 더 잘 생깁니다.

원인은 크게 두 가지입니다. 첫째는 노화로, **콜라겐이나 엘라스틴 같은 피부를 탄탄하게 받쳐주는 성분들이 줄어들면서** 잔주름이 생겨요. 둘째는 피부 건조로, 눈 밑을 자주 만지거나 긁는 행동이 마찰을 만들어 자극을 줍니다. 특히 아토피 피부염이 눈 주변에 만성적으로 오래된 분들은 눈가 피부가 코끼리 피부처럼 두꺼워지고 잔주름이 진하게 짝짝 가 있는 모습이 관찰돼요.$AAA$, array['눈밑잔주름', '피부건조', '콜라겐엘라스틴', '아토피', '피지샘밀도']::text[], 2023, 'nPp5sdjQzEk-2', 'https://youtu.be/nPp5sdjQzEk?t=165s', null, '2023-02-16 00:00:00+00'::timestamptz, '2023-02-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$눈 밑이 볼록해진 건 주름인가요?$AAQ$, $AAA$눈 밑이 볼록해 보이는 건 주름이 아니라 안구를 보호하는 지방층이 돌출되어 생긴 음영입니다. 우리 눈 아래쪽 두개골 위로 지방층이 존재하는데, 이 지방층은 **안구를 보호하기 위한 일종의 쿠션 역할**을 합니다. 그런데 노화가 진행되면 지방층을 잡고 있는 구조물들이 점점 느슨해지면서 지방이 밖으로 돌출되는 거예요.

눈 밑이 볼록해지면 아래쪽에 음영이 지면서 마치 주름이 생긴 것처럼 보입니다. **실제로는 주름이 아니고 튀어나온 지방이 만든 음영**에 해당돼요. 또 눈 밑 고랑 또는 눈 밑 팔자 주름이라 부르는 음영은 받쳐주던 조직이 줄어들어 풍선에 바람이 빠진 것처럼 꺼져 보이는 것입니다. 이런 변화들은 보톡스로 좋아질 수 있는 주름이 아닐 수 있으니 정확한 진료를 통한 구분이 필요해요.$AAA$, array['눈밑지방', '눈밑꺼짐', '음영주름', '팔자주름', '안구쿠션']::text[], 2023, 'nPp5sdjQzEk-3', 'https://youtu.be/nPp5sdjQzEk?t=272s', null, '2023-02-16 00:00:00+00'::timestamptz, '2023-02-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$눈가 주름은 평소에 어떻게 관리해야 하나요?$AAQ$, $AAA$눈가 주름 예방은 보습과 자외선 차단 두 가지가 핵심입니다. 눈가는 피부가 건조해지기 쉬워 아이크림을 수시로 발라 촉촉하게 유지하는 것만으로도 잔주름을 예방할 수 있어요. **비싼 아이크림이 꼭 필요한 건 아니고**, 얼굴에 바르는 보습감 충분한 로션이나 크림을 눈가에도 발라주는 것으로도 충분합니다. 추가로 레티놀이나 레티날 같은 레티노이드 계열 성분이 있으면 도움이 됩니다.

두 번째는 선크림인데 눈가 피부가 워낙 얇아 자외선에 매우 취약합니다. 다른 부위는 열심히 바르면서 **눈가는 빠트리는 경우가 굉장히 많아서** 눈가에도 빠짐없이 발라줘야 해요. 단 비벼서 바르면 자극이 가해질 수 있으니 톡톡 두들겨주면서 발라주시는 게 좋습니다. 평소 관리만으로도 잔주름 발생을 상당히 늦출 수 있어요.$AAA$, array['아이크림', '보습관리', '선크림', '레티놀', '눈가차단제']::text[], 2023, 'nPp5sdjQzEk-4', 'https://youtu.be/nPp5sdjQzEk?t=356s', null, '2023-02-16 00:00:00+00'::timestamptz, '2023-02-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$PHA 필은 어떤 관리인가요?$AAQ$, $AAA$PHA 필은 Poly Hydroxy Acid 성분으로 수분 공급과 각질 정리를 함께 해주는 관리입니다. 이름 그대로 **물 분자를 많이 머금고 있어 수분 공급이 잘되고**, 산 성분이 묵은 각질을 벗겨내며 피부 재생을 돕는 원리예요. 받았다는 티 없이 피부 광택과 화장 밀착감이 좋아져 중요한 약속 전 관리로 많이 권합니다.

산 성분이지만 **분자량이 커서 침투가 천천히 이루어져 자극감이 거의 없다는 게 큰 장점**입니다. 그래서 웨딩 전이나 시상식 전 안전하게 피부를 정돈하려는 분들이 많이 받고, 연예인 필이라는 이름으로도 유명했어요. 실제로 촬영 후 피부가 뒤집어져 각질이 생겼을 때 보습제로도 안 가라앉던 것이 PHA 필 한 번에 가라앉는 경우도 있고, 다음 날 일정이 중요한 분들이 안전하게 시도해 볼 수 있는 관리입니다.$AAA$, array['PHA필', '각질관리', '수분공급', '연예인필', '저자극필링']::text[], 2023, 'pwEa8iIjNFM-1', 'https://youtu.be/isurrT0ap1c?t=56s', null, '2023-02-21 00:00:00+00'::timestamptz, '2023-02-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$LDM 물방울 리프팅은 어떤 효과가 있나요?$AAQ$, $AAA$LDM 물방울 리프팅은 보습과 노화 방지 효과를 함께 주는 관리로, 보습으로 촉촉해지고 리프팅으로 노화를 방지한다는 의미에서 물방울 리프팅이라 불립니다. **보습 효과가 확 올라가 촉촉해지고 화장도 굉장히 잘 먹으며**, 멀리서 봐도 광이 나는 피부가 됩니다. 아토피 피부염이나 홍조 경향이 있는 분들에게 특히 권할 만한 관리예요.

임상에서 보면 접촉 피부염이 반복적으로 올라오는 분, 스테로이드를 끊으면 재발하는 분, 홍조가 심한 분들이 꾸준히 받으면 약을 끊어도 될 만큼 좋아지는 경우가 많았어요. **다른 병원에서 여러 레이저와 약을 시도해도 효과가 없던 분이 LDM만 꾸준히 받아 홍조가 좋아진 사례**도 있고, 촬영 후 각질이 일어났을 때 한 번 받고 바로 가라앉기도 합니다. 자극에 민감한 피부를 안정시키며 컨디션을 끌어올리는 데 적합합니다.$AAA$, array['LDM', '물방울리프팅', '보습관리', '홍조관리', '민감성피부']::text[], 2023, 'pwEa8iIjNFM-2', 'https://youtu.be/isurrT0ap1c?t=171s', null, '2023-02-21 00:00:00+00'::timestamptz, '2023-02-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$코레지셀핏은 어떻게 효과가 나타나나요?$AAQ$, $AAA$코레지셀핏은 양자분자공명이라는 공명파를 이용해 피부 속 세포를 활성화시키는 원리의 관리입니다. 일반적인 장비들이 좋은 성분을 바르고 초음파 진동이나 미세 전류로 흡수시키는 방식인 데 비해, 코레지셀핏은 **공명파로 피부 속 세포들을 흔들어 깨워 재생시키는 방식**이에요. 벗겨내거나 추가하는 게 아니라 내부 세포를 활성화시키는 접근입니다.

받아보면 '효과가 있겠나' 싶지만 꾸준히 3~4번 정도 받으면 변화가 체감됩니다. **피부결이 정리되는 느낌과 함께 광보다는 윤이 난다는 느낌**이 들고, 건강해지면서 화장도 잘 먹는 결과가 나타나요. 송혜교 같은 연예인이 화장을 했는데도 윤이 나 보이는 피부 결을 떠올리게 하는 느낌이라, 노화가 신경 쓰이지만 자극적인 시술이 부담스러운 분께 꾸준한 옵션으로 권할 만합니다.$AAA$, array['코레지셀핏', '양자분자공명', '공명파관리', '피부결정돈', '안티에이징']::text[], 2023, 'pwEa8iIjNFM-3', 'https://youtu.be/isurrT0ap1c?t=237s', null, '2023-02-21 00:00:00+00'::timestamptz, '2023-02-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$이온자임은 색소·기미에 효과 있나요?$AAQ$, $AAA$이온자임은 미백 성분을 피부에 침투시켜 색소와 기미를 밝게 만드는 관리입니다. 미백에 도움이 되는 성분을 피부에 바른 뒤 두 가지 방식으로 흡수시키는데, 초음파 진동을 이용한 **소노포레시스와 미세 전류를 이용한 이온토포레시스를 함께 적용**해요. 두 침투 방식의 결합으로 단순 도포보다 효과를 끌어올리는 구조입니다.

기미가 심하거나 휴가 후 칙칙해진 피부에 **2~3번 받으면 밝아지는 것이 눈에 보일 정도로 효과가 체감**됩니다. 침투시키는 성분들이 항산화 물질이기 때문에 단순 미백뿐 아니라 피부 자체가 건강해지는 변화도 나타나요. 골프 선수나 어머님들, 등산을 많이 다니거나 푸석푸석한 분들이 꾸준히 받으면 피부결이 좋아지고 밝아지는 효과가 있어 색소 관리가 필요할 때 권하는 옵션입니다.$AAA$, array['이온자임', '소노포레시스', '이온토포레시스', '기미관리', '미백관리']::text[], 2023, 'pwEa8iIjNFM-4', 'https://youtu.be/isurrT0ap1c?t=437s', null, '2023-02-21 00:00:00+00'::timestamptz, '2023-02-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부 노화는 왜 일어나나요?$AAQ$, $AAA$피부 노화는 내인성 노화와 외인성 노화 두 가지로 나뉘며, 피부도 신체 기관의 일부이기 때문에 노화가 일어날 수밖에 없습니다. 내인성 노화는 유전자에 **태어날 때부터 프로그래밍되어 있어 막을 방법이 없지만**, 외인성 노화는 자외선을 차단하는 등 외부 요인을 막는 방법으로 개인의 노력으로 상당 부분 예방할 수 있어요.

피부 표피·진피층에서 일어나는 가장 중요한 변화는 콜라겐 감소입니다. 노화가 되면 **콜라겐 양이 줄어들고 힘이 떨어지면서 피부 탄력 자체가 많이 떨어지게 돼요**. 게다가 표피·진피만이 아니라 그 아래 지방층, 근육, 뼈가 노화되면서 얼굴이 변해요. 피하지방이 위축되고 근육이 늘어지면서 지지력이 무너져 처지고, 뼈가 흡수되기 때문에 밖을 탱탱하게 만들어도 밑에서부터 꺼지는 것은 완벽히 해결하기 어렵습니다.$AAA$, array['피부노화', '내인성노화', '외인성노화', '콜라겐감소', '광선탄력증']::text[], 2023, 'Fa17vgXxGcw-1', 'https://youtu.be/pwEa8iIjNFM?t=52s', null, '2023-02-23 00:00:00+00'::timestamptz, '2023-02-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$노화를 예방하는 생활 습관은 무엇인가요?$AAQ$, $AAA$노화 예방의 가장 중요한 출발점은 자외선 차단입니다. 자외선 때문에 색소·홍조뿐 아니라 검버섯, 광선각화증 같은 각화, 주름과 탄력 저하가 생기는데 자외선 차단제, 모자, 선글라스로 **드라마틱하게 예방할 수 있을 정도**예요. 이 부분은 항상 기억해 두는 게 좋습니다.

내인성 노화는 활성 산소를 줄이는 방향으로 늦출 수 있어요. 활성 산소는 우리 몸이 음식을 소화·대사할 때 부산물로 나오는데 과도해지면 독소처럼 작용합니다. 그래서 **비타민·신선한 야채·과일·항산화 식품 섭취, 충분한 휴식과 숙면, 스트레스를 낮춰주는 명상**, 그리고 금연이 도움이 돼요. 담배는 활성 산소 유발 물질이 나오고 피우는 행위 자체가 입술 주름을 만들기 때문에, 리프팅을 받고 다시 담배를 피우면 노화가 다시 진행됩니다.$AAA$, array['자외선차단', '광노화예방', '활성산소', '항산화', '금연']::text[], 2023, 'Fa17vgXxGcw-2', 'https://youtu.be/pwEa8iIjNFM?t=257s', null, '2023-02-23 00:00:00+00'::timestamptz, '2023-02-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리프팅 시술은 어떤 종류가 있나요?$AAQ$, $AAA$리프팅 시술은 크게 세 가지 접근으로 나뉘며, 처진 조직을 올리는 방법, 콜라겐을 다시 만드는 방법, 꺼진 부분을 채우는 방법이 있습니다. 처진 피부를 직접 올리는 대표 시술은 실 리프팅으로, 실을 넣어 끌어올려 **드라마틱한 효과가 어느 정도 있어요**. 초음파를 이용한 울쎄라·슈링크·리니어펌도 처진 피부를 살짝 끌어올려 주는 역할을 합니다.

콜라겐 자체가 줄거나 힘이 없어진 경우에는 콜라겐을 빽빽하게 만들어주는 타이트닝 시술이 적합해요. **써마지·올리지오·튠페이스·쓰리딥·인모드** 같은 장비가 조직에 힘을 주는 시술입니다. 마지막으로 지방·뼈가 부족해 눈 밑·관자·턱이 꺼진 경우에는 필러·스컬트라·레디어스로 채워줍니다. 밖을 두껍게 해도 밑에서 골격이 무너지면 막을 수 없기 때문에 부족한 부분을 채워주는 접근이 함께 필요해요.$AAA$, array['실리프팅', '울쎄라', '써마지', '타이트닝', '볼륨필러']::text[], 2023, 'Fa17vgXxGcw-3', 'https://youtu.be/pwEa8iIjNFM?t=389s', null, '2023-02-23 00:00:00+00'::timestamptz, '2023-02-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리프팅은 왜 미리 받는 게 좋나요?$AAQ$, $AAA$리프팅은 노화가 많이 진행되기 전 미리 받는 게 결과가 좋습니다. 노화는 어느 순간 딱 일어나는 이벤트가 아니라 유전자에 프로그램되어 있어 **이야기를 나누고 잠자는 순간에도 계속해서 일어나기 때문**이에요. 연세가 많고 피부가 많이 처진 분들이 안면거상술을 받아도 일정 기간이 지나면 다시 처지는 이유가 여기에 있습니다.

'오늘의 내가 가장 젊은 나다'라는 말은 과학적인 표현이에요. 주름이 많아지고 피부가 많이 처졌을 때 한꺼번에 리프팅을 다 하겠다는 접근은 한계가 있습니다. **1살이라도 어릴 때, 재생력이 좋고 노화가 덜 진행됐을 때 꾸준히 관리하면 노화 진행을 천천히 늦출 수 있어요**. 50대가 10대 피부가 될 수는 없지만 적어도 몇 년 정도는 돌릴 수 있기 때문에 미리 시작해 꾸준히 관리하는 것이 답입니다.$AAA$, array['조기리프팅', '꾸준한관리', '안면거상술', '노화진행', '재생력']::text[], 2023, 'Fa17vgXxGcw-4', 'https://youtu.be/pwEa8iIjNFM?t=478s', null, '2023-02-23 00:00:00+00'::timestamptz, '2023-02-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$목 가로 주름과 세로 주름은 어떻게 다른가요?$AAQ$, $AAA$목 가로 주름은 노화의 상징이 아닌 밴드 같은 주름이고, 세로 주름은 노화에 의한 주름이라는 점에서 본질적으로 다릅니다. **가로 주름은 애기들도 있을 정도로** 노화와 직접 연관이 없고, 목에 살이 찌거나 하루 종일 숙여서 핸드폰을 보는 습관 때문에 더 도드라져 보일 수 있어요. 단순히 패여 있는 형태라 보시면 됩니다.

세로 주름은 목 전체를 가로지르는 넓은 목근(광경근)을 많이 사용하면서 생기는 노화성 주름입니다. 그래서 치료 방식도 달라요. 가로 주름은 패인 곳을 채워주면 되니 필러나 좀 더 자연스러운 효과의 쥬베룩 볼륨을 사용합니다. **세로 주름은 노화를 막아주는 보톡스와 고주파가 대표적**이에요. 보톡스는 근육을 마비시켜 주름을 덜 보이게 하고, 고주파는 콜라겐 재생으로 탄력을 살립니다.$AAA$, array['목가로주름', '목세로주름', '넓은목근', '필러', '쥬베룩볼륨']::text[], 2023, 'pg2r017cUxU-1', 'https://youtu.be/pg2r017cUxU?t=60s', null, '2023-02-28 00:00:00+00'::timestamptz, '2023-02-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$목 주름에 써마지 대신 어떤 고주파가 좋나요?$AAQ$, $AAA$목 피부는 얇기 때문에 써마지보다는 멀티 고주파인 3DEEP 같은 시술이 가성비 측면에서 더 권할 만합니다. 얼굴에 흔히 하는 써마지는 가격이 부담스럽고, 목은 피부가 워낙 얇은 부위라 **얕은 층에만 들어가는 고주파만으로도 충분히 효과**를 낼 수 있어요. 깊은 층까지 가는 강한 에너지가 필요하지 않습니다.

3DEEP처럼 멀티 고주파는 목 피부 두께에 맞춘 출력으로 콜라겐 재생을 유도해 세로 주름·잔주름을 완화합니다. **목에 색소 침착이 잘 생기기 때문에 레이저류는 권하지 않는 편**이에요. 실제로 얼굴 점과 목 점을 뺐을 때 목 쪽에 자국이 훨씬 더 잘 남는 경향이 있습니다. 그래서 목은 레이저보다는 가벼운 고주파 위주로 접근하고, 시술 후 자외선 관리를 함께 챙기는 게 좋습니다.$AAA$, array['3DEEP', '멀티고주파', '목고주파', '색소침착', '써마지가성비']::text[], 2023, 'pg2r017cUxU-2', 'https://youtu.be/pg2r017cUxU?t=148s', null, '2023-02-28 00:00:00+00'::timestamptz, '2023-02-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$손등 꺼짐과 잔주름은 어떻게 치료하나요?$AAQ$, $AAA$손등은 꺼진 볼륨과 잔주름을 나눠서 접근하며, 꺼짐에는 필러, 잔주름에는 가벼운 고주파가 적합합니다. 인대 사이가 푹 들어가 손등이 꺼지고 혈관이 튀어나와 보이는 경우, **목과 달리 손등은 필러로 채워주면 부자연스럽지 않고 효과도 좋습니다**. 꺼짐과 혈관 돌출이 동시에 좋아지는 효과가 있어요.

손등 잔주름은 고주파 레이저를 많이 활용하는데, 손은 기능이 중요한 부위라 보톡스를 놓으면 **움직임에 제약이 생길 수 있어 가벼운 고주파 정도로만 관리**해요. 또 손등 레이저는 색소 침착이 올 수 있어 권하지 않는 편입니다. 검버섯·잡티로 레이저를 했을 때 손등에 물이 닿거나 딱지가 빨리 떨어지면 색소 침착이 생겨 검버섯과 비슷하게 보이는 안 좋은 결과가 나올 수 있기 때문이에요.$AAA$, array['손등필러', '손등잔주름', '손등고주파', '손등색소침착', '검버섯주의']::text[], 2023, 'pg2r017cUxU-3', 'https://youtu.be/pg2r017cUxU?t=180s', null, '2023-02-28 00:00:00+00'::timestamptz, '2023-02-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$목·손 주름을 집에서 어떻게 예방하나요?$AAQ$, $AAA$목과 손 주름 예방의 핵심은 보습·자외선 차단·습관 개선 세 가지입니다. 얼굴에는 보습제를 열심히 바르지만 **목과 손은 덜 바르는 경향**이 있어요. 얼굴 바를 때 목에도 양보해 주고, 손은 씻고 수건으로 살짝 닦은 직후 바로 핸드크림을 바르는 습관이 도움이 됩니다. 손소독제는 균이 대부분 손바닥에 있으니 손등은 빼는 것도 방법이에요.

자외선은 노화의 가장 큰 원인이라 자외선 차단제를 꼭 발라야 하고, **검버섯이나 색소 침착처럼 까맣게 되는 변화 예방에도 큰 도움**이 됩니다. 운전할 때 모자·선글라스·장갑까지 챙기는 풀착장이 사실은 현명한 노화 예방법이에요. 또 고개를 너무 숙이는 습관이나 베개를 높게 베고 자는 자세는 목 가로 주름을 깊게 만드니, 지하철·버스에서 핸드폰을 오래 숙여 보는 시간을 줄이는 게 좋아요.$AAA$, array['목보습', '핸드크림', '자외선차단', '숙이는습관', '검버섯예방']::text[], 2023, 'pg2r017cUxU-4', 'https://youtu.be/pg2r017cUxU?t=242s', null, '2023-02-28 00:00:00+00'::timestamptz, '2023-02-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$보톡스의 어원은 무엇인가요?$AAQ$, $AAA$보톡스의 어원은 소시지를 뜻하는 라틴어 'Botulus'에서 유래했습니다. 18세기 말~19세기 초 독일 남부 빌드바트에서 소시지를 먹고 식중독으로 다수가 사망하는 사건이 있었는데, **위에서부터 아래로 마비가 진행되며 사망하는 하행성 마비**가 특징이었어요. 1829년 의사이자 시인이었던 케르너가 소시지 독에 운동신경·자율신경 마비를 일으키는 물질이 있다고 의심하고, 자극 억제 효과로 치료제로 사용될 수 있다고 논문에 덧붙였습니다.

이후 1895년 벨기에 미생물학자 에르멩겐이 시골 장례식 집단 식중독 조사 중 새로운 세균을 발견했고, 이 균이 케르너가 연구한 소시지 식중독의 원인균이었어요. 그래서 라틴어 'Botulus'에서 이름을 따와 **'Clostridium botulinum'으로 명명**됐습니다. 1978년 이 독을 이용한 약 '오큘리눔'이 개발됐고, 미국 제약사 엘러간이 9백만 달러에 소유권을 사들이면서 제품명을 보톡스로 바꿨습니다.$AAA$, array['보톡스어원', 'Botulus', 'Clostridiumbotulinum', '케르너', '엘러간']::text[], 2023, 'Fa17vgXxGcw-1-2', 'https://youtu.be/Fa17vgXxGcw?t=172s', null, '2023-03-02 00:00:00+00'::timestamptz, '2023-03-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$보톡스는 어떻게 미용 시술로 사용되게 됐나요?$AAQ$, $AAA$보톡스의 미용 효과는 안검경련 환자를 치료하던 중 우연히 발견됐습니다. 1960년대 말 미국 안과의사 앨런 스콧 박사가 사시 치료법을 찾다가 1971년 보툴리눔 톡신이 사시와 안검경련에 효과가 있다는 것을 확인했어요. 1985년에는 콜롬비아대 신경과 의사 브린이 목사경 치료에 사용하면서 안면 주름이 펴지는 **좋은 부작용을 관찰**했지만 관심을 끌지 못했습니다.

주름 개선 효과가 본격적으로 알려진 건 밴쿠버대 안과의사 잔 캐루더스를 통해서예요. 안검경축 환자의 눈 주위와 이마에 독소를 주사했더니 인상이 너무 좋아진 거죠. **마침 남편이 피부과 의사여서 이 사실을 공유했고**, 1982년 남편 알테어 캐루더스가 클리닉에서 일하는 여성에게 미용 목적으로 최초로 독소를 주사해 좋은 효과를 확인했어요. 1991년 이 발견을 세상에 알려 보톡스는 치료용은 물론 미용 목적으로도 인기를 끌게 됐습니다.$AAA$, array['앨런스콧', '사시치료', '캐루더스', '안검경련', '미용보톡스']::text[], 2023, 'Fa17vgXxGcw-2-2', 'https://youtu.be/Fa17vgXxGcw?t=320s', null, '2023-03-02 00:00:00+00'::timestamptz, '2023-03-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$보톡스는 어떻게 주름을 펴주나요?$AAQ$, $AAA$보톡스는 시냅스에서 분비되는 신경전달물질 아세틸콜린을 차단해 근육을 움직이지 못하게 만들어 주름을 펴줍니다. 우리 몸의 근육이 움직이려면 신경에서 **아세틸콜린이라는 명령어를 전달받아야 하는데**, 보톡스가 이 전달을 막아 근육이 마비되는 거예요. 표정 근육이 마비되면 그 근육이 만들던 주름이 펴지게 됩니다.

작용 부위에 따라 적용 질환이 달라요. 목 안쪽 근육에 작용하면 말을 잘 못 하거나 목소리가 변할 수 있고, **호흡 근육에 작용하면 사망까지 갈 수 있는 무서운 부작용**이 생길 수 있어요. 이런 부작용은 근육 치료 목적으로 다량 사용할 때 드물게 생기는 사례이고, 피부과에서 미용 목적으로 소량 사용할 때는 거의 없다고 봅니다. 보톡스는 그 외에도 사각턱 축소, 과민성 방광, 겨드랑이 다한증 등 다양한 질환에 사용됩니다.$AAA$, array['보톡스원리', '아세틸콜린', '신경전달물질', '근육마비', '다한증']::text[], 2023, 'Fa17vgXxGcw-3-2', 'https://youtu.be/Fa17vgXxGcw?t=496s', null, '2023-03-02 00:00:00+00'::timestamptz, '2023-03-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$튼살크림 발라도 예방 효과가 있나요?$AAQ$, $AAA$튼살크림은 과학적 근거가 약한 편이지만, 안 바르는 것보다는 발라주는 게 도움이 될 수 있습니다. 2012년 코크란 리뷰에서 센텔라 아시아티카(마데카솔 성분), 코코넛 버터, 올리브오일 같은 튼살크림 성분들을 분석했을 때 **예방 효과의 근거가 확실하지 않다**고 결론이 나왔어요.

그렇지만 크림을 바르면서 하는 물리적인 마사지가 튼살 예방에 도움이 된다는 연구들도 있고, 보습 성분이 피부에 도움이 된다는 논문들도 있어요. 그래서 **꾸준한 보습 자체가 안 바르는 것보다는 도움이 될 수 있다**고 보시면 됩니다. 임신 중에는 보습제를 바르는 겸 튼살크림을 꾸준히 발라주는 것도 괜찮은 선택입니다. 다만 개인차가 커서 발라도 생기는 경우가 있다는 점은 미리 알고 계셔야 해요.$AAA$, array['튼살크림', '튼살예방', '임신튼살', '코크란리뷰', '보습']::text[], 2023, 'TFHuzQ86n1I-1', 'https://youtu.be/TFHuzQ86n1I?t=182s', null, '2023-03-07 00:00:00+00'::timestamptz, '2023-03-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$이미 생긴 튼살에는 스티바A 연고가 효과 있나요?$AAQ$, $AAA$이미 생긴 튼살에 스티바A(트레티노인) 연고를 바르면 어느 정도 완화 효과를 볼 수 있습니다. 트레티노인 성분이 **섬유 모세포의 콜라겐 합성을 유도해 탄력을 증가**시키기 때문에, 튼살 부위의 주변 피부를 조여주는 효과가 있어요.

다만 튼살 자체를 아예 지워주는 약은 아닙니다. 약간 완화시키는 정도라서 완전히 없어지는 것을 기대하시면 어려울 수 있어요. 또 자극감이 있어서 바르고 3일 정도 지나면 붉어지거나 각질이 생기는 경우가 흔합니다. 중요한 주의사항으로 **임신 중에는 사용 금기 성분이라 출산 후에 사용하셔야** 합니다. 임신 중 튼살이 한창 생긴다고 급한 마음에 바르시면 안 되고, 출산 이후 자극감을 충분히 인지한 상태에서 조심스럽게 시작하시는 게 좋습니다.$AAA$, array['스티바A', '트레티노인', '튼살연고', '임신금기', '콜라겐합성']::text[], 2023, 'TFHuzQ86n1I-2', 'https://youtu.be/TFHuzQ86n1I?t=294s', null, '2023-03-07 00:00:00+00'::timestamptz, '2023-03-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$붉은 튼살과 흰 튼살, 치료 시기가 중요한가요?$AAQ$, $AAA$튼살은 생긴 지 얼마 안 된 붉은 튼살일 때 치료해야 효과가 훨씬 좋습니다. 튼살이 처음 생기면 흉터와 비슷한 구조를 보이는데, **붉은 튼살 단계에 적극적으로 치료하면 치료 효과가 좋습니다**.

실제로 스테로이드 장기 사용으로 생긴 붉은 튼살에 브이빔 레이저를 1주 간격으로 5회 치료했을 때 드라마틱한 호전을 보인 사례가 있어요. 반대로 청소년기 성장기 튼살은 사춘기에 생겨서 비밀로 하다가 성인이 되어 내원하면 이미 하얗게 변해 있는 경우가 많고, 이럴 때는 치료가 더 어렵습니다. 흰 튼살은 프랙셔널 레이저나 니들 고주파, 미라젯 같은 장비로 치료가 가능하긴 하지만 붉은 단계만큼 드라마틱하지는 않아요. **방치하지 말고 최대한 생긴 지 얼마 되지 않았을 때 치료**하는 게 정말 중요합니다.$AAA$, array['붉은튼살', '흰튼살', '브이빔', '프랙셔널레이저', '미라젯']::text[], 2023, 'TFHuzQ86n1I-3', 'https://youtu.be/TFHuzQ86n1I?t=410s', null, '2023-03-07 00:00:00+00'::timestamptz, '2023-03-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$튼살은 어떤 사람에게 잘 생기나요?$AAQ$, $AAA$튼살은 몸이 갑자기 커지는 변화를 살이 따라가지 못해 튿어지면서 생기며, 위험인자가 알려져 있습니다. 임산부는 **임신 중 체중 증가가 많고 태아 몸무게가 많이 나갈수록** 잘 생기고, 임신 전 비만 지수가 높은 경우에도 흔합니다.

흥미롭게도 엄마의 나이가 젊을수록 튼살이 더 잘 생기는 걸로 알려져 있어요. 젊을수록 피부가 탱탱하고 탄탄해서 늘어남을 못 견디고 잘 튿어지는 경향이 있기 때문이죠. 성장기에 생기는 튼살도 마찬가지로 비만 지수가 높을수록 잘 생기고, 아토피 피부염이나 지루 피부염 같은 피부 질환이 있는 경우에도 잘 생깁니다. 또 스테로이드 제제를 먹거나 바르면 **섬유 모세포가 활성화되어 단백질 분해가 늘어나서** 튼살이 생기는 경우도 많아 주의가 필요합니다.$AAA$, array['튼살위험인자', '임신튼살', '성장기튼살', '스테로이드부작용', '비만지수']::text[], 2023, 'TFHuzQ86n1I-4', 'https://youtu.be/TFHuzQ86n1I?t=110s', null, '2023-03-07 00:00:00+00'::timestamptz, '2023-03-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$보톡스는 몇 살부터 맞는 게 좋나요?$AAQ$, $AAA$보톡스는 일반적으로 20대 중반에서 후반부터 미리 맞는 것이 권장됩니다. 보톡스의 가장 중요한 기능은 현재 있는 주름을 펴는 것보다 **앞으로 생길 주름을 예방하는 기능**이기 때문이에요.

그때쯤부터 슬슬 주름이 자리잡기 시작하는데, 표정을 짓지 않아도 주름이 이미 생긴 경우에는 보톡스만으로 완전한 효과를 보기는 어렵습니다. 반면 미리 예방적으로 맞으신 경우에는 효과가 더 길게 가서 **6개월에서 1년에 한 번씩 맞아도 효과가 잘 지속되는 분들이 많습니다**. 반대로 생각하면 내가 보톡스를 맞았는데 마음에 들지 않더라도 3~6개월이 지나면 다시 원상복귀가 되니, 처음 시도하시는 분도 부담을 덜 수 있어요. 1년에 2~3번 정도면 충분하기 때문에 병원 자주 오실 필요가 없다는 점도 장점입니다.$AAA$, array['보톡스시기', '주름예방', '20대보톡스', '보톡스주기', '예방시술']::text[], 2023, 'T7vWTpZItJE-1', 'https://youtu.be/T7vWTpZItJE?t=39s', null, '2023-03-09 00:00:00+00'::timestamptz, '2023-03-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$보톡스 맞으면 안 되는 부위가 있나요?$AAQ$, $AAA$보톡스는 효과를 보지 못하거나 표정을 굳게 만드는 부위가 있어 주의해야 합니다. 대표적으로 **눈 아래쪽의 잔주름은 보톡스로 효과를 보기 어렵습니다**. 그 외에도 얼굴 근육들은 다 유기적으로 연결되어 있어서, 광대 주변이나 입꼬리를 올리는 미소 근육에 보톡스를 많이 맞으면 문제가 생길 수 있어요.

이런 중안면부 근육은 미소를 짓는 데 중요한 역할을 하기 때문에, 이쪽에 보톡스를 많이 맞으면 **얼굴이 굳은 표정으로 잘 웃지 못하는 마스크 페이스 현상**이 나타나게 됩니다. 보톡스는 효과가 확실한 시술이지만, 모든 부위에 다 잘 맞는 게 아니라 부위별로 적합성이 다릅니다. 그래서 처음 맞으실 때는 가장 효과 좋은 부위 한두 군데부터 시작하시는 것을 권해 드려요.$AAA$, array['보톡스부작용', '마스크페이스', '중안면부', '눈밑보톡스', '표정근육']::text[], 2023, 'T7vWTpZItJE-2', 'https://youtu.be/T7vWTpZItJE?t=72s', null, '2023-03-09 00:00:00+00'::timestamptz, '2023-03-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$보톡스 효과가 가장 좋은 부위는 어디인가요?$AAQ$, $AAA$보톡스는 이마, 미간, 눈가 세 부위에서 가장 추천되며, 그 중에서도 미간이 핵심입니다. 미간 근육은 **상당히 두껍고 강력해 얼굴 상안면부 전체를 관장**하는 근육이에요.

미간이 움직이면 이마 주름, 눈썹, 눈가, 콧잔등까지 함께 움직이기 때문에, 이 근육을 제대로 마비시키지 못하면 미간뿐 아니라 주변에도 주름이 다 지게 됩니다. 그래서 "미간에 주름이 없으니까 이마에만 맞고 싶어요"라고 하시는 분께도 **미간은 그래도 꼭 같이 맞으시는 걸 권해 드리는 편**입니다. 표정 습관이나 다른 이유로 미간에 패인 듯한 주름이 일단 생기면 보톡스 이외의 방법으로 교정하기가 쉽지 않기 때문에, 주름이 생기기 전에 미리 예방적으로 맞으시는 것을 가장 권해 드리는 부위입니다.$AAA$, array['미간보톡스', '이마보톡스', '눈가보톡스', '상안면부', '주름예방']::text[], 2023, 'T7vWTpZItJE-3', 'https://youtu.be/T7vWTpZItJE?t=102s', null, '2023-03-09 00:00:00+00'::timestamptz, '2023-03-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$보톡스로 인상이 부드러워지는 부위가 있나요?$AAQ$, $AAA$턱끝근과 입꼬리 내림근에 보톡스를 맞으면 표정이 부드러워지고 입꼬리가 살짝 올라가는 효과를 볼 수 있습니다. 평상시 무표정으로 있을 때 입에 힘을 많이 주는 분들이 있는데, 이 부위에 힘을 빼주면 **턱이 자갈처럼 우는 듯한 모양이 펴지고 인상이 밝아져요**.

턱끝근에 힘이 많이 들어가면 입이 앞으로 나오고 입술 주변 주름과 마리오네트 주름이 심해집니다. 이런 표정 습관은 의식적으로 고치기가 어려워서 보톡스가 좋은 해결책이 됩니다. 또 **입꼬리 내림근의 힘을 풀어주면 입꼬리가 살짝 올라가는 효과**가 있어서 부담 없이 예뻐질 수 있어요. 이 부위는 위험한 구조물이 별로 없어서 안전하게 맞을 수 있는 점도 장점입니다. 거울로 보이는 이마나 눈가만 신경 쓰시는 분이 많은데, 턱과 입꼬리도 함께 고려해 보시면 좋아요.$AAA$, array['턱끝근', '입꼬리보톡스', '자갈턱', '마리오네트주름', '표정개선']::text[], 2023, 'T7vWTpZItJE-4', 'https://youtu.be/T7vWTpZItJE?t=163s', null, '2023-03-09 00:00:00+00'::timestamptz, '2023-03-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$10대 20대에 클렌징은 어떻게 하는 게 좋나요?$AAQ$, $AAA$10대 20대 클렌징은 피부 타입에 맞춰 닦되 피부 장벽을 훼손하지 않을 정도로 부드럽게 하는 것이 핵심입니다. **피부가 건조한 분은 오일 클렌저로 색조 화장을 닦고 폼클렌징으로 마무리**하는 게 좋아요.

유분기가 원래 많은 분들은 오일보다 유분이 적은 클렌징 밀크 정도로 살짝 닦고 폼으로 마무리하시고, 선크림만 바른 경우는 클렌징 워터 정도로만 가볍게 닦아도 충분합니다. 중요한 건 **피부 장벽이 훼손될 만큼 과도하게 닦지 않는 것**이에요. 어릴 때부터 화장하는 게 걱정되시는 분도 있는데, 깨끗하게 지우지 못하면 모공에 잔여물이 남아 문제가 생기고 반대로 과도한 클렌징은 피부 장벽을 무너뜨립니다. 화장을 할 거라면 1살이라도 어릴 때 제대로 지우고 관리하는 습관을 들이는 게 진짜 중요합니다.$AAA$, array['클렌징습관', '오일클렌저', '폼클렌징', '피부장벽', '10대피부관리']::text[], 2023, 'KMApclcZpiA-1', 'https://youtu.be/KMApclcZpiA?t=39s', null, '2023-03-14 00:00:00+00'::timestamptz, '2023-03-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$10대 20대 때 화장품 많이 쓰면 안 좋나요?$AAQ$, $AAA$10대 20대에는 너무 많은 화장품을 사용하지 않는 게 중요한 습관입니다. **이 시기에는 피부 재생이 좋고 피부 자체가 너무 건강한 시기**이기 때문이에요.

여드름에 좋다, 색소에 좋다, 주름에 좋다 하며 이런저런 화장품을 잔뜩 바르시는 분들이 많지만, 쓸데없이 필요 없는 성분들을 너무 많이 바르다 보면 트러블만 생기고 오히려 도움이 안 되는 경우가 많아요. **나한테 맞는 것 한두 가지 정도만 사용하는 습관을 들이는 게 정말 중요합니다**. 보습도 피부 타입에 따라 달라서 건조한 분은 밀폐제가 많은 크림류를 하루 4~5번 덧발라 주시면 좋고, 유분기 있는 타입은 가벼운 로션이나 스킨 정도만 발라도 충분합니다. 무엇을 더하기보다 내 피부에 맞는 것을 골라 단순하게 쓰는 습관이 장기적으로 더 도움이 됩니다.$AAA$, array['보습제', '화장품줄이기', '피부타입', '기초화장품', '스킨케어루틴']::text[], 2023, 'KMApclcZpiA-2', 'https://youtu.be/KMApclcZpiA?t=110s', null, '2023-03-14 00:00:00+00'::timestamptz, '2023-03-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$당지수 높은 음식이 피부에 안 좋다는 게 사실인가요?$AAQ$, $AAA$당지수가 높은 음식은 여드름을 악화시키는 것으로 연구 결과가 이미 나와 있습니다. **단 음식들이 인슐린 분비를 촉진하고 남성 호르몬을 많이 나오게 해서 여드름에 안 좋은 영향**을 줘요.

구체적으로는 캔커피, 초콜릿 같은 단 음식과 케이크, 시리얼처럼 가공이 많이 된 음식들이 대표적이에요. 이런 음식을 먹으면 피지 분비가 늘어나 여드름에 안 좋다는 연구 결과는 이미 다 나와 있습니다. **이런 음식들을 조금 줄이는 습관을 갖는 게 좋고**, 야식을 먹는 것도 피해야 합니다. 야식은 살을 찌게 만들어 지방에서 인슐린과 비만 호르몬이 나와 피부에 안 좋은 영향을 주고, 밤에 먹으면 소화하느라 잠을 잘 못 자서 수면의 질도 떨어집니다. 어릴 때부터 야식을 줄이는 습관이 피부를 위해서도 중요해요.$AAA$, array['당지수', '여드름음식', '인슐린', '야식', '식습관']::text[], 2023, 'KMApclcZpiA-3', 'https://youtu.be/KMApclcZpiA?t=160s', null, '2023-03-14 00:00:00+00'::timestamptz, '2023-03-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$수면 부족이 정말 피부에 영향을 주나요?$AAQ$, $AAA$늦게 자는 습관은 호르몬 불균형을 일으켜 피부 건강을 해칩니다. **수면 밸런스와 피부 건강의 관계에 대한 연구는 이미 다 나와 있는 상태**예요.

자꾸 밤에 자버릇하면 호르몬에 불균형이 생기고, 본인은 늦게 자도 안 피곤하다고 느낄 수 있지만 그 피로감들이 결국 피부에 쌓여서 피부가 안 좋아지게 만듭니다. 함께 고려해야 할 습관이 손으로 얼굴을 만지는 버릇과 술·담배예요. 손에는 균이 많아 자꾸 만지고 여드름을 짜면 염증이 심해지고, 술을 마시면 클렌징을 안 하고 자게 되고 안주로 당지수가 올라가는 악순환이 생깁니다. 또 **담배를 피우는 동작 자체가 입술 주변에 주름을 만드는 표정을 하루 100번씩 반복하는 것**과 같아요. 10대 20대 피부 재생력이 좋은 지금이 습관 고치기에 제일 좋은 시기입니다.$AAA$, array['수면습관', '호르몬불균형', '얼굴만지기', '담배주름', '피부재생력']::text[], 2023, 'KMApclcZpiA-4', 'https://youtu.be/KMApclcZpiA?t=213s', null, '2023-03-14 00:00:00+00'::timestamptz, '2023-03-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$속눈썹은 왜 머리카락처럼 길게 자라지 않나요?$AAQ$, $AAA$속눈썹이 짧은 이유는 성장기 길이가 머리카락보다 훨씬 짧기 때문입니다. 모발은 자라는 성장기, 잠시 멈추는 휴지기, 빠지는 퇴행기 세 단계로 자라는데, **머리카락 성장기는 3년에서 6년이지만 속눈썹 성장기는 30~45일밖에 안 됩니다**.

그 한두 달 동안만 자라고 빠지기 때문에 자연스럽게 짧을 수밖에 없어요. 속눈썹은 또 다른 털과 달리 '털세움근'이라는 근육이 없습니다. 머리카락이나 몸의 털은 추울 때 닭살이 돋으며 털이 쭈뼛 서지만, 속눈썹은 외부 자극을 막아주는 커튼 역할을 해야 해서 설 일이 없기 때문이에요. 또 신기하게도 **속눈썹은 전체 털 중에서 탈모도 가장 늦게 일어나고 백모도 가장 늦게 진행**됩니다. 인종에 따라서도 차이가 있어서, 아시아인은 서양인보다 컬링이 덜하고 직모로 뻗어 있으며 길이도 짧고 두께도 얇습니다.$AAA$, array['속눈썹성장주기', '성장기', '털세움근', '백모', '인종차이']::text[], 2023, '2wUR_TsEpJ8-1', 'https://youtu.be/2wUR_TsEpJ8?t=199s', null, '2023-04-04 00:00:00+00'::timestamptz, '2023-04-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$Bimatoprost는 정말 속눈썹을 자라게 하나요?$AAQ$, $AAA$Bimatoprost는 실제로 속눈썹을 자라게 하는 것이 입증된 성분입니다. **원래 녹내장 안약으로 안압을 낮추는 데 쓰는 프로스타글란딘 성분**이었어요.

녹내장 환자들이 사용하다 보니 속눈썹이 풍성해지고 눈 주변이 까매지는 부작용이 많이 발견됐고, 연구 결과 모발을 자라게 하고 색소 침착을 유발하는 기능이 밝혀졌습니다. 그래서 보톡스로 유명한 앨러간사에서 **2008년에 FDA 승인을 받은 라티쎄(Latisse)라는 속눈썹 증모제로 출시**되었어요. 다만 우리나라에는 십수 년 전에 들어왔다가 시장성이 없어 철수해서 지금은 구할 수 없습니다. 미국에서도 화장품이 아닌 의사 처방 의약품으로 분류돼 있어요. 안압을 내리는 효과와 눈 시림, 충혈, 색소 침착 같은 부작용이 있을 수 있어서 의사 지도하에 사용해야 합니다.$AAA$, array['Bimatoprost', '라티쎄', '속눈썹증모제', '녹내장안약', '프로스타글란딘']::text[], 2023, '2wUR_TsEpJ8-2', 'https://youtu.be/2wUR_TsEpJ8?t=355s', null, '2023-04-04 00:00:00+00'::timestamptz, '2023-04-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$시중 속눈썹 영양제는 효과가 있나요?$AAQ$, $AAA$시중 속눈썹 영양제는 Bimatoprost 같은 약 성분만큼 강력하지는 않지만 어느 정도 도움은 될 수 있습니다. 보통 모발 영양제와 비슷한 성분들이 들어 있어요.

대표적인 성분이 비오틴(비타민 B7)인데 모발이나 손톱이 자라는 데 필요한 수용성 비타민이고, 그 외에 아미노산, 비타민 E, 니코틴산, 펩타이드, 판테놀 같은 성분이 들어갑니다. **비오틴은 그나마 연구가 몇 개 있지만 다른 성분들은 과학적인 근거가 아직 부족한 편**이에요. 다만 속눈썹은 위에서도 바르고 아래쪽 점막에서도 접근할 수 있으며 **눈꺼풀 자체가 얇아 다른 부위 털보다 흡수가 잘되는 편**이라 꾸준히 바르면 어느 정도 도움이 될 수 있습니다. 단, 영양 성분 외에 첨가물·보존제가 들어 있어 눈에 들어가면 눈 시림이나 각막염이 생길 수 있으니 바를 때 안에 들어가지 않도록 조심해야 합니다.$AAA$, array['속눈썹영양제', '비오틴', '판테놀', '흡수율', '안전성']::text[], 2023, '2wUR_TsEpJ8-3', 'https://youtu.be/2wUR_TsEpJ8?t=445s', null, '2023-04-04 00:00:00+00'::timestamptz, '2023-04-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$봄에 팔다리 각질은 왜 더 심해지나요?$AAQ$, $AAA$봄에 팔다리 각질이 심해지는 주된 원인은 피부 건조증입니다. 겨울에는 공기가 차갑고 건조해서 피부가 건조하고 가렵지만, **봄에는 날씨가 따뜻해지면서 옷차림이 가벼워져 팔다리가 노출되는 시간이 늘어나는 것**이 큰 차이예요.

공기는 여전히 건조한데 노출은 많아지니 건조증이 악화되면서 각질이 생기고 가려워지게 됩니다. 특히 정강이와 팔은 진피층이 얇아 원래부터 수분 함량이 적은데 자외선 노출까지 많아서 더 빨리 건조해지고 각질도 더 많이 생겨요. **각질은 피부가 필요해서 만드는 것이라 과도하게 제거하면 반드시 다시 만들게 되어 있습니다**. 그래서 각질을 무리해서 떼어내려 하기보다 보습으로 건조 자체를 해결하는 게 핵심이에요. 봄철 환절기에 이런 증상으로 진료실을 찾는 분들이 많은데, 원리를 알면 홈케어로도 충분히 관리할 수 있습니다.$AAA$, array['봄철각질', '피부건조증', '팔다리각질', '진피층', '환절기관리']::text[], 2023, 'D9n6OPoJCT4-1', 'https://youtu.be/D9n6OPoJCT4?t=70s', null, '2023-04-06 00:00:00+00'::timestamptz, '2023-04-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$보습제는 어떻게 발라야 효과가 좋나요?$AAQ$, $AAA$보습제는 샤워 직후 물기가 남아있을 때 바르는 것이 가장 효과적입니다. **물기를 다 닦지 말고 반만 닦은 축축한 상태에서 바로 발라야** 보습도 잘되고 발리기도 쉬워요.

많은 분들이 몸을 완전히 말리고 나서 보습제를 바르는데, 그건 좋은 방법이 아닙니다. 또 수분이 부족한 상태에서 바셀린이나 오일만 바르면 덮어주는 역할은 하지만 건조함은 잘 해결되지 않아요. **세라마이드, 콜레스테롤, 지방산처럼 세포 간 지질을 이루는 세 가지 성분이 함유된 보습제**를 먼저 바르고 그 위에 바셀린이나 오일을 덮거나 섞어 바르는 게 좋습니다. 그리고 "저는 보습제 잘 발라요" 하시는 분도 샤워 후 한 번만 바르는 경우가 많은데, 건조한 분은 하루 2~3번, 부족하면 5번, 10번까지 자주 덧발라 주세요. 씻지 않고 그냥 덧발라도 전혀 상관없습니다.$AAA$, array['보습제', '세라마이드', '샤워후보습', '덧바르기', '세포간지질']::text[], 2023, 'D9n6OPoJCT4-2', 'https://youtu.be/D9n6OPoJCT4?t=98s', null, '2023-04-06 00:00:00+00'::timestamptz, '2023-04-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$뜨거운 목욕과 때 미는 습관이 건조에 안 좋나요?$AAQ$, $AAA$뜨거운 물에 오래 있거나 때를 미는 습관은 건조증을 악화시킵니다. **5~10분 정도의 반신욕이나 샤워는 괜찮지만, 너무 길어지면 각질층 탈락이 가속화**되어 오히려 피부가 더 건조해져요.

손이 쪼글쪼글해질 정도로 오래 있는 건 안 좋습니다. 때 타월로 각질을 문지르거나 스크럽으로 자주 밀어내는 것도 자극이 되거나 **피부의 턴오버를 증가시켜 각질을 계속 만들어내는 악순환**을 만들어요. 비누 사용도 주의해야 하는데 대부분 알칼리 성분이라 매일 비누로 닦아내면 건조증에 좋지 않습니다. 건조하신 분은 비누나 바디클렌저를 이틀에 한 번, 3일에 한 번 쓰거나 냄새 나는 부위만 특별히 닦고 나머지는 물로만 씻어내는 것도 좋아요. 바디클렌저를 쓴다면 약산성 제품을 선택하고 향료가 강하지 않은 것을 고르세요. 카페인과 알코올은 이뇨 작용으로 몸의 수분을 빼내니 줄이는 게 도움이 됩니다.$AAA$, array['반신욕', '때밀기', '비누사용', '약산성', '피부턴오버']::text[], 2023, 'D9n6OPoJCT4-3', 'https://youtu.be/D9n6OPoJCT4?t=321s', null, '2023-04-06 00:00:00+00'::timestamptz, '2023-04-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$뿌리는 탈모약 핀쥬베는 먹는 약과 어떻게 다른가요?$AAQ$, $AAA$핀쥬베는 먹는 프로페시아와 효과는 비슷하면서 전신 부작용은 줄인 뿌리는 형태의 피나스테리드입니다. **연구 결과 정수리 부위 탈모 환자에 사용 시 경구 피나스테리드와 비슷한 효과를 보이면서 성기능 장애 같은 부작용은 매우 줄어든** 것으로 나왔어요.

먹는 프로페시아는 5알파 환원 효소를 억제해 DHT 생성을 막아 탈모를 막는 효과가 좋지만, 성욕 감퇴와 발기 부전 같은 성적 부작용이 가장 널리 알려진 부작용입니다. 약물 복용을 중단하면 사라지긴 하지만 예민한 부분이라 복용을 망설이는 분들이 많아요. **핀쥬베는 두피에 직접 분사해 전신 흡수를 줄이는 방식**이라 이런 전신 부작용을 낮춘 것이 가장 큰 차이점입니다. 우울증과의 인과관계는 아직 명확히 밝혀지지 않았는데, 탈모 자체가 심리적 영향을 줘서 생기는 것일 수도, 약 때문일 수도 있어 추가 연구가 필요한 영역입니다.$AAA$, array['핀쥬베', '프로페시아', '피나스테리드', '탈모약비교', '성기능장애']::text[], 2023, 'LiFAzG1FT6Q-1', 'https://youtu.be/LiFAzG1FT6Q?t=149s', null, '2023-04-11 00:00:00+00'::timestamptz, '2023-04-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$핀쥬베에도 부작용이 있나요?$AAQ$, $AAA$핀쥬베는 전신 부작용은 줄었지만 피부에 직접 닿는 약이라 국소 부작용은 발생할 수 있습니다. 손상된 피부에 뿌렸을 경우 **에탄올 제제에 의한 작열감**이 유발될 수 있어요.

또 붉은 기, 진물, 가려움증을 동반한 접촉성 피부염이 생길 수 있는데, 이는 주로 프로필렌 글라이콜 성분 때문입니다. 프로필렌 글라이콜은 무색·무취의 액체로 화장품, 연고, 샴푸에 흔히 포함되는 성분이고 **보습 효과와 미생물 증식 억제(방부제 역할)를 위해** 들어가요. 하지만 일부 사람들에게는 접촉성 피부염을 유발할 수 있습니다. 만약 스프레이 사용 후 이런 불편한 증상이 생기면 사용을 중단하고 진료를 받아보시는 게 좋습니다. 또 임신 가능성이 있는 여성이나 임산부에게 닿으면 남자 태아의 성기 발달에 영향을 줄 수 있어 접촉 자체를 피해야 합니다.$AAA$, array['핀쥬베부작용', '접촉성피부염', '프로필렌글라이콜', '작열감', '임신금기']::text[], 2023, 'LiFAzG1FT6Q-2', 'https://youtu.be/LiFAzG1FT6Q?t=171s', null, '2023-04-11 00:00:00+00'::timestamptz, '2023-04-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$핀쥬베 뿌린 뒤 가족이 닿아도 괜찮나요?$AAQ$, $AAA$핀쥬베는 분사 후 빠르게 흡수되지만 가족 안전을 위해 30분에서 1~2시간 정도는 접촉을 피하는 게 좋습니다. 사람 피부와 유사한 돼지 등에 분사해 묻어나는 양을 실험한 결과 **5분 뒤에 약 성분의 90% 이상이 흡수**되어 있었어요.

스테인리스 스틸에 분사해 측정한 결과에서도 5분 뒤 잔여량은 처음 뿌린 양의 10분의 1 수준이었고 30분 뒤에는 전혀 검출되지 않았습니다. 그래서 피나스테리드 분사 후 5분 뒤 여성이 접촉한 경우에 옮겨질 가능성은 미미합니다. 다만 **더 확실하고 안전하게 하기 위해서는 최소 30분, 넉넉하게는 1~2시간 정도 조심하는 것**이 좋아요. 스프레이 특성상 주변에 분사될 수 있고 두피에 충분히 흡수되지 않은 상태로 옆에 있던 분이 만질 가능성이 있기 때문입니다. 가임기 여성과 임산부는 접촉을 자제해 주세요.$AAA$, array['핀쥬베주의사항', '흡수시간', '가족접촉', '임산부주의', '분사후관리']::text[], 2023, 'LiFAzG1FT6Q-3', 'https://youtu.be/LiFAzG1FT6Q?t=286s', null, '2023-04-11 00:00:00+00'::timestamptz, '2023-04-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$핀쥬베는 하루에 몇 번 어떻게 사용하나요?$AAQ$, $AAA$핀쥬베는 하루에 한 번, 탈모 부위에 따라 1회에서 4회 분사하는 것이 권장 사용법입니다. **한 통의 총 용량이 18ml이며 최대 180번 정도 사용 가능**합니다.

예를 들어 M자형 탈모처럼 이마 양쪽에 사용하는 분은 하루에 2회씩 펌프해서 사용하면 총 90일, 즉 3개월 정도 사용이 가능해요. 탈모 범위에 따라 사용 기간은 달라지지만 **짧게는 한 달 반에서 길게는 최대 6개월까지** 한 통으로 사용할 수 있습니다. 처음 사용할 때는 옆에 있는 깔때기를 스프레이 입구에 부착해야 하는데, 부착 과정에서 약이 나올 수 있으니 몸이 아닌 바깥쪽을 향하게 한 뒤 딸깍 소리가 날 때까지 끼우세요. 그리고 중요한 점은 치료를 중단하면 발모됐던 모발이 다시 탈락할 수 있어서 지속적으로 치료하시는 게 좋습니다.$AAA$, array['핀쥬베사용법', '분사횟수', 'M자형탈모', '용량', '지속치료']::text[], 2023, 'LiFAzG1FT6Q-4', 'https://youtu.be/LiFAzG1FT6Q?t=357s', null, '2023-04-11 00:00:00+00'::timestamptz, '2023-04-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$웨이트할 때 턱을 깨물면 정말 사각턱이 되나요?$AAQ$, $AAA$웨이트 트레이닝 중 이를 꽉 깨무는 습관은 턱 근육을 발달시켜 사각턱을 유발할 수 있습니다. **중량을 쥐어짤 때 매일 30번씩 50번씩, 1세트 2세트 10세트를 반복하면 턱 근육도 발달**해요.

우리 몸의 다른 근육이 운동으로 발달하는 것처럼 얼굴 근육도 같은 원리로 커집니다. 이를 꽉 깨물고 중량을 치다 보면 턱 근육이 발달해 얼굴이 사각턱이 되고 얼굴 자체가 커지게 돼요. 게다가 **이를 꽉 깨무는 습관 때문에 치아도 많이 손상**됩니다. 운동을 10년 정도 하고 나서 치과에 가보면 치아가 깨져 있는 경우가 흔해요. 사실 본인은 자기도 모르게 이를 꽉 깨물게 되니까 운동을 열심히 하시는 분들은 치과 검진도 한번 받아보시는 것을 권해 드립니다. 보톡스를 턱 근육에 맞으면 힘이 안 들어가니까 운동 중 발달을 막는 데 도움이 됩니다.$AAA$, array['사각턱', '교근발달', '이악물기', '치아손상', '턱보톡스']::text[], 2023, 'NLkLjFioQPs-1', 'https://youtu.be/NLkLjFioQPs?t=159s', null, '2023-04-13 00:00:00+00'::timestamptz, '2023-04-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$운동하면서 미간 주름이 생기는 이유는 뭔가요?$AAQ$, $AAA$운동 중에 인상을 쓰며 미간에 힘을 주는 습관이 미간 근육을 키우고 주름을 만듭니다. 단련하고 싶은 건 가슴 근육인데 **자꾸 미간 근육이 단련되는 셈**이에요.

미간 근육은 만져보면 알 수 있듯 엄청 두껍고 단단한 근육인데, 매일매일 운동을 하다 보면 이 근육이 자꾸 커집니다. 그러면 미간 때문에 얼굴이 늙어 보이게 돼요. 더 큰 문제는 **근육 사용이 습관이 되어 운동을 안 할 때, 모니터를 볼 때도 저절로 힘이 들어가게 된다**는 점입니다. 또 운동 중 눈을 꽉 감는 습관도 흔한데, 힘을 줄 때 윽! 하면서 눈을 감으면 눈가에 주름이 생겨요. 보통은 웃을 때 눈가 주름이 생기는데 이런 습관을 많이 하면 눈 아래쪽으로도 주름이 생길 수 있습니다. 사람마다 운동할 때 짓는 표정이 다르니 거울이나 영상으로 자기 표정을 점검해 보세요.$AAA$, array['미간주름', '추미근', '눈가주름', '운동표정', '근육습관']::text[], 2023, 'NLkLjFioQPs-2', 'https://youtu.be/NLkLjFioQPs?t=243s', null, '2023-04-13 00:00:00+00'::timestamptz, '2023-04-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$운동할 때 입 주변 근육은 어떻게 영향을 받나요?$AAQ$, $AAA$운동 중 입 주변 근육 사용 패턴에 따라 다양한 주름과 변형이 생길 수 있습니다. **턱을 꽉 깨물거나 입을 옆으로 찢거나 꽉 다무는 등 사람마다 자기만의 버릇**이 있어요.

입 주변에는 입꼬리를 옆으로 찢는 근육, 밑으로 내리는 근육, 위로 올리는 턱끝근 등 다양한 근육이 있습니다. 입술을 열심히 꽉 다물다 보면 입술 주변에 쪼글쪼글한 주름이 생기고, 옆으로 보면 팔자 주름이 길어진 것처럼 옆으로 가는 주름이 생기기도 해요. 어떤 분은 입꼬리가 아래로 내려가서 리프팅돼야 할 얼굴이 처지는 방향으로 근육이 발달하기도 합니다. 또 **자갈턱처럼 턱끝근이 발달하거나 목 근육이 발달하면서 얼굴 전체와 목까지 변할 수 있어요**. 거울이나 영상으로 자기가 주로 쓰는 근육을 확인하고 그 부위에 맞춰 보톡스를 맞으면 운동의 효과는 살리면서 얼굴 변형은 막을 수 있습니다.$AAA$, array['입주변주름', '마리오네트주름', '자갈턱', '목근육', '입꼬리처짐']::text[], 2023, 'NLkLjFioQPs-3', 'https://youtu.be/NLkLjFioQPs?t=315s', null, '2023-04-13 00:00:00+00'::timestamptz, '2023-04-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스티바A 크림은 어떤 성분이며 피부에 어떤 효과가 있나요?$AAQ$, $AAA$스티바A는 비타민A 유도체인 **트레티노인 성분의 전문의약품**입니다. 레티노익 산이라고도 불리며, 레티노이드 계열 중에서도 가장 효과가 크고 그만큼 부작용도 커서 전문의 처방을 받아야 구매할 수 있습니다. 함유량에 따라 0.01%, 0.025%, 0.05% 세 가지가 있어요.

레티노익 산은 표피세포 분화와 재생을 촉진해 죽은 각질을 제거하고 턴오버를 조절하여 피부결을 매끈하게 만들어줍니다. 또한 모공의 과각화와 염증을 완화하고 피지분비 조절을 도와 여드름에 효과적이며, **진피 내 콜라겐 합성을 촉진해 탄력과 주름 개선에도** 도움이 됩니다. 멜라닌색소 생산에 관여하는 효소를 억제해 기미·색소침착 개선까지 가능해 만능 크림으로 불려요.$AAA$, array['스티바A', '트레티노인', '레티노이드', '주름개선', '여드름', '미백']::text[], 2023, '1X8KTo4VlKs-1', 'https://youtu.be/1X8KTo4VlKs?t=142s', '{"pmid": "41302994", "doi": "10.3390/jcm14227958", "title": "An Updated Review of Topical Tretinoin in Dermatology: From Acne and Photoaging to Skin Cancer.", "journal": "J Clin Med", "year": "2025", "authors_short": "Balado-Simó P, Morgado-Carrasco D, Gómez-Armayones S et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/41302994/", "doi_url": "https://doi.org/10.3390/jcm14227958"}'::jsonb, '2023-04-18 00:00:00+00'::timestamptz, '2023-04-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스티바A 부작용을 줄이며 안전하게 사용하는 방법은?$AAQ$, $AAA$스티바A는 **아주 소량씩 천천히** 사용하는 것이 핵심입니다. 처음 사용할 때는 기초 마지막 단계에서 쌀알 만큼 짜고, 본인이 쓰던 보습제를 3배에서 5배 정도 더 짜서 섞은 뒤 얼굴 옆면이나 귀 뒤처럼 잘 안 보이는 부위에 며칠간 테스트해 보세요. 한 일주일 큰 문제가 없으면 그때 얼굴 전체에 발라봅니다.

자극이 있다면 일단 중지하고 보습을 열심히 해 피부가 회복된 뒤, **매일이 아니고 2~3일에 한 번 처음 용량의 반 정도로** 다시 시도합니다. 자외선 감수성이 높아지므로 밤에만 사용하고 아침에는 깨끗이 씻은 뒤 자외선 차단제를 꼭 발라야 해요. 섞을 보습제는 기능성보다 자극이 덜한 순한 제품이 좋고, 피부가 붉거나 예민한 날·상처가 있는 날·햇빛에 많이 노출된 날은 사용을 피하세요.$AAA$, array['스티바A', '부작용', '보습제희석', '사용법', '자외선차단']::text[], 2023, '1X8KTo4VlKs-2', 'https://youtu.be/1X8KTo4VlKs?t=417s', '{"pmid": "39184919", "doi": "10.1155/2024/5551774", "title": "A Comprehensive Review of the Strategies to Reduce Retinoid-Induced Skin Irritation in Topical Formulation.", "journal": "Dermatol Res Pract", "year": "2024", "authors_short": "Narsa AC, Suhandi C, Afidika J et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/39184919/", "doi_url": "https://doi.org/10.1155/2024/5551774"}'::jsonb, '2023-04-18 00:00:00+00'::timestamptz, '2023-04-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스티바A 사용하면 안 되는 경우가 있나요?$AAQ$, $AAA$임산부와 수유부에서는 스티바A 사용이 권고되지 않습니다. 먹는 비타민A 유도체 이소트레티노인이 태아 기형을 유발하기 때문에 임산부에서는 금기인데, 바르는 국소제는 직접적 태아 기형 유발 보고는 없지만 **혹시 모를 가능성 때문에 임산부·수유부에서는 권고하지 않습니다**.

또한 국소 자극감 때문에 주의가 필요한 사람들이 있어요. 건강한 피부에서도 붉어짐, 화끈거림, 건조함, 피부당김, 벗겨짐, 가려움증이 나타날 수 있는데, 아토피 피부염, 지루성 피부염, 주사피부염이 있거나 화장품만 잘못 써도 뒤집어지는 민감한 피부라면 **이런 증상이 훨씬 심하게 나타날 수 있으므로 신중히** 접근해야 합니다. 상처가 생겼거나 화상을 입은 부위에는 사용해서는 안 됩니다.$AAA$, array['스티바A금기', '임산부', '아토피피부', '민감성피부', '레티노이드피부염']::text[], 2023, '1X8KTo4VlKs-3', 'https://youtu.be/1X8KTo4VlKs?t=335s', '{"pmid": "36791447", "doi": null, "title": "Common Skin Conditions During Pregnancy.", "journal": "Am Fam Physician", "year": "2023", "authors_short": "Erlandson M, Wertz MC, Rosenfeld E", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/36791447/", "doi_url": null}'::jsonb, '2023-04-18 00:00:00+00'::timestamptz, '2023-04-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스티바A 농도가 높으면 무조건 효과가 더 좋은가요?$AAQ$, $AAA$농도가 높다고 무조건 효과가 더 좋은 것은 아닙니다. 트레티노인은 많이 바른다고 해서 더 빠르거나 좋은 결과가 나타나지 않으며, 오히려 **과량 사용으로 자극이 생겨 색소침착이 더 심해질 수도 있어요**. 자외선 노출과 만나면 원래 없애려던 색소가 도리어 진해질 수 있습니다.

얼굴에 사용하는 경우 보통 **0.025%가 가장 많이 사용되며, 민감하거나 처음 쓰는 분은 0.01%로 시작**해 적응되면 0.025%로 올립니다. 붉은 튼살이나 얼굴이 아닌 몸·팔다리에 사용할 때는 0.05%가 적합해요. 효과는 천천히 장기간에 걸쳐 나타나기 때문에 부작용 없이 효과를 잘 모르겠다는 분은 6개월 이상 꾸준히 사용해야 변화를 느낄 수 있습니다.$AAA$, array['스티바A농도', '트레티노인0.025%', '농도선택', '장기사용', '튼살']::text[], 2023, '1X8KTo4VlKs-4', 'https://youtu.be/1X8KTo4VlKs?t=590s', '{"pmid": "39348007", "doi": "10.1007/s40257-024-00893-w", "title": "Comparing Tretinoin to Other Topical Therapies in the Treatment of Skin Photoaging: A Systematic Review.", "journal": "Am J Clin Dermatol", "year": "2024", "authors_short": "Siddiqui Z, Zufall A, Nash M et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/39348007/", "doi_url": "https://doi.org/10.1007/s40257-024-00893-w"}'::jsonb, '2023-04-18 00:00:00+00'::timestamptz, '2023-04-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$자외선 차단제는 SPF와 PA 어떻게 보고 고르나요?$AAQ$, $AAA$**SPF는 자외선 B, PA는 자외선 A 차단 효과**를 나타내는 지표입니다. SPF는 숫자가 높을수록, PA는 +가 많을수록 자외선으로부터 더 효과적으로 피부를 보호합니다. 국내에서는 SPF 50까지 표시되고 그 이상 차단되는 경우 50 뒤에 +를 붙이는데, SPF 50이 넘어가면 차단율 상승폭이 무시해도 될 정도로 적기 때문이에요.

상황별로는 실내 활동과 가벼운 외출은 SPF 15~20에 PA+~PA++ 정도면 충분하고, 등산이나 스포츠 활동 등 **장시간 야외에서는 SPF 30 이상, PA+++ 이상의 제품**이 좋습니다. 여름 야외 물놀이를 갈 때는 SPF 50에 PA+++ 이상이면서 물에 잘 지워지지 않는 워터프루프 제품을 선택해야 해요. 인공 향·색소가 들어간 제품은 피하고 유효기간이 1년 이상 남았는지 구매 시 확인하세요.$AAA$, array['자외선차단제', 'SPF', 'PA', '지수선택', '워터프루프']::text[], 2023, 'FgBTkKHEcZg-1', 'https://youtu.be/FgBTkKHEcZg?t=156s', null, '2023-04-20 00:00:00+00'::timestamptz, '2023-04-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$유기자차와 무기자차는 어떻게 다른가요?$AAQ$, $AAA$유기자차는 화학적 자외선 차단제이고 무기자차는 물리적 차단제로, **자외선 차단 원리 자체가 다른 두 제품**입니다. 유기자차는 벤조페논·옥시벤존·아보벤존 등 화학 물질로 이루어져 자외선을 피부에 흡수시켜 열로 방출하는 방식이고, 무기자차는 징크옥사이드와 티타늄다이옥사이드 등 무기 화학 물질이 피부 표면에 막을 형성해 자외선을 반사·산란시켜 차단합니다.

유기자차는 백탁이 적고 발림성이 좋아 메이크업 시 사용하기 좋지만 **피부 자극을 유발해 예민한 피부는 주의해서 사용**해야 합니다. 반면 무기자차는 자극이 적어 민감하거나 기미가 있는 분, 아이들에게 추천되고 물에 잘 씻기지 않아 수영·운동 등 야외 활동에도 적합해요. 다만 많이 바르면 백탁이 생기고 꾸덕해 발림성이 떨어지는 단점이 있어 두 성분 장단점을 보완한 혼합 제품도 많이 나옵니다.$AAA$, array['유기자차', '무기자차', '화학적차단제', '물리적차단제', '백탁현상']::text[], 2023, 'FgBTkKHEcZg-2', 'https://youtu.be/FgBTkKHEcZg?t=207s', null, '2023-04-20 00:00:00+00'::timestamptz, '2023-04-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$자외선 차단제는 얼마만큼 발라야 하나요?$AAQ$, $AAA$**세계보건기구(WHO)가 권고한 1회 적정량은 남성 얼굴 기준 900mg, 여성 얼굴 기준 800mg**입니다. 500원짜리 동전만큼 발라야 한다는 양인데, 실제로 이렇게 사용하는 분은 거의 없을 정도로 많은 양이에요. 아무리 잘 골랐어도 제대로 바르지 않으면 표기된 효과를 볼 수 없습니다.

현실적으로는 2~3번에 나눠 바르고 흡수시킨 뒤 다시 덧바르는 방식을 권합니다. 아침에 바빠 덧바를 시간이 없다면 **자외선 차단 지수가 좀 더 높은 제품을 선택**하시는 게 좋아요. 그리고 얼굴 중심부부터 바르다 보면 옆면이나 헤어라인 같은 부위는 잘 안 발리는 경우가 많으니 그 부분도 신경 써서 발라주시고, 목·귓바퀴·입술을 포함한 신체 노출 부위 전체에 꼼꼼하게 발라야 합니다.$AAA$, array['자외선차단제용량', '1회적정량', 'WHO권고량', '덧바르기', '헤어라인']::text[], 2023, 'FgBTkKHEcZg-3', 'https://youtu.be/FgBTkKHEcZg?t=418s', null, '2023-04-20 00:00:00+00'::timestamptz, '2023-04-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$수영장에서 화학적 선크림이 발암 물질로 변한다는 게 사실인가요?$AAQ$, $AAA$야외 수영장에서는 화학적 선크림 대신 무기자차를 바르는 것이 안전합니다. 화학적 선크림에 들어 있는 **아보벤존 성분이 수영장 소독제로 사용하는 염소와 자외선과 함께 만나면** 페놀과 같은 인체에 유해한 물질이 생길 수 있다는 보고가 있었어요.

그렇다고 자외선 차단제를 안 바를 수는 없겠죠. 자외선을 그대로 맞는 것이 훨씬 위험하기 때문입니다. 이런 환경에서는 유기자차 대신 **무기자차를 발라 염소와의 반응 자체를 피하는** 것이 합리적인 대안입니다. 무기자차는 피부 표면에 막을 만들어 자외선을 반사·산란시키는 방식이라 물에도 잘 씻기지 않아 수영장 환경에서 적합하고, 자극도 적어 어린이나 민감 피부에도 권장됩니다.$AAA$, array['수영장선크림', '아보벤존', '염소반응', '무기자차대안', '워터프루프']::text[], 2023, 'FgBTkKHEcZg-4', 'https://youtu.be/FgBTkKHEcZg?t=313s', null, '2023-04-20 00:00:00+00'::timestamptz, '2023-04-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$흐린 날이나 비 오는 날에도 선크림을 발라야 하나요?$AAQ$, $AAA$흐린 날과 비 오는 날에도 **자외선 차단제는 반드시 발라야** 합니다. 구름이 흡수할 수 있는 것은 적외선뿐이고, 자외선은 구름을 통과해 그대로 우리에게 전달됩니다. 특히 자외선 A는 파장이 길고 투과성이 높아 비가 오는 날에도 우리 피부까지 도달해요.

오히려 **구름이 태양을 반쯤 가리고 있을 때 자외선이 구름에 반사되어 그 지수가 더 강해지는 경우**도 있다고 합니다. 겨울도 마찬가지로 눈에 반사되는 자외선이 더 강한 자외선을 유발하므로 차단제는 날씨와 계절에 상관없이 1년 내내 바른다고 생각하는 게 좋습니다. 또 형광등만 있는 실내는 자외선 방출이 미미해 꼭 바르지 않아도 되지만, 대부분 집에는 창문이 있고 자외선 A가 창문을 통과해 바닥·천장에 반사되어 피부에 닿을 수 있으므로 발라야 해요.$AAA$, array['흐린날선크림', '자외선A투과', '실내자외선', '사계절자외선차단', '창문자외선']::text[], 2023, 'YoZ8wz9hN0s-1', 'https://youtu.be/YoZ8wz9hN0s?t=47s', null, '2023-04-25 00:00:00+00'::timestamptz, '2023-04-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$아이들에게 자외선 차단제를 발라줘도 되나요?$AAQ$, $AAA$아이들에게도 자외선 차단제를 발라줘야 합니다. **아이는 각질 층이 얇고 피부가 연약해서 자외선에 자극을 받기 쉽기** 때문이에요. 다만 제품과 방법 선택에 신경을 써야 합니다.

생후 6개월 미만 아이는 얇고 소매 긴 옷, 챙 넓은 모자나 양산, 유모차 덮개 등으로 햇빛을 차단하고, **유기자차보다 알레르기를 덜 유발하고 흡수가 적은 무기자차**를 사용하는 것이 좋습니다. 또 아이들은 제대로 클렌징하기 어렵기 때문에 물에 비교적 쉽게 지워지는 워셔블 타입의 순한 로션이나 크림 제형 제품을 발라주고, 씻을 때는 유아용 저자극 클렌저로 깨끗이 씻어내야 해요. 어른도 마찬가지로 클렌징 오일이나 밀크로 1차, 클렌징 폼으로 2차 세안하는 이중 세안을 해야 잔여물에 의한 모공 막힘과 여드름 악화를 막을 수 있습니다.$AAA$, array['아이선크림', '유아무기자차', '워셔블타입', '유아클렌저', '이중세안']::text[], 2023, 'YoZ8wz9hN0s-2', 'https://youtu.be/YoZ8wz9hN0s?t=129s', null, '2023-04-25 00:00:00+00'::timestamptz, '2023-04-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$자외선 차단제는 외출 직전에 발라도 되나요?$AAQ$, $AAA$무기자차는 외출 직전에 발라도 되지만 유기자차는 미리 발라야 합니다. **무기자차는 피부에 보호막을 형성해 자외선 차단 효과를 내기 때문에 바로 외출해도** 되지만, 화학적 자외선 차단제인 유기자차는 최소한 밖으로 나가기 20분~30분 전에 발라 충분히 흡수시켜야 최대 효과를 볼 수 있어요.

또한 자외선 차단 성분이 함유된 색조 제품을 사용해도 별도의 선크림은 꼭 필요합니다. 선크림에 표시된 차단 효과를 내려면 많은 양을 발라야 하는데, **색조 제품을 선크림처럼 두껍게 바를 수는 없기 때문에** 색조에 자외선 차단 성분이 있더라도 확실한 효과를 보려면 선크림을 같이 사용해야 합니다. 아침에 한 번만 바르는 것도 부족해 피지·땀·환경 요인으로 닦여 나가고, 유기자차는 빛을 흡수한 뒤 물질 구조가 깨져 더 이상 자외선을 흡수할 수 없는 상태가 되므로 보통 2~3시간마다 덧바를 것을 권합니다.$AAA$, array['선크림발리는타이밍', '유기자차20분', '색조선크림병용', '덧바르기', '자외선차단지속']::text[], 2023, 'YoZ8wz9hN0s-3', 'https://youtu.be/YoZ8wz9hN0s?t=195s', null, '2023-04-25 00:00:00+00'::timestamptz, '2023-04-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$자외선 차단 지수가 높을수록 무조건 좋은 건가요?$AAQ$, $AAA$자외선 차단 지수가 무조건 높다고 좋은 것은 아닙니다. **차단 지수가 높아지면 그만큼 다양한 성분이 들어 있어 자극 피부염·알레르기성 접촉 피부염** 등이 유발될 수 있어요. 특히 민감성 피부이거나 피부가 약한 아이들은 너무 높은 지수의 선크림보다 SPF가 낮은 제품을 자주 덧발라 주는 편이 더 좋습니다.

현실에서 2~3시간마다 덧바르기 어려운 경우에는 **SPF 30, PA+++ 선크림을 아침 출근 전·점심시간·퇴근 전 세 번 정도** 사용하는 방식을 권합니다. 화장이 들뜨는 게 부담되면 스틱형이나 팩트형 선크림을 활용하시고, 호주 빅토리아 암 위원회의 선스마트 캠페인처럼 햇빛을 가릴 수 있는 옷을 입고 차단제를 바르고 모자를 쓰는 등 여러 방법을 함께 사용해 피부를 보호하는 것이 중요합니다.$AAA$, array['고SPF부작용', '민감성피부선크림', '선크림덧바르기', '스틱선크림', '선스마트']::text[], 2023, 'YoZ8wz9hN0s-4', 'https://youtu.be/YoZ8wz9hN0s?t=330s', null, '2023-04-25 00:00:00+00'::timestamptz, '2023-04-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기미가 있는데 집에서 절대 하지 말아야 할 것은 무엇인가요?$AAQ$, $AAA$기미가 있다면 **마사지·스크럽·민간요법은 절대 피하셔야** 합니다. 기미는 작은 마찰이나 자극에 의해서 악화될 수 있는 질환이라 입자 큰 알갱이가 든 스크럽 제제를 팍팍 문지르거나, 마사지샵에서 과한 경락 마사지를 받거나, 가정용 마사지 기기를 과하게 사용하면 오히려 자극이 됩니다.

민간요법은 더 위험합니다. 들깨가루·생 율무가루에 사과 식초를 섞은 팩이나 밀가루에 빙초산을 개어 붙이는 식의 방법으로 화상을 입고 흉터까지 남은 사례들이 있어요. **식초는 pH가 3 정도 되는 아세트산이라 화학적 화상을 일으킬 수** 있고, 팩 형태로 밀봉하면 흡수율이 확 높아져 자극이 극대화됩니다. 살리실산과 젖산으로 이루어진 산성의 티눈 치료제도 기미에 바르면 피부염·궤양이 생길 수 있어 절대 사용하지 마세요. 자극이나 피부염은 기미를 급격히 악화시킵니다.$AAA$, array['기미악화', '민간요법금지', '식초팩', '티눈치료제', '기미자극']::text[], 2023, 'S-w93eewma0-1', 'https://youtu.be/S-w93eewma0?t=162s', null, '2023-04-27 00:00:00+00'::timestamptz, '2023-04-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기미에 바르는 연고는 어떤 종류가 있나요?$AAQ$, $AAA$기미에 사용하는 대표 연고는 **하이드로퀴논, 트레티노인, 그리고 두 성분에 스테로이드를 더한 트리플 콤비네이션**입니다. 하이드로퀴논은 멜라닌색소 합성 과정의 핵심 효소인 tyrosinase를 억제해 색소 합성을 막아주는 성분으로, 도미나 크림은 하이드로퀴논 4%가 들어 있고 처방전 없이 약국에서 구매 가능합니다.

스티바A 연고의 트레티노인은 각질세포 턴오버를 촉진해 피부톤을 밝고 매끄럽게 하면서 멜라닌색소 생산 효소 활성을 억제해 기미·색소침착 개선에 효과적입니다. **하이드로퀴논과 트레티노인은 색소 제거에 효과적이지만 피부 자극이 있을 수 있어**, 자극과 염증을 완화하기 위해 스테로이드를 추가한 트리루스트라 크림이나 멜라논 크림 같은 트리플 콤비네이션 연고를 병원에서 처방하기도 해요. 이건 전문의약품이라 처방이 있어야 구매할 수 있습니다.$AAA$, array['하이드로퀴논', '도미나크림', '트레티노인', '트리플콤비네이션', '기미연고']::text[], 2023, 'S-w93eewma0-2', 'https://youtu.be/S-w93eewma0?t=399s', null, '2023-04-27 00:00:00+00'::timestamptz, '2023-04-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기미 먹는 약 트라넥삼산은 어떤 원리로 효과를 내나요?$AAQ$, $AAA$**트라넥삼산은 원래 출혈을 멈추는 지혈제로 사용되는 약물**이지만, 그 작용 기전을 통해 기미 치료에도 사용됩니다. 지혈을 위해서는 혈전이 필요한데 이 혈전을 분해시키는 plasmin이라는 성분을 트라넥삼산이 억제해 지혈 작용을 합니다.

그런데 이 **plasmin이 멜라닌 생성을 촉진하는 과정도 함께 억제되어** 기미 치료제로 활용되는 것이죠. 기미에는 지혈 용량보다 낮은 용량을 사용하기 때문에 비교적 안전하게 복용이 가능하지만, 혈전 생성 위험이 있거나 심장질환·신장질환이 있는 분들은 사용 시 주의해야 합니다. 제품으로는 도란사민, 멜라스민 캡슐이 있고, 트란시노라는 일반의약품도 트라넥삼산에 l-시스테인과 비타민C가 함께 들어간 복합제제예요. 전문의약품인 도란사민에 비해 트라넥삼산 함유량이 적어 효과가 좀 적을 수 있습니다.$AAA$, array['트라넥삼산', '도란사민', '지혈제기미', 'plasmin억제', '기미먹는약']::text[], 2023, 'S-w93eewma0-3', 'https://youtu.be/S-w93eewma0?t=481s', null, '2023-04-27 00:00:00+00'::timestamptz, '2023-04-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기미에 미백 화장품이나 기미 패치를 써도 괜찮나요?$AAQ$, $AAA$미백 화장품과 기미 패치는 도움이 될 수 있지만 자극을 일으키지 않는지 확인이 필요합니다. 피부과에서 자주 권하는 성분으로는 칸데이아 나무껍질에서 추출한 천연 성분인 **알파-비사보롤이 있는데 멜라닌 합성을 감소시켜 미백 기능이 있는 자극이 적은 순한 화장품**입니다. 이외에도 나이아신아마이드, 알부틴, 마그네슘 아스코빌 포스페이트 같은 비타민C 유도체가 들어간 다양한 화장품들이 있어요.

다만 **일부 성분은 과하게 사용하거나 본인에게 맞지 않으면 오히려 기미가 악화될 수** 있으므로, 사용 시 따끔거리거나 자극이 느껴지면 일단 중단하셔야 합니다. 기미 패치는 미백 성분이 들어 있지만 접착력 있는 패치를 장기간 기미 부위에 붙이고 있으면 그 자체가 자극이 될 수 있어요. 미백 성분이 포함된 패치를 사용하고 오히려 더 짙어져서 내원하시는 분들이 종종 있으니, 피부가 민감하다면 주의해서 사용하세요.$AAA$, array['미백화장품', '알파비사보롤', '나이아신아마이드', '기미패치', '비타민C유도체']::text[], 2023, 'S-w93eewma0-4', 'https://youtu.be/S-w93eewma0?t=571s', null, '2023-04-27 00:00:00+00'::timestamptz, '2023-04-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$흰머리는 왜 생기는 건가요?$AAQ$, $AAA$흰머리는 **모낭의 멜라닌 줄기세포가 멜라닌 색소를 만들지 못해** 발생합니다. 모발은 모낭의 옆쪽 팽대(Bulge)라는 부위에 있는 모발 줄기세포가 세포 분열을 해 만들어지는데, 여기에 멜라닌 줄기세포도 함께 있어 머리카락을 만들 때 멜라닌 색소를 입힙니다. 원래 머리카락은 흰 기둥 같은 거고 거기에 멜라닌이 색을 입히는 셈이에요.

나이가 들면 줄기세포들의 기능이 떨어지고 수도 줄어 멜라닌을 잘 만들지 못해 자연스럽게 흰머리가 많아집니다. 또 **유전자 변이, 활성 산소(ROS) 축적, 자외선 노출, 흡연**도 주요 원인이며, 비오틴 같은 비타민B군이나 아연·셀레늄·철분 같은 영양소 부족, 식습관도 영향을 줄 수 있어요. 측두부(두피 옆면)에서 흰머리가 먼저 난다고 알려져 있지만 그 이유에 대한 정확한 근거는 아직 부족합니다.$AAA$, array['흰머리원인', '멜라닌줄기세포', '활성산소', '모낭팽대', '비타민결핍']::text[], 2023, 'EFlVZBGPwVQ-1', 'https://youtu.be/EFlVZBGPwVQ?t=74s', null, '2023-05-02 00:00:00+00'::timestamptz, '2023-05-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스트레스를 받으면 흰머리가 정말 생기나요?$AAQ$, $AAA$스트레스와 흰머리는 **과학적 근거가 있는 진짜 인과관계**가 있습니다. 2020년 네이처지에 실린 연구에서 우리 몸이 스트레스를 받을 때 교감신경에서 분비되는 호르몬인 노르에피네프린 때문에 머리가 하얗게 된다는 사실이 실험적으로 증명되었어요.

실험은 털이 까만 쥐에게 심한 스트레스를 주는 방식으로 진행되었습니다. **원래 모낭 팽대에 있어야 할 멜라닌 줄기세포가 스트레스로 인해 빠르게 분열해 모두 없어져 버려** 까만 털이 못 나고 흰 털이 났고, 그 원인이 교감신경 말단에서 분비되는 노르에피네프린이라는 점이 밝혀졌어요. 모낭 구조에서 머리카락 뿌리 쪽에 아주 작은 모세혈관과 교감신경이 맞닿아 있어, 여기서 분비되는 물질 때문에 스트레스를 받으면 머리가 센다는 속설이 과학적으로 입증된 셈입니다.$AAA$, array['스트레스흰머리', '노르에피네프린', '교감신경', '네이처논문', '줄기세포소실']::text[], 2023, 'EFlVZBGPwVQ-2', 'https://youtu.be/EFlVZBGPwVQ?t=251s', null, '2023-05-02 00:00:00+00'::timestamptz, '2023-05-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$흰머리가 나면 뽑아도 되나요?$AAQ$, $AAA$흰머리는 **뽑는 것을 추천하지 않고 가위로 잘라**주세요. 모낭의 줄기세포는 그대로 남아 있기 때문에 흰머리를 뽑아도 다시 흰머리가 나는 경우가 많고, 일부에서 걱정하는 것처럼 한 가닥 뽑았다고 2가닥, 3가닥이 더 나지는 않습니다.

다만 **반복해서 뽑다 보면 모낭에 상처가 나거나 두피에 자극이 되는 경우가 많기 때문에** 가위로 자르는 편이 좋습니다. 흥미로운 점은 한번 흰머리가 됐다고 영원히 그대로인 것은 아니라는 사실이에요. 피부과에서 건선이나 류머티즘 치료로 휴미라·코센틱스 같은 생물학적 제제 주사를 맞은 환자 중 머리가 다시 까맣게 되는 케이스 리포트가 있고, 프로페시아 같은 탈모약 처방으로 까만 머리가 다시 자란 경험 사례도 있어 흰머리가 비가역적이지는 않다는 단서가 됩니다.$AAA$, array['흰머리뽑기', '모낭손상', '가위로자르기', '흰머리가역성', '케이스리포트']::text[], 2023, 'EFlVZBGPwVQ-3', 'https://youtu.be/EFlVZBGPwVQ?t=466s', null, '2023-05-02 00:00:00+00'::timestamptz, '2023-05-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$흰머리가 더 늘지 않게 예방하는 방법이 있나요?$AAQ$, $AAA$흰머리 예방은 **식습관·생활 습관·영양제 관리**로 어느 정도 도움을 받을 수 있습니다. 영양 측면에서는 양질의 단백질, 비타민B군이 풍부한 견과류·브로콜리·아보카도·초록 야채를 챙겨 드시고, 몸 안의 염증을 줄여주는 생선·베리류·올리브오일도 좋습니다.

생활 습관으로는 **스트레스를 너무 받지 않게 관리하는 것이 과학적으로 증명된 방법**이며, 충분한 수면 시간 확보와 금연도 도움이 됩니다. 영양제로는 비타민B·C·E가 함께 들어 있고 아연·셀레늄까지 같이 들어간 제품과 오메가3가 권장되는데, 오메가3는 혈관 건강·고지혈증뿐 아니라 염증을 줄여주는 효과가 있어요. 흰머리는 노화 외에도 여러 인자가 영향을 주기 때문에 단순히 늙어서 어쩔 수 없다고 생각하지 말고 관리해볼 만한 가치가 있습니다.$AAA$, array['흰머리예방', '비타민B군', '오메가3', '스트레스관리', '모발영양제']::text[], 2023, 'EFlVZBGPwVQ-4', 'https://youtu.be/EFlVZBGPwVQ?t=520s', null, '2023-05-02 00:00:00+00'::timestamptz, '2023-05-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$운동할 때 얼굴 주름 안 생기게 하려면 어떤 근육을 써야 하나요?$AAQ$, $AAA$운동할 때는 **광대 근육에 힘을 주는 것**이 정답입니다. 헬스할 때 얼굴이 망가지는 대표 원인은 이마·미간 등 위쪽 근육과 입가 밑 근육인데, 이 근육들은 평상시 무표정·운전·집중할 때 자주 쓰여 얼굴을 찡그리거나 끌어내리며 주름을 만들어요.

반면 **광대 근육은 쓰면 쓸수록 얼굴이 예뻐지고 젊어지며 입꼬리가 올라가는 효과**가 있습니다. 광대 근육을 단련하는 방법으로 '은' 소리를 내듯 입꼬리를 끌어올려 주세요. 벤치프레스를 들 때 '으' 하는 대신 '은~' 하는 식으로 광대 근육을 쥐어짜며 운동하면 됩니다. 한 달·두 달·1년·2년 트레이닝을 하다 보면 가만히 있는 자세에서도 그 부위가 강화되어 웃는 인상이 되며, 노인분도 얼굴만 웃고 있어도 환하고 밝고 젊어 보입니다.$AAA$, array['광대근육', '리프팅운동', '은운동법', '표정근운동', '헬스얼굴주름']::text[], 2023, 'p7unAXIHOic-1', 'https://youtu.be/p7unAXIHOic?t=80s', null, '2023-05-04 00:00:00+00'::timestamptz, '2023-05-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$평소에도 광대 근육을 자연스럽게 쓰는 방법이 있나요?$AAQ$, $AAA$평소에는 **입술만 살짝 떼는 것만으로도 광대에 힘이** 들어갑니다. '은' 소리를 내는 운동은 헬스장 같은 곳에서는 좋지만 일상에서 티가 너무 나서 부담스러울 수 있어요. 가만히 있다 보면 항상 입술을 꽉 다물게 되는데, 이때 입술만 살짝 떼주는 것만으로도 광대 근육에 힘이 들어가는 효과가 있습니다.

**입술을 꽉 붙이고 있으면 입이 나오면서 더 무표정해지고 끌어내리는 근육에 힘**이 들어가기 때문에, 운전·업무 등 무표정해지기 쉬운 상황이나 마스크 안에서 가끔 입술을 떼볼 수 있어요. 처음에는 평소 너무 안 쓰던 근육이라 경련이 일어날 정도지만, 계속하면 근육이 강화되어 리프팅 효과가 생기고 입꼬리도 들어올려져요. 안 써야 할 근육은 보톡스로 도움을 받고, 많이 써야 하는 광대 근육은 힘껏 웃어 단련하는 것이 좋습니다.$AAA$, array['광대근육일상운동', '입술떼기', '마스크속운동', '표정근단련', '리프팅습관']::text[], 2023, 'p7unAXIHOic-2', 'https://youtu.be/p7unAXIHOic?t=360s', null, '2023-05-04 00:00:00+00'::timestamptz, '2023-05-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$광대 근육을 단련하면 어떤 효과가 있나요?$AAQ$, $AAA$광대 근육을 단련하면 **얼굴이 리프팅되고 동안 효과**가 생깁니다. 이 근육을 쓰면 쓸수록 얼굴이 예뻐지고 젊어지며 입꼬리가 자연스럽게 올라가는데, 지난 영상에서 이마·미간·입가 밑 근육을 단련하지 말라고 한 것과 반대로 광대 근육은 자꾸 단련시키면 가만히 있는 자세에서도 그 부위가 강화됩니다.

한 달·두 달·1년·2년 트레이닝을 하다 보면 **웃는 인상이 자연스럽게 자리잡고 평소에도 입꼬리가 들어올려진 상태**가 되어 노인분도 환하고 밝고 젊어 보입니다. 화난 얼굴이나 무표정한 얼굴은 훨씬 더 나이 들어 보이고 좋지 않게 보이는 반면, 광대 근육이 발달한 사람은 표정 자체가 웃는 상·리프팅상이 됩니다. "행복해서 웃는 게 아니라 웃어서 행복하다"는 말처럼 웃는 표정이 기분까지 좋게 만들어주는 부수 효과도 기대할 수 있어요.$AAA$, array['광대근육효과', '동안표정', '입꼬리상승', '표정근비대', '안면리프팅']::text[], 2023, 'p7unAXIHOic-3', 'https://youtu.be/p7unAXIHOic?t=259s', null, '2023-05-04 00:00:00+00'::timestamptz, '2023-05-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$손발톱에 생긴 갈색·검은색 세로줄은 왜 생기나요?$AAQ$, $AAA$손톱 세로줄의 가장 큰 원인은 **손발톱 기질 모반(Nail matrix nevus)**입니다. 손발톱 기질은 손발톱이 만들어지는 공장 같은 곳인데, 흔히 피부에 점이 생기는 것처럼 이 공장에 점이 생기면 그 부위에서 만들어진 손톱이 손끝으로 자라 나오면서 긴 세로 선으로 보이게 되는 것이죠.

흑색 손발톱이 흑색종이 아닌 다른 이유로 생기는 경우도 다양합니다. **임신, 인종에 따른 차이, 외상, 작은 신발에 의한 반복 마찰, 손톱 깨무는 습관, 비타민 결핍, 쿠싱 증후군 같은 전신 질환, 항암제·말라리아 치료제, 곰팡이나 세균 감염** 등이 있어요. 주로 세로줄로 나타나지만 항암 치료를 받는 경우에는 가로줄 형태로도 발생할 수 있고, 하나의 손발톱뿐 아니라 여러 개에 동시에 발생할 수도 있습니다.$AAA$, array['손톱세로줄', '흑색조갑증', '손발톱기질모반', '흑색종원인', '손톱점']::text[], 2023, '1KQxCdSpuE0-1', 'https://youtu.be/1KQxCdSpuE0?t=46s', null, '2023-05-09 00:00:00+00'::timestamptz, '2023-05-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$손톱 흑색종은 어떻게 자가 검진할 수 있나요?$AAQ$, $AAA$손톱 흑색종은 **A, B, C, D, E, F 6가지 기준으로 자가 검진**할 수 있습니다. A는 Age(나이)로 50~70대 환자나 아시안·아프리칸·아메리칸 등 특정 인종에서 위험도가 높고, B는 Nail Band로 띠의 폭이 3mm가 넘고 경계가 불명확하며 불규칙한 경우 위험도가 더 높아요.

**C는 Change로 손톱 띠가 갑자기 두께가 증가하거나 모양이 변하는 경우**, D는 여러 손가락보다 하나의 손가락만 침범할 때 악성 위험이 높고 엄지손가락·엄지발가락·둘째 손가락 순으로 발병률이 높습니다. **E는 Extension으로 검은색 띠가 손톱뿐 아니라 주변 피부까지 번지는 Hutchinson sign**, F는 Family history(가족력)입니다. 흑색종은 최근 변화를 보이는 경우가 많아 원래 있던 병변의 색이 바뀌거나 모양·두께가 변하고 통증이나 궤양이 동반되면 의심해야 합니다. 2~3개월 간격으로 동일한 조건에서 사진을 찍어 변화를 기록하면 진단에 큰 도움이 됩니다.$AAA$, array['흑색종자가검진', 'ABCDEF기준', 'Hutchinsonsign', '손톱변화관찰', '흑색종위험도']::text[], 2023, '1KQxCdSpuE0-2', 'https://youtu.be/1KQxCdSpuE0?t=220s', null, '2023-05-09 00:00:00+00'::timestamptz, '2023-05-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$손톱 세로줄은 무조건 조직 검사를 해야 하나요?$AAQ$, $AAA$손톱 세로줄은 **흑색종이 강하게 의심되는 경우에 한해 조직 검사를** 시행합니다. 우리가 피부에 있는 모든 점을 다 검사하지 않는 것처럼 손발톱 기질 모반의 경우에도 대부분은 조직 검사를 하지 않아요. 다만 육안으로 모든 병변을 정확히 감별할 수 없기 때문에 꾸준히 변화를 관찰해야 합니다.

조직 검사 과정이 일반 피부와 달리 쉽지 않다는 점도 이유입니다. **손톱 아래 손톱이 만들어지는 부위(손발톱 기질)를 검사해야 해서 예전에는 손톱을 빼서** 검사를 했고, 지금은 다 뽑지는 않지만 그 부위의 손톱을 일부 자르고 젖혀서 아래쪽 조직을 떼어내 검사합니다. 손발톱을 만드는 공장의 일부를 떼어내기 때문에 일부에서는 영구적으로 손톱 모양이 변형되는 경우가 있어, 흑색종이 강하게 의심될 때만 진행해요. 2~3개월 간격 사진 기록과 변화 관찰이 진단에 큰 도움이 됩니다.$AAA$, array['손톱조직검사', '손발톱기질생검', '손톱변형', '흑색조관찰', '주기검진']::text[], 2023, '1KQxCdSpuE0-3', 'https://youtu.be/1KQxCdSpuE0?t=172s', null, '2023-05-09 00:00:00+00'::timestamptz, '2023-05-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$동양인은 손톱 흑색종이 잘 안 생기나요?$AAQ$, $AAA$악성 흑색종은 **주로 백인에게 많이 발생하는 질환이고 동양인에서는 드물지만**, 빈도가 조금씩 증가하고 있어 안심할 수는 없습니다. 빈도는 낮지만 피부과에서 중요하게 보는 이유가 있는데, 흑색종 외 대부분의 피부암은 병변 부위를 절제하면 생존율에 크게 영향이 없는 반면 흑색종은 진단이 지연되면 치료가 어렵고 다른 부위로 전이가 되어 사망할 수 있기 때문이에요.

특히 **동양인의 흑색종은 서양인과 달리 손발톱이나 손·발바닥에 많이 생기고**, 초기에는 손발톱에 선이 생기는 것 말고는 특별한 자각 증상이 없어 진단이 늦어지는 경우가 많은 것이 문제입니다. 그래서 A·B·C·D·E·F 기준으로 자가 검진을 시행하고, 사진으로 변화를 기록하면서 주기적으로 전문의 진료를 받으며 지속적으로 경과 관찰을 하는 것이 초기 발견의 기회를 놓치지 않는 방법이에요.$AAA$, array['동양인흑색종', '손발바닥흑색종', '흑색종전이', '조기진단', '주기검진']::text[], 2023, '1KQxCdSpuE0-4', 'https://youtu.be/1KQxCdSpuE0?t=407s', null, '2023-05-09 00:00:00+00'::timestamptz, '2023-05-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$탈모는 어떤 종류로 나뉘나요?$AAQ$, $AAA$탈모는 크게 남성형·여성형 탈모, 원형 탈모, 견인성 탈모, 휴지기 탈모로 나뉩니다.

남성형 탈모는 M자로 헤어라인이 뒤로 밀리거나 정수리가 비어 보이는 형태로, 가장 흔하게 진료실에 오시는 유형이에요. 여성형 탈모는 이마 헤어라인은 보통 괜찮고 **가르마를 따라 중앙부가 길게 넓어지는 모양**으로 나타나는 게 특징입니다. 원형 탈모는 급격한 스트레스를 받았을 때 동그란 모양으로 빠지고, 견인성 탈모는 머리를 너무 꽉 묶거나 옆으로 핀을 계속 고정하는 등 반복적으로 당겨지는 힘 때문에 모낭이 상해 생기는 탈모예요. 휴지기 탈모는 출산이나 큰 수술, 심한 다이어트 후 **3~6개월 정도 지나고 머리가 우수수 빠지는 현상**을 말합니다.$AAA$, array['탈모종류', '남성형탈모', '여성형탈모', '원형탈모', '견인성탈모', '휴지기탈모']::text[], 2023, 'B3cOiwUQOYg-1', 'https://youtu.be/B3cOiwUQOYg?t=70s', null, '2023-05-11 00:00:00+00'::timestamptz, '2023-05-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$탈모 자가 진단은 어떻게 하나요?$AAQ$, $AAA$탈모 자가 진단은 **하루에 100개 이상 빠지는지** 확인하고 정수리와 뒤통수 모발 굵기를 비교해 보는 게 기본입니다.

교과서적으로는 하루에 100개까지 빠지는 것은 정상으로 봐요. 다만 100개를 다 세기는 어려우니, 머리 감고 수채 구멍에 모이는 모발 양이 평상시보다 많이 늘어났다면 병원에 한 번 보여 주시는 게 좋습니다. 집에서 할 수 있는 또 다른 방법은 **뒤통수가 가장 마지막에 얇아지고 정수리가 먼저 얇아진다는 점**을 이용하는 거예요. 두 부위를 만져 비교했을 때 정수리가 더 빨리 얇아진 느낌이면 탈모 시작 신호일 수 있어요. 여성분은 가르마가 이전보다 휑하고 넓어 보일 때 의심해 볼 수 있습니다.$AAA$, array['탈모자가진단', '정상탈락모', '정수리탈모', '가르마탈모']::text[], 2023, 'B3cOiwUQOYg-2', 'https://youtu.be/B3cOiwUQOYg?t=251s', null, '2023-05-11 00:00:00+00'::timestamptz, '2023-05-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$탈모 샴푸가 정말 효과가 있나요?$AAQ$, $AAA$탈모 샴푸는 직접 발모 성분이 아니라 두피와 모발을 건강하게 유지해 주는 **보조적인 기능성 화장품**입니다.

시중 탈모 샴푸에 흔히 들어가는 성분은 덱스판테놀, 비오틴, 나이아신아마이드, 살리실릭애시드, 징크피리치온 등이에요. 덱스판테놀과 비오틴, 나이아신아마이드 같은 비타민B 계열은 모발이 잘 자라도록 돕는 역할을 하고, 살리실릭애시드는 두피 모공 스케일링 효과로 피지와 각질을 녹여 모공을 열어 줍니다. 징크피리치온은 항염 작용이 있어 **두피 지루 피부염으로 인한 염증성 탈모를 완화하는 데** 도움을 주죠. 다만 분류상 의약품이 아니라 기능성 화장품이라 탈모 치료보다는 예방·유지 관리용 보조 제품으로 보시는 게 정확합니다.$AAA$, array['탈모샴푸', '기능성화장품', '두피관리', '징크피리치온', '살리실릭애시드']::text[], 2023, 'B3cOiwUQOYg-3', 'https://youtu.be/B3cOiwUQOYg?t=427s', null, '2023-05-11 00:00:00+00'::timestamptz, '2023-05-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$탈모 치료에는 어떤 방법들이 있나요?$AAQ$, $AAA$탈모 치료는 **먹는 약, 영양 보조제, 바르는 약, 시술 및 모발 이식**으로 나뉘어 진행됩니다.

먹는 약은 가장 대표적이고 효과적인 방법으로, 프로페시아·아보다트 같은 약이 있어요. 다만 호르몬과 관련된 약이라 **남성형 탈모에 처방되며 여성분은 아직 허가가 되지 않아 복용할 수 없습니다**. 영양 보조제는 판토가·판시딜·케라민 등이 있고 티아민, 판토텐산, 효모, 케라틴 같은 성분으로 모발 성장에 도움을 줘요. 바르는 약은 미녹시딜이 대표적이고, 로게인폼처럼 무스 형태로 가르마 부위에 꾸준히 바르면 머리카락이 자라는 게 보입니다. 그 외 메조테라피, 보톡스, 두피 스케일링, 광치료, 레이저, 줄기세포·엑소좀 시술과 모발 이식까지 다양하게 선택할 수 있어요.$AAA$, array['탈모치료', '프로페시아', '미녹시딜', '로게인폼', '모발이식']::text[], 2023, 'B3cOiwUQOYg-4', 'https://youtu.be/B3cOiwUQOYg?t=605s', null, '2023-05-11 00:00:00+00'::timestamptz, '2023-05-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스트레스를 받으면 정말 머리가 빠지나요?$AAQ$, $AAA$네, 스트레스는 실제로 탈모에 영향을 준다는 연구가 많이 있습니다.

스트레스를 받으면 우리 몸에서는 코티졸, 노르에피네프린 같은 스트레스 호르몬이 분비되는데, 이 호르몬들이 **모낭에 영향을 미쳐 실제로 탈모로 이어집니다**. 원형 탈모는 특히 급격한 스트레스 상황에서 동그란 모양으로 빠지는 대표적인 케이스죠. 스트레스 호르몬 외에 남성 호르몬인 디하이드로테스토스테론(DHT)은 남성형 탈모와의 연관이 잘 알려져 있어 약으로도 조절합니다. 그 외 갑상선 질환, 빈혈, 다낭성 난소 증후군처럼 **호르몬이나 영양 불균형을 일으키는 질환**들도 탈모를 유발할 수 있으니, 머리가 갑자기 많이 빠지면 원인 질환부터 살펴 보시는 게 좋아요.$AAA$, array['스트레스탈모', '코티졸', '원형탈모', 'DHT', '호르몬탈모']::text[], 2023, 'B3cOiwUQOYg-5', 'https://youtu.be/B3cOiwUQOYg?t=370s', null, '2023-05-11 00:00:00+00'::timestamptz, '2023-05-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$문신 제거 레이저는 어떤 원리로 잉크를 없애나요?$AAQ$, $AAA$문신 제거 레이저는 큰 잉크 입자를 잘게 쪼개 **면역 세포가 배출하도록** 돕는 시술입니다.

문신을 하면 잉크가 표피층이 아니라 그 아래 진피층에 남게 되는데, 진피층은 표피처럼 각질로 탈락되는 기전이 없어 잉크가 그대로 머무릅니다. 게다가 **잉크 입자가 너무 커서 배출이 안 되고 계속 남게 되는 거예요**. 레이저는 이렇게 큰 입자를 산산조각으로 분쇄해 우리 몸의 면역 세포가 처리할 수 있는 크기로 만들어 줍니다. 분쇄 과정에서 기포가 생기면서 피부 표면이 하얗게 변하는 백화 현상, 즉 프로스팅이 일시적으로 나타나기도 해요. 이렇게 잘게 쪼개진 잉크가 면역 세포에 의해 빠져나가는 데에는 시간이 걸리므로 한 번에 완전히 사라지지는 않습니다.$AAA$, array['문신제거레이저', '진피층잉크', '프로스팅', '면역세포배출']::text[], 2023, '5q1_-Xh5PXE-1', 'https://youtu.be/5q1_-Xh5PXE?t=85s', null, '2023-05-16 00:00:00+00'::timestamptz, '2023-05-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$문신 제거는 몇 번 정도 받아야 하나요?$AAQ$, $AAA$다 제거하려면 최소 15회 이상, **총 기간 1년 반에서 2년 정도** 잡고 진행합니다.

다만 필요한 세션 수는 개개인마다 다르고, 잉크 색상이나 피부 상태에 따라 더 길어질 수 있어요. 영상의 환자분처럼 잎사귀에 녹색과 검은색이 섞여 있거나 피부색이 비교적 짙은 편이면 **잉크 색상이 섞여 있으면 아무래도 조금 더 오래 걸릴 수 있습니다**. 한 회 시술 간격은 4주에서 8주 정도로, 잘게 쪼개진 잉크가 면역 세포에 의해 배출되는 시간을 충분히 준 뒤 다음 시술을 이어 가요. 한 번 시술 직후엔 하얗게 백화 현상이 보이지만 시간이 지나면 색소가 다시 올라오므로, 회차를 거듭하며 점진적으로 옅어진다는 점을 미리 알고 계셔야 합니다.$AAA$, array['문신제거횟수', '문신제거기간', '시술간격', '다색문신']::text[], 2023, '5q1_-Xh5PXE-2', 'https://youtu.be/5q1_-Xh5PXE?t=124s', null, '2023-05-16 00:00:00+00'::timestamptz, '2023-05-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$문신 제거 통증은 어떻게 줄이나요?$AAQ$, $AAA$문신 제거 통증은 **마취 연고 30~40분 도포와 에어 쿨링 병행**으로 크게 줄일 수 있습니다.

시술 전에는 처방받은 진통제를 미리 복용하고, 마취 연고를 30분~40분 정도 충분히 바르고 시작해요. 마취 성분이 날아가지 않도록 위에 랩을 씌워 두는 것도 흡수율을 높이는 방법입니다. 시술 중에는 차가운 쿨링 가스를 옆에서 함께 쏴 주는 에어 쿨링 기계를 사용하는데, **차가운 감각 덕분에 통증이 한층 덜해지는 효과**가 있어요. 시술이 끝난 뒤에는 진정 드레싱을 함께 넣어 마무리합니다. 영상의 환자분도 통증을 10점 만점에 7~8점으로 표현하면서 못 참을 정도는 아니라고 했으니, 통증이 걱정되어도 마취와 쿨링을 잘 활용하면 충분히 견디실 수 있어요.$AAA$, array['문신제거통증', '마취연고', '에어쿨링', '진정드레싱']::text[], 2023, '5q1_-Xh5PXE-3', 'https://youtu.be/5q1_-Xh5PXE?t=159s', null, '2023-05-16 00:00:00+00'::timestamptz, '2023-05-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$문신 제거 후 시술 부위가 왜 하얗게 변하나요?$AAQ$, $AAA$레이저로 **문신 입자가 분쇄되며 기포가 발생하기 때문에** 시술 직후 피부가 하얗게 변합니다.

레이저 에너지가 들어가면 문신 잉크 입자를 잘게 분쇄시키는데, 이 과정에서 어쩔 수 없이 기포가 생깁니다. 그 기포가 **피부 표면에 떠오르면서 창문에 서리가 낀 것처럼 하얗게 보이는 현상**을 일으키죠. 이걸 의학적으로는 프로스팅, 또는 백화 현상이라고 부릅니다. 다만 이 하얀 막이 있을 때는 추가 레이저 에너지가 더 들어가지 않기 때문에, 같은 회차에 다른 파장으로 추가 제거를 원하시면 20분 정도 마취 연고를 다시 바르고 기다린 뒤 진행해야 해요. 또 백화 현상으로 잉크가 사라진 듯 보여도 시간이 지나면 색소가 다시 올라오니, 한 번에 다 없어진다고 오해하지 않으셨으면 좋겠습니다.$AAA$, array['프로스팅', '백화현상', '문신레이저버블', '시술경과']::text[], 2023, '5q1_-Xh5PXE-4', 'https://youtu.be/5q1_-Xh5PXE?t=420s', null, '2023-05-16 00:00:00+00'::timestamptz, '2023-05-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레이저 제모는 몇 회 정도 받아야 효과가 있나요?$AAQ$, $AAA$레이저 제모는 보통 **한 달에 한 번씩 5~10회 정도** 받아야 효과를 봅니다.

털은 성장기·퇴행기·휴지기의 주기를 반복하는데, 성장기에 있는 털을 제거할 때 제모가 가장 효과적이거든요. 그래서 털의 성장 주기를 고려해 보통 한 달에 한 번 시술하고, 제모 부위나 털의 굵기·밀도·피부 상태에 따라 횟수는 달라질 수 있어요. **제모 횟수가 많아질수록 털이 점점 얇아지고 점차 나지 않게 돼서 효과는 반영구적으로 유지됩니다**. 한 가지 주의할 점은 제모 4주 전부터 털을 뽑거나 왁싱하는 건 자제해야 한다는 거예요. 여름을 위해서라면 노출이 시작되기 몇 달 전에 미리 시작하는 게 좋고, 한두 번에 끝나지 않는다는 점도 기억해 두시면 좋겠습니다.$AAA$, array['레이저제모', '제모횟수', '성장기털', '반영구제모']::text[], 2023, 'R54pJz0zZ3I-1', 'https://youtu.be/R54pJz0zZ3I?t=176s', null, '2023-05-23 00:00:00+00'::timestamptz, '2023-05-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$태닝과 제모를 동시에 할 수 있나요?$AAQ$, $AAA$태닝과 제모를 함께 한다면 **레이저 제모를 먼저 받는 것이 좋습니다**.

레이저 제모는 빛이 멜라닌 색소에 흡수되는 과정에서 열 에너지를 발생시켜 모근을 제거하는 원리예요. 그런데 태닝은 자외선이 멜라닌 세포를 자극해 피부를 어둡게 만드는 과정이라, 제모 레이저가 검은 멜라닌 세포에도 반응하기 때문에 **태닝이 이루어진 상태에서 제모를 받으면 레이저 강도를 줄여야 하고 제모 효과도 떨어집니다**. 게다가 색소 침착이나 착색 같은 부작용이 생길 확률도 높아져요. 따라서 바디 프로필 촬영 등으로 두 가지를 모두 원하신다면 순서가 중요하고, 제모 레이저로 먼저 충분히 진행한 뒤 태닝을 하는 게 안전합니다.$AAA$, array['태닝제모', '멜라닌레이저', '착색부작용', '제모순서']::text[], 2023, 'R54pJz0zZ3I-2', 'https://youtu.be/R54pJz0zZ3I?t=242s', null, '2023-05-23 00:00:00+00'::timestamptz, '2023-05-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$바디 색소 침착도 토닝으로 좋아지나요?$AAQ$, $AAA$네, 바디 색소 침착은 **1~2주 간격 레이저 토닝 10회 정도**로 개선 효과를 볼 수 있습니다.

팔꿈치·무릎의 반복 마찰 착색, 상처가 아문 자국, 가려워 긁었던 부위, 가슴·등 여드름 자국 등 다양한 원인으로 색소 침착이 생기죠. 부위와 정도, 원인에 따라 치료 기간은 달라질 수 있지만 1~2주 간격으로 토닝을 꾸준히 진행하면 어느 정도 효과를 보실 수 있어요. **흉터에 붉은 기가 함께 있다면 브이빔 같은 혈관 레이저를 병행해 치료**합니다. 무엇보다 중요한 건 재발 방지입니다. 다친 부위는 다시 안 다치게 하고, 아토피 피부염이나 여드름이 원인이었다면 그 질환부터 관리해야 해요. 그리고 몸에도 자외선 차단제를 꼭 발라 주시는 게 좋습니다.$AAA$, array['바디토닝', '색소침착', '브이빔', '착색관리']::text[], 2023, 'R54pJz0zZ3I-3', 'https://youtu.be/R54pJz0zZ3I?t=387s', null, '2023-05-23 00:00:00+00'::timestamptz, '2023-05-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$겨드랑이 보톡스 효과는 얼마나 지속되나요?$AAQ$, $AAA$겨드랑이 보톡스 효과는 **최소 3개월에서 최대 6개월 정도** 지속됩니다.

다한증은 자율 교감 신경에서 아세틸콜린이 비정상적으로 많이 분비돼 땀이 과하게 나는 증상이에요. 겨드랑이는 땀샘이 많아 특히 더 잘 느껴지죠. 보톡스를 땀이 많이 나는 부위에 주사하면 **아세틸콜린 분비를 차단해 땀 분비를 줄여 줍니다**. 효과는 빠르게 나타나서 시술 후 일주일 이내로 땀이 확연히 줄어드는 게 느껴지고, 유지 기간은 사람에 따라 3~6개월 정도예요. 다만 이마나 미간 보톡스보다 사용 용량이 많기 때문에 자주 맞으면 항체가 생겨 내성이 올 수 있으니, 시술 간격을 잘 지키고 내성이 잘 생기지 않는 제품을 선택하시는 게 좋습니다.$AAA$, array['겨드랑이보톡스', '다한증치료', '아세틸콜린', '보톡스내성']::text[], 2023, 'R54pJz0zZ3I-4', 'https://youtu.be/R54pJz0zZ3I?t=470s', null, '2023-05-23 00:00:00+00'::timestamptz, '2023-05-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$겨드랑이 보톡스 시술은 어떻게 진행되나요?$AAQ$, $AAA$겨드랑이 보톡스는 마취 크림 30~40분 도포 후 **1~1.5cm 간격으로 주사**해 진행됩니다.

많은 분이 부위 특성상 통증을 걱정하시는데, 의외로 이마·미간 보톡스보다 통증을 덜 느끼는 분이 많다고 해요. 시술은 다른 부위 보톡스와 동일한 방식으로 시작합니다. 먼저 마취 크림을 30~40분 정도 충분히 도포한 뒤 크림을 닦아내고, **땀이 나는 영역을 펜으로 표시한 다음 1~1.5cm 간격으로 주사를 놓습니다**. 시술 자체는 간단하고 효과도 3~6개월까지 오래 가서, 손도 못 들 정도로 축축한 여름철 겨드랑이가 고민이라면 충분히 고려해 볼 만한 시술이에요. 시술 간격을 잘 지키고 내성이 적은 제품을 선택해 진행하시면 좋습니다.$AAA$, array['겨드랑이보톡스시술', '보톡스마취', '주사간격', '다한증주사']::text[], 2023, 'R54pJz0zZ3I-5', 'https://youtu.be/R54pJz0zZ3I?t=556s', null, '2023-05-23 00:00:00+00'::timestamptz, '2023-05-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부를 위해 잠은 몇 시에 자는 게 좋나요?$AAQ$, $AAA$피부 건강을 위해서는 **밤 10시부터 새벽 2시까지** 반드시 잠을 자는 게 중요합니다.

이 시간대는 성장 호르몬과 멜라토닌이 가장 활발하게 분비되는 시기예요. 성장 호르몬은 밤 10시~새벽 2시 사이에 왕성하게 분비되어 **피부의 재생과 피로 회복을 돕고 활성 산소를 제거해 노화를 방지하는 효과**가 있습니다. 멜라토닌도 잠이 들면서부터 서서히 분비되기 시작해 깊은 수면 단계에 이르는 새벽 2시에 가장 활발하게 분비돼서 이 시간대를 골든 타임이라고 부릅니다. 멜라토닌은 염증 완화와 면역력 증강, 활성 산소 제거뿐 아니라 멜라닌 기능을 저하시켜 기미를 예방해 주는 작용도 합니다. 그래서 이 골든 타임을 놓치지 않고 주무시는 게 가장 좋아요.$AAA$, array['수면골든타임', '성장호르몬', '멜라토닌', '피부재생수면']::text[], 2023, 'qPt6xMA53MQ-1', 'https://youtu.be/qPt6xMA53MQ?t=255s', null, '2023-05-26 00:00:00+00'::timestamptz, '2023-05-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$엎드려 자거나 옆으로 자면 주름이 생기나요?$AAQ$, $AAA$엎드리거나 한쪽으로만 자면 **고정 주름과 안면 비대칭이 생길 수 있습니다**.

자는 자세는 천장을 보고 주무시는 게 가장 좋아요. 보통 하루 8시간을 잔다고 가정하면, 그 시간 동안 엎드리거나 옆으로 누워 자면 **피부가 눌려 주름진 상태로 8시간이 지나는 셈**입니다. 특히 눈가 주름이나 팔자 주름이 고착화되어 고정 주름이 될 수 있고, 한쪽 방향으로만 누워 자는 습관이 반복되면 안면 비대칭으로 이어지기도 해요. 베개 높이도 중요한데, 너무 높은 베개는 자세를 불편하게 해 수면을 방해할 뿐 아니라 목이 앞으로 젖혀지면서 목주름의 악화 요인이 될 수 있습니다. 가능하면 천장을 보고 적당한 높이의 베개로 주무시길 권합니다.$AAA$, array['수면자세', '고정주름', '안면비대칭', '베개높이', '목주름']::text[], 2023, 'qPt6xMA53MQ-2', 'https://youtu.be/qPt6xMA53MQ?t=283s', null, '2023-05-26 00:00:00+00'::timestamptz, '2023-05-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$잠을 못 자면 피부에 어떤 문제가 생기나요?$AAQ$, $AAA$수면이 부족하면 **수분 손실 증가와 각질 정체, 염증 악화** 등 다양한 피부 문제가 생깁니다.

수면 장애가 있는 사람의 피부는 숙면을 취한 사람보다 경표피 수분 손실이 높은 것으로 알려져 있어, 건조하고 푸석푸석해지기 쉽습니다. 또 피부는 성장 호르몬의 도움으로 정상적인 턴오버 주기를 유지하는데, **밤 10시~새벽 2시 성장 호르몬 분비 시간에 충분히 자지 못하면 각질 교체가 원활하지 않아** 노화 각질이 표피에 쌓이고 트러블이 생길 수 있어요. 아토피나 지루성 피부염 같은 만성 염증성 피부 질환이 있는 경우, 잠이 부족하면 스트레스 호르몬과 사이토카인 같은 염증 물질이 증가해 질환이 악화되기도 합니다. 그래서 피부가 칙칙해지고 화장이 들뜨는 경험은 결코 기분 탓이 아닙니다.$AAA$, array['수면부족피부', '경표피수분손실', '스킨턴오버', '염증악화']::text[], 2023, 'qPt6xMA53MQ-3', 'https://youtu.be/qPt6xMA53MQ?t=189s', null, '2023-05-26 00:00:00+00'::timestamptz, '2023-05-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$자기 전 술이나 커피는 피부에 어떤 영향을 주나요?$AAQ$, $AAA$자기 전 카페인·알코올·니코틴은 **뇌를 각성시켜 숙면을 방해하고 피부를 건조하게** 만듭니다.

많은 분이 술을 마셔야 잠이 잘 온다고 하시는데, 일시적으로 졸음을 늘릴 수는 있어도 결국 뇌를 각성 상태로 만들어 깊은 잠을 방해합니다. 니코틴 역시 각성 작용이 있어 같은 문제를 일으켜요. 게다가 **카페인과 알코올은 이뇨 작용이 있어 피부를 건조하고 푸석푸석하게** 만들기도 합니다. 자는 동안 피부가 충분히 회복하려면 낮 동안 쌓인 노폐물과 메이크업 잔여물을 꼼꼼히 세안하고, 클렌징 후 보습제를 잘 발라 건조해지지 않도록 해주는 것이 중요해요. 결국 피부를 위한 좋은 수면은 자기 전 자극 물질을 피하고 보습까지 마무리하는 데서 시작됩니다.$AAA$, array['수면방해', '카페인피부', '알코올수면', '자기전보습']::text[], 2023, 'qPt6xMA53MQ-4', 'https://youtu.be/qPt6xMA53MQ?t=465s', null, '2023-05-26 00:00:00+00'::timestamptz, '2023-05-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$쥬베룩과 필러는 어떻게 다른가요?$AAQ$, $AAA$쥬베룩은 자가 콜라겐을 생성시키는 시술이고, 필러는 **히알루론산을 그대로 주입하는 점**에서 본질적으로 다릅니다.

필러는 히알루론산을 여러 개 묶어 결합한 형태를 피부에 그대로 집어넣는 시술이에요. 그 자리에 머무르며 물을 끌어당겨 볼륨 효과를 유지하고, 부위에 따라 몇 년씩 가는 안정적인 유지가 큰 장점입니다. 반면 쥬베룩은 PDLLA 가루로 만든 속이 빈 공 같은 입자를 넣어 두면 그 안에 콜라겐이 차오르고, **껍데기는 물에 녹아 콜라겐만 얻고 피부에는 아무것도 남지 않는 방식**입니다. 그래서 많은 양을 주입해야 하고 효과가 서서히 나타나며 시간이 좀 걸려요. 즉각적이고 풍부한 볼륨이 필요하다면 필러, 본인 콜라겐으로 자연스러운 볼륨을 원한다면 쥬베룩 볼륨이 더 잘 맞습니다.$AAA$, array['쥬베룩필러비교', 'PDLLA', '히알루론산필러', '자가콜라겐']::text[], 2023, 'lxJtyhhBQZ8-1', 'https://youtu.be/lxJtyhhBQZ8?t=200s', null, '2023-05-30 00:00:00+00'::timestamptz, '2023-05-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$쥬베룩과 쥬베룩 볼륨은 어떻게 다른가요?$AAQ$, $AAA$쥬베룩과 쥬베룩 볼륨은 **입자 크기와 주입 깊이가 다른 시술**입니다.

쥬베룩 볼륨이 축구공만큼 큰 입자라면 쥬베룩은 야구공처럼 더 작은 입자라고 생각하시면 돼요. 입자가 작은 쥬베룩은 피부결, 모공, 잔주름 개선을 목적으로 **피부 바깥쪽 가까운 층에 주로 시술**합니다. 입자가 큰 쥬베룩 볼륨은 볼륨 효과를 얻기 위해 피하 지방층처럼 더 안쪽 깊은 층에 시술하죠. 두 가지 모두 PDLLA 미세 입자에 히알루론산을 결합한 가루 형태이고, 물에 녹여 액체로 만드는 수화 과정을 거친 뒤 손 주사나 인젝터로 피부에 주입합니다. 어떤 부위·고민이냐에 따라 쥬베룩과 쥬베룩 볼륨 중 적합한 쪽을 선택하거나, 두 가지를 함께 활용하기도 합니다.$AAA$, array['쥬베룩', '쥬베룩볼륨', '입자크기', '주입깊이']::text[], 2023, 'lxJtyhhBQZ8-2', 'https://youtu.be/lxJtyhhBQZ8?t=185s', null, '2023-05-30 00:00:00+00'::timestamptz, '2023-05-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$쥬베룩 볼륨은 어떤 사람에게 잘 맞나요?$AAQ$, $AAA$쥬베룩 볼륨은 **필러에 거부감이 있으신 분과 자연스러운 볼륨을 원하시는 분**에게 가장 잘 맞습니다.

옆 볼이 꺼졌거나 앞 볼이 꺼졌거나 퀭하다며 오시는 분 중에서 "필러는 안 맞고 싶어요"라고 말씀하시는 경우가 요즘 많아요. 그런 분들에게 가장 추천하는 시술이 쥬베룩 볼륨입니다. 한 번 맞아보고 **볼륨이 채워지는 느낌을 필러 전에 예행 연습처럼** 경험해 볼 수도 있어요. 다만 코, 이마, 턱, 관자놀이, 입술처럼 모양을 만들어 유지해야 하는 부위는 필러가 더 적합하고, 볼륨 손실이 큰 경우에도 필러를 권합니다. 효과가 즉각적이지 않고 한두 달 단위로 재시술이 필요해 비용이 누적될 수 있는 점은 단점이지만, 잔주름과 피부결 개선까지 함께 따라오는 게 장점입니다.$AAA$, array['쥬베룩볼륨적응증', '필러거부감', '자가콜라겐볼륨', '꺼진볼']::text[], 2023, 'lxJtyhhBQZ8-3', 'https://youtu.be/lxJtyhhBQZ8?t=280s', null, '2023-05-30 00:00:00+00'::timestamptz, '2023-05-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$쥬베룩 결절 부작용은 위험하지 않나요?$AAQ$, $AAA$쥬베룩 결절은 **수화를 충분히 하면 생길 가능성이 매우 줄어드는** 부작용이라 크게 걱정하지 않으셔도 됩니다.

쥬베룩은 가루 형태라 시술 전 물에 녹이는 수화 과정이 필요하고, 이 수화를 충분히 해 주면 결절이 잘 생기지 않아요. 또 쥬베룩 볼륨은 깊은 층에 놓기 때문에 결절이 있어도 사실 밖에서는 별로 티가 나지 않습니다. 만약 결절이 발생하더라도 **쥬베룩 안 히알루론산 결절은 히알라제로 녹여 주고, PDLLA 결절은 고주파 같은 높은 열로 해결**할 수 있어요. 일반적인 시술 후엔 마취 주사 시 따끔함, 캐뉼라 통증, 약간의 멍, 부기 정도가 흔한 부작용입니다. 시술 콜라겐 형성에는 개인차가 크니, 한 달 간격 세 번이나 3개월 간격 같은 주기를 기본으로 두고 꾸준히 조정해 가시면 됩니다.$AAA$, array['쥬베룩결절', '수화과정', '히알라제', 'PDLLA결절']::text[], 2023, 'lxJtyhhBQZ8-4', 'https://youtu.be/lxJtyhhBQZ8?t=525s', null, '2023-05-30 00:00:00+00'::timestamptz, '2023-05-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$쥬베룩 시술은 어떤 방법들로 주입하나요?$AAQ$, $AAA$쥬베룩은 **직접 주사, 미라젯, 니들RF** 등 여러 방법으로 피부에 주입할 수 있습니다.

직접 주사로 놓으면 여러 번 바늘로 찌르다 보니 통증이 있고, 주사 후 생기는 엠보나 바늘 자국이 짧게는 2~3일, 길게는 일주일 정도까지 가실 수 있어요. 그래서 요새 시술 트렌드인 티가 안 나는 시술을 원하는 분들이 늘면서 **미라젯이나 니들RF로 주입하는 방법이 인기**입니다. 이 방법은 다운타임이 적어 주말에 시술하고 월요일에 출근해도 거의 티가 나지 않아요. 또 미라젯·니들RF 같은 장비 자체에 피부 재생 효과가 있기 때문에 쥬베룩 효과에 시너지를 더해 줍니다. 본인 라이프스타일과 다운타임 허용 범위에 맞춰 주치의와 상의해 결정하시면 좋습니다.$AAA$, array['쥬베룩주입방법', '미라젯', '니들RF', '다운타임']::text[], 2023, 'lxJtyhhBQZ8-5', 'https://youtu.be/lxJtyhhBQZ8?t=386s', null, '2023-05-30 00:00:00+00'::timestamptz, '2023-05-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$다크서클은 어떤 유형으로 나뉘나요?$AAQ$, $AAA$다크서클은 크게 **색소 침착형, 혈관형, 볼륨형** 세 가지로 나뉩니다.

색소 침착형은 자주 비비는 자극, 자외선, 타고난 색소, 반복적인 염증 같은 원인으로 눈 밑이 갈색을 띠는 유형이에요. 혈관형은 눈 밑 피부가 얇아 아래의 정맥이 비쳐 푸른빛으로 보이는 형태이고, **피부가 얇거나 살짝 꺼져 있는 경우 더 두드러집니다**. 볼륨형은 눈 밑 지방이 처지거나 두꺼워지면서 그림자가 지거나, 반대로 살짝 꺼져 어두워 보이는 유형으로 시술 만족도가 높은 편이에요. 본인이 어떤 유형인지 모른 채 친구가 좋다고 한 시술을 따라 받기보다는, **원인에 따라 치료가 달라지기 때문에 정확한 진단을 받는 것이 가장 중요**합니다.$AAA$, array['다크서클유형', '색소침착형', '혈관형다크서클', '볼륨형다크서클']::text[], 2023, 'z5p885cLK48-1', 'https://youtu.be/z5p885cLK48?t=95s', null, '2023-06-01 00:00:00+00'::timestamptz, '2023-06-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$내 다크서클 유형은 어떻게 자가 진단하나요?$AAQ$, $AAA$다크서클 유형은 **피부를 당겨 보고 빛을 비춰** 자가 진단해 볼 수 있습니다.

눈 밑 피부를 밑이나 옆으로 당겨 봤을 때 어두운 색이 피부와 함께 움직이면 색소 침착형으로 진단할 수 있어요. 반대로 아무리 움직여도 **혈관이 그대로 그 자리에 있는 것처럼 보이면 혈관형**으로 볼 수 있습니다. 또 밝은 곳에서 빛을 비춰 봤을 때 혈관형은 피부가 얇아 파란색 혈관이 잘 비쳐 보이는 점도 단서가 돼요. 다만 이 방법이 완전한 진단법은 아니라서 집에서 대략적인 느낌을 보는 정도로만 활용하시고, 정확한 진단은 병원에서 특수 카메라 등을 이용해 받는 것이 좋습니다. 멜라닌 색소 때문인지, 피부가 두꺼워진 건지, 주름이 겹쳐 진해 보이는 건지에 따라 치료가 달라집니다.$AAA$, array['다크서클자가진단', '혈관형감별', '색소침착감별', '당김검사']::text[], 2023, 'z5p885cLK48-2', 'https://youtu.be/z5p885cLK48?t=200s', null, '2023-06-01 00:00:00+00'::timestamptz, '2023-06-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$색소 침착형 다크서클은 어떻게 치료하나요?$AAQ$, $AAA$색소 침착형 다크서클은 **자극을 줄이고 멜라닌을 분해하는 색소 레이저 치료**가 효과적입니다.

색소 침착형 다크서클은 비비는 자극으로 더 짙어질 수 있어, 혈액 순환을 위해 너무 세게 문지르는 마사지는 오히려 색을 어둡게 만들 수 있습니다. 그래서 **피부에 자극을 주지 않게 살살 문지르는 정도의 마사지**가 좋고, 보습을 충분히 해 주는 것도 기본입니다. 멜라닌이 많아져 생긴 경우라면 멜라닌을 파괴해 주는 색소 레이저 치료가 도움이 될 수 있고, 분해 과정을 거치면서 치료 효과가 좋게 나타나요. 다만 한 번 치료해도 눈 주변을 다시 긁거나 비비면 색소가 다시 생길 수 있어, 원인이 되는 알레르기나 아토피 피부염 같은 질환을 먼저 치료받는 것이 가장 중요합니다.$AAA$, array['색소침착다크서클', '색소레이저', '비비는자극', '아토피눈가']::text[], 2023, 'z5p885cLK48-3', 'https://youtu.be/z5p885cLK48?t=263s', null, '2023-06-01 00:00:00+00'::timestamptz, '2023-06-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$볼륨형 다크서클은 어떻게 개선하나요?$AAQ$, $AAA$볼륨형 다크서클은 **꺼진 곳은 채우고 돌출 부위는 줄이는 방식**으로 1~2회에 좋아질 수 있습니다.

눈 밑이 푹 들어가 보이는 케이스라면 채워 주는 시술이 답이에요. 대표적으로 필러가 있고, 요즘에는 **쥬베룩 볼륨처럼 자연스럽게 채워 주는 형태도 많이 활용**합니다. 반대로 눈 밑 지방이 처지거나 돌출되어 있는 경우엔 수술로 살짝 제거하거나, 아그네스 같은 고주파 시술로 지방만 녹여 개선할 수 있어요. 또 주름·돌출·꺼짐이 복합적으로 있는 분께는 아이울쎄라·아이써마지 같은 리프팅 시술도 도움이 됩니다. 볼륨형은 비교적 1~2번에 잘 좋아지는 타입이지만, 현실에서는 색소·혈관·볼륨 문제가 함께 있는 경우가 많아 진단 후 복합 플랜으로 꾸준히 관리하는 것이 중요합니다.$AAA$, array['볼륨형다크서클', '눈밑필러', '아그네스', '아이써마지']::text[], 2023, 'z5p885cLK48-4', 'https://youtu.be/z5p885cLK48?t=386s', null, '2023-06-01 00:00:00+00'::timestamptz, '2023-06-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$다크서클 홈케어는 어떻게 해야 하나요?$AAQ$, $AAA$다크서클 홈케어는 **충분한 수면, 보습, 자외선 차단** 이 세 가지가 핵심입니다.

밤을 새우거나 피곤할 때 다크서클이 진해지는 것처럼, 충분한 수면과 스트레스 조절은 모든 유형에 기본이 됩니다. 보습도 매우 중요한데, 특히 아토피 피부염으로 다크서클이 있으신 분은 **세수 후 한 번이 아니라 당김·각질이 느껴질 때마다 수시로 보습제를 도포**해 주시는 게 좋아요. 화장으로 인한 착색도 다크서클을 유발할 수 있어, 눈 화장을 지울 때 자극을 주지 않고 꼼꼼히 제거해야 합니다. 그리고 자외선 차단제는 눈가까지 빠짐없이 바르고, 선글라스를 함께 끼면 자외선 차단과 눈 찡그림으로 생기는 주름까지 미리 예방됩니다. 단, 마사지는 살살, 과하게 문지르지 않도록 주의하세요.$AAA$, array['다크서클홈케어', '눈가보습', '자외선차단', '선글라스']::text[], 2023, 'z5p885cLK48-5', 'https://youtu.be/z5p885cLK48?t=480s', null, '2023-06-01 00:00:00+00'::timestamptz, '2023-06-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$실리프팅은 정말 얼굴을 끌어올리는 시술인가요?$AAQ$, $AAA$실리프팅은 **얼굴을 끌어올리기보다 흘러내리는 조직을 잡아 주는 시술**입니다.

많은 분이 밧줄로 살을 끌어올리는 느낌으로 생각하시는데, 중력 반대 방향으로 끌어올리는 건 너무 과하고 유지도 안 되며 얼굴이 어색해집니다. 실제로는 광대 주변, 관자 주변, 턱 라인 주변에 실을 걸어 **근막과 지방 사이 조직이 흘러내리는 것을 잡아 주는 역할**이 가장 큽니다. 얼굴은 지방이 구역으로 나뉘어 인대 같은 격막이 잡아 주는데, 이 인대가 느슨해지고 지방이 빠지거나 쌓이면서 울퉁불퉁한 노안의 형태가 됩니다. 실은 약해진 인대 대신 **피부 밑에 단단한 철길을 깔아 지방층을 재배치하고 얼굴 라인을 만들어 주는** 구조물에 가깝습니다.$AAA$, array['실리프팅원리', '코그실', '지방재배치', '얼굴라인교정']::text[], 2023, 'KdEF-Rg_zZM-1', 'https://youtu.be/KdEF-Rg_zZM?t=156s', null, '2023-06-06 00:00:00+00'::timestamptz, '2023-06-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$실리프팅과 필러는 어떻게 다른가요?$AAQ$, $AAA$실리프팅은 라인을 잡아 주는 시술이고, **필러는 원하는 부위에 즉각 볼륨을 채우는 시술**이라는 점에서 다릅니다.

돌기실로 얼굴 윤곽을 잡아 살짝 끌어 주는 효과는 실을 대체할 만한 시술이 없어요. 반면 모노실·캐번실 같은 볼륨용 실은 콜라겐 재생을 유도해 볼륨을 채우는데, **필러는 원하는 부위에 원하는 양을 정확히 주입해 즉각적이고 직관적인 효과**를 냅니다. 필러는 마음에 안 들면 녹일 수 있지만 실은 제거가 어렵습니다. 실은 자리에 그대로 머물러 안정적이고 자연스럽다는 장점이 있지만, 필러만큼 볼륨을 내려면 많은 양이 필요해 가격이 비싸지고 부위별로 정확한 양 예측이 어려운 단점이 있어요. 라인 교정은 실, 볼륨은 필러를 우선 고려하고 함께 활용하기도 합니다.$AAA$, array['실리프팅필러비교', '캐번실', '모노실', '볼륨시술비교']::text[], 2023, 'KdEF-Rg_zZM-2', 'https://youtu.be/KdEF-Rg_zZM?t=298s', null, '2023-06-06 00:00:00+00'::timestamptz, '2023-06-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$실리프팅 효과는 얼마나 지속되나요?$AAQ$, $AAA$실리프팅 효과는 보통 **1년 정도면 서서히 떨어진다고** 보고 있습니다.

실은 피부에 들어간 뒤 천천히 녹아서 다 없어지고, 그 자리에 유착을 만들어 단단하게 유지시키는 역할을 합니다. 시간이 지나면 이 유착도 약해지면서 효과가 줄어드는데, 보통은 **1년 정도면 효과가 서서히 떨어지지만 케이스 바이 케이스**라 정해진 주기보다는 효과가 떨어졌다고 느낄 때 다시 시술하는 방식을 권합니다. 따라서 정기적으로 무조건 받아야 하는 시술이 아니라, 본인 얼굴 상태에 맞춰 필요하면 지속적으로 받는 시술입니다. 실은 한번 넣으면 제거가 어렵기 때문에 처음 디자인할 때 적절한 층·깊이·위치·양을 잘 계획하는 것이 효과 유지에서도 가장 중요합니다.$AAA$, array['실리프팅지속기간', '실유착', '리프팅주기', '재시술시점']::text[], 2023, 'KdEF-Rg_zZM-3', 'https://youtu.be/KdEF-Rg_zZM?t=405s', null, '2023-06-06 00:00:00+00'::timestamptz, '2023-06-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$실리프팅 후 통증과 부작용은 어떤 게 있나요?$AAQ$, $AAA$실리프팅 후에는 **2~3주간 입 벌릴 때 불편감과 딤플 같은 가벼운 부작용**이 생길 수 있습니다.

시술 자체는 주사로 마취를 먼저 깔고 진행해 시술 중에는 거의 아프지 않습니다. 다만 시술 후에 마취가 풀린 뒤에는 볼 주변 실 때문에 입이 잘 안 벌어지거나, 크게 벌리면 우드득 같은 기분 나쁜 소리가 날 수 있어요. 이런 증상은 **유착이 안정화될 때까지 2~3주 정도까지 좀 아플 수 있습니다**. 가장 흔한 부작용은 딤플로, 실이 표면 가까운 피부를 살짝 물면 집힌 듯 파여 보이는 현상이에요. 보통 풀어 주는 마사지를 하면 좋아지고, 실이 녹으면서 자연스럽게 해결되는 경우가 대부분입니다. 그 외 멍·통증 같은 가벼운 부작용은 시간이 지나면 해소되니 너무 겁먹지 않으셔도 돼요.$AAA$, array['실리프팅부작용', '딤플', '실리프팅통증', '회복기간']::text[], 2023, 'KdEF-Rg_zZM-4', 'https://youtu.be/KdEF-Rg_zZM?t=418s', null, '2023-06-06 00:00:00+00'::timestamptz, '2023-06-06 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$두피 마사지로 탈모를 치료할 수 있나요?$AAQ$, $AAA$두피 마사지만으로 탈모를 치료할 수는 없습니다. 일부 논문에서 두피 마사지가 모낭세포를 자극해 모발 생산을 촉진하고 모세혈관을 확장시켜 두피 혈류를 증가시킨다고 보고되어 있어 어느 정도 모발 상태 개선 효과는 있을 수 있지만, **탈모 치료 효과를 입증하기엔 증거가 부족**합니다.

오히려 세게 손톱으로 긁듯이 마사지를 하거나 날카로운 도구로 지나친 자극을 주면 두피에 상처가 나고 염증이 유발되어 모발에 악영향을 끼칠 가능성도 있어요. 따라서 치료 목적이 아닌 모발 상태 개선을 위해 마사지를 원하신다면, **손끝으로 부드럽게 지그시 누르거나 톡톡 두드리는 가벼운 방법**을 사용하는 것이 좋겠습니다.$AAA$, array['두피마사지', '탈모치료', '모낭자극', '홈케어', '두피자극']::text[], 2023, '4e9PSxrsnm4-1', 'https://youtu.be/4e9PSxrsnm4?t=89s', null, '2023-06-08 00:00:00+00'::timestamptz, '2023-06-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$어성초나 검은콩이 탈모에 도움이 되나요?$AAQ$, $AAA$어성초와 검은콩 모두 탈모 개선 효과는 과학적으로 입증되지 않았습니다. 어성초 성분 자체에 항산화 성분이 많이 함유되어 있기는 하지만, **탈모 개선에 도움을 준다는 과학적으로 입증된 결과가 없어요**.

검은콩에는 단백질과 다양한 종류의 비타민, 식이섬유, 아연 등이 함유되어 있어서 영양 섭취와 건강면에서 좋은 건 사실이지만, 머리카락을 나게 하는 효과는 과학적으로 검증되지 않았습니다. 어릴 때부터 꾸준히 먹어왔다면 탈모가 덜 일어날 아주 약간의 가능성은 있겠지만, **이미 진행 중인 탈모에는 큰 도움이 되지 않아요**. 결론적으로 민간요법이나 홈케어로 탈모 치료가 되지 않는다는 점을 알아두시는 것이 좋습니다.$AAA$, array['어성초', '검은콩', '탈모식품', '민간요법', '모발건강']::text[], 2023, '4e9PSxrsnm4-2', 'https://youtu.be/4e9PSxrsnm4?t=144s', null, '2023-06-08 00:00:00+00'::timestamptz, '2023-06-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$올바른 머리 감기 방법은 무엇인가요?$AAQ$, $AAA$두피 건강을 위해 미온수로 손에서 거품을 낸 뒤 손끝으로 부드럽게 감는 것이 중요합니다. 너무 뜨거운 물은 두피에 자극이 되고 너무 차가운 물은 노폐물 제거가 어렵기 때문에, **너무 뜨겁거나 차갑지 않은 미온수**로 감는 것이 좋아요.

샴푸는 머리 위에서 바로 짜지 말고 손에서 미리 거품을 내야 합니다. 손에서 거품을 내지 않고 젖은 모발을 비비면 모발이 손상되기 쉽거든요. 또한 손톱으로 긁듯이 감으면 두피에 손상을 줄 수 있으므로, **손끝을 사용해서 부드럽게 두피와 머리카락을 마사지하듯이 문지르는 것**이 좋습니다. 거품이 충분히 생긴 다음에는 샴푸 성분이 두피에 남지 않도록 구석구석 깨끗하게 헹궈 주세요. 린스나 트리트먼트는 두피에 닿으면 트러블을 유발할 수 있어 머리카락에만 발라야 합니다.$AAA$, array['머리감기', '샴푸방법', '두피관리', '미온수', '거품세정']::text[], 2023, '4e9PSxrsnm4-3', 'https://youtu.be/4e9PSxrsnm4?t=309s', null, '2023-06-08 00:00:00+00'::timestamptz, '2023-06-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$한쪽으로만 가르마를 타면 정말 탈모가 오나요?$AAQ$, $AAA$한쪽으로만 가르마를 타면 자외선에 의해 그 부위에 탈모가 올 수 있습니다. 평소에 한쪽으로만 가르마를 타면 그 부위의 두피만 지속적으로 자외선에 노출되기 때문에 **탈모 현상이 올 수 있으므로, 주기적으로 가르마를 바꿔 주는 것이 좋습니다**.

여름철 강한 자외선에 두피가 장시간 노출되면 일광 화상을 입을 수 있고, 이로 인해 모낭 조직이 파괴되거나 피부염이 발생해 탈모까지 올 수 있어요. 실제로 여름 휴가 후 가르마 부위에 화상을 입어 내원하시는 분들이 꽤 있다고 합니다. 햇빛이 강한 낮 시간에 활동하신다면 모자나 양산 사용을 권해 드려요. 또한 머리를 너무 꽉 묶거나 핀을 같은 부위에 계속 꽂으면 **반복적으로 당겨지는 힘 때문에 모낭이 손상돼 견인성 탈모**가 발생할 수 있으니, 묶을 땐 아래쪽으로 살짝 묶는 것이 좋습니다.$AAA$, array['가르마탈모', '자외선두피', '견인성탈모', '두피화상', '모낭손상']::text[], 2023, '4e9PSxrsnm4-4', 'https://youtu.be/4e9PSxrsnm4?t=521s', null, '2023-06-08 00:00:00+00'::timestamptz, '2023-06-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$아침과 저녁 중 언제 머리를 감는 게 좋나요?$AAQ$, $AAA$두피와 모발 건강을 위해서는 저녁에 머리를 감는 것이 좋습니다. 밖에 나가면 미세먼지나 황사, 매연 같은 것들이 머리카락에 달라붙기 때문에 외출 후 손 씻고 세수하듯 **머리도 저녁에 감고 자는 것**이 권장됩니다.

아침에 감으시는 분들은 주로 스타일링 때문이지만, 두피와 모발 건강의 측면만 보면 저녁 세정이 우선입니다. 특히 헤어스프레이나 헤어젤 같은 제품을 사용했다면 화학 성분이 머리카락에 오래 달라붙어 있지 못하도록 자기 전에 반드시 머리를 감아서 씻어내는 것이 중요해요. 외출 후 두피에 쌓인 노폐물을 그대로 둔 채 잠자리에 들면 모발 건강에 좋지 않으니, **두피 청결을 위한 저녁 세정 습관**을 들이는 것이 좋습니다.$AAA$, array['저녁머리감기', '두피청결', '미세먼지', '모발건강', '헤어스타일링']::text[], 2023, 'pr5LAfov1rY-1', 'https://youtu.be/pr5LAfov1rY?t=70s', null, '2023-06-13 00:00:00+00'::timestamptz, '2023-06-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$때를 자주 미는 것이 피부에 좋은가요?$AAQ$, $AAA$과도하게 때를 밀면 피부 보호 기능이 손상되어 오히려 피부에 해롭습니다. 피부의 가장 중요한 기능은 보호 기능이고, 그 핵심 역할을 하는 것이 바로 **각질층입니다**.

각질층은 피부 가장 바깥쪽에 위치하면서 외부로부터 세균이 들어오지 못하게 하고 수분이 밖으로 나가지 않도록 막아줘요. 과도하게 때를 밀면 보호 기능이 손상되고 피부에서 수분이 날아가게 됩니다. 그리고 역설적으로 **각질층의 때를 많이 밀게 되면 오히려 피부는 더 많은 각질을 생성하게 돼요**. 몸에 붙은 먼지나 땀은 때를 밀지 않고 샤워만으로도 충분히 제거가 가능하므로, 때를 미는 대신에 샤워 후 보습제를 충분히 사용해서 피부 건강을 지켜주시는 것이 좋습니다. 아토피 피부염이나 발진, 가려움이 있는 분들은 특히 찜질방·사우나에서 때 미는 것을 피하셔야 합니다.$AAA$, array['때밀기', '각질층', '피부장벽', '보호기능', '보습']::text[], 2023, 'pr5LAfov1rY-2', 'https://youtu.be/pr5LAfov1rY?t=159s', null, '2023-06-13 00:00:00+00'::timestamptz, '2023-06-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$마스크팩을 오래 붙이고 자도 괜찮은가요?$AAQ$, $AAA$마스크팩을 오래 붙이거나 붙인 채 자는 것은 피부에 오히려 해롭습니다. 마스크팩 성분이 좋다고 30분, 1시간씩 오래 붙이는 분들이 많지만, 시간이 지나면서 **마스크팩 성분이 건조되며 증발할 때 피부 표면 수분까지 빼앗아가요**.

그래서 오래 붙이면 피부가 더 건조해질 수 있어요. 또한 자는 동안 계속 밀착되어 있으면 노폐물 배출에 방해가 되고 유수분 밸런스가 깨져서 피부 트러블이 생길 수 있습니다. **마스크팩 뒷면에 표시된 권장 시간**에 맞춰 사용하는 것이 좋아요. 1일 1팩이 한때 연예인 관리법으로 알려졌지만, 건강한 피부가 아닌 경우 오히려 자극이 될 수 있고 특히 민감성 피부나 지루성 피부염, 아토피가 있다면 1일 1팩은 피하는 것이 좋습니다.$AAA$, array['마스크팩', '팩사용시간', '피부건조', '유수분밸런스', '팩부작용']::text[], 2023, 'pr5LAfov1rY-3', 'https://youtu.be/pr5LAfov1rY?t=263s', null, '2023-06-13 00:00:00+00'::timestamptz, '2023-06-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$샤워할 때 머리와 몸 중 어느 쪽을 먼저 씻어야 하나요?$AAQ$, $AAA$몸을 먼저 씻고 머리를 나중에 감는 것이 피부에 더 좋습니다. 만약 샴푸를 나중에 하면 **샴푸의 알코올 등 화학 성분이나 트리트먼트·린스의 성분 일부가 몸에 남아 피부 트러블을 유발할 수 있어요**.

샴푸는 바디워시 제품들보다 머리카락을 씻어내기 위해 더 세정력이 좋습니다. 그래서 그만큼 강력하고 많은 계면 활성제가 들어가 있기 때문에 피부에 남아있을 경우 자극이 더 될 수 있고, 건조한 피부를 더 건조하게 만들 수 있어요. 또한 샤워하면서 동시에 세수까지 하려고 샤워기로 얼굴에 직접 물을 맞으시는 분들이 있는데, **수압이 세서 피부 장벽이 손상되는 경우**가 있으니 얼굴은 따로 부드럽게 씻으시는 것이 좋습니다.$AAA$, array['샤워순서', '샴푸잔여물', '계면활성제', '피부장벽', '세정순서']::text[], 2023, 'pr5LAfov1rY-4', 'https://youtu.be/pr5LAfov1rY?t=420s', null, '2023-06-13 00:00:00+00'::timestamptz, '2023-06-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스티바A는 처음에 어떻게 시작해야 안전한가요?$AAQ$, $AAA$스티바A 입문자나 피부가 예민한 분들은 0.01% 농도로 쌀 한 톨 양부터 시작하는 것이 안전합니다. 보습제와 충분히 희석해서 발라야 트러블을 예방할 수 있어요.

양은 처음에는 쌀 한 톨, 즉 약 입구에 묻어있는 정도를 덜어내는 양이며, 보습제는 검지 한 마디 정도를 짜서 함께 섞어 얼굴 전체에 바릅니다. **꼭 밤에 취침 전에 바르시는 게 중요**하고, 일주일 정도 이 비율로 사용하다가 양을 쌀 두 톨, 세 톨, 네 톨로 점진적으로 늘려가세요. 특별히 문제가 없으면 완두콩 한 알 정도의 양까지 사용 가능합니다. 한 두세 달 정도 0.01%를 발라 별다른 문제가 없으면 0.025%, 그다음 0.05%로 단계업 할 수 있고, **단계업 하는 방법은 0.01% 시작 시와 동일하게** 양을 점차 늘리는 방식입니다.$AAA$, array['스티바A', '트레티노인', '사용법', '희석', '보습제혼합']::text[], 2023, '_BpNOZ1RUSo-1', 'https://youtu.be/_BpNOZ1RUSo?t=109s', null, '2023-06-16 00:00:00+00'::timestamptz, '2023-06-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스티바A 사용 시 어떤 보습제가 가장 좋은가요?$AAQ$, $AAA$스티바A와 함께 쓸 때는 세라마이드·콜레스테롤·지방산이 함유된 보습제, 줄여서 '세콜지'를 사용하는 것이 좋습니다. 이러한 성분이 **피부 장벽을 구성하는 핵심 성분**이기 때문이에요.

세콜지 보습제는 단순히 스티바A 농도를 적절하게 희석해주는 역할만 하는 것이 아니라, **보습제 자체가 피부 장벽을 튼튼하게 해줘서 스티바A 연고로 인한 부작용을 완화시켜주는 효과**도 있습니다. 평상시에는 스티바 연고 0.025%를 완두콩 한 알 양으로 보습제 검지 한 마디와 섞어 사용하고, 컨디션이 떨어질 땐 아예 쉬거나 0.01%를 완두콩 반 알 양으로 줄여 보습제와 섞어 사용합니다. 촬영처럼 중요한 날에는 중단하고, 컨디션이 좋고 집에만 있을 땐 가끔 0.05%를 충분히 희석해 사용하는 방식으로 운용해요.$AAA$, array['세콜지', '세라마이드', '콜레스테롤', '지방산', '피부장벽']::text[], 2023, '_BpNOZ1RUSo-2', 'https://youtu.be/_BpNOZ1RUSo?t=233s', null, '2023-06-16 00:00:00+00'::timestamptz, '2023-06-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스티바A 사용 후 피부에 트러블이 생기면 어떻게 해야 하나요?$AAQ$, $AAA$트러블이 생기면 일단 사용을 중단하고 일주일 정도 보습제만 발라 피부를 진정시켜야 합니다. 증상이 심하면 병원에서 적절한 치료를 받는 것이 도움이 될 수 있어요.

피부가 충분히 진정된 후 다시 사용을 원하시면 **투여 간격을 매일 바르던 것에서 2~3일에 한 번으로 늘리거나** 농도를 더 희석해서 발라보는 것이 좋습니다. 한편 드물게 과색소 침착이 생길 수 있는데, 이때는 밤에 바른 후 다음 날 아침에 충분히 세안했는지, 자외선 차단제를 잘 사용했는지 먼저 확인해야 합니다. **스티바 성분이 일부 남아있는 상태에서 일상생활을 하면 태양 광선 감수성이 증가**해 염증이 생기고 염증후 색소침착으로 이어질 수 있기 때문이에요. 기미는 자극에 매우 약해 약간의 자극으로도 짙어질 수 있으므로, 이때도 사용 중단 또는 추가 희석이 권장됩니다.$AAA$, array['스티바부작용', '트러블대처', '색소침착', '자외선차단', '사용중단']::text[], 2023, '_BpNOZ1RUSo-3', 'https://youtu.be/_BpNOZ1RUSo?t=374s', null, '2023-06-16 00:00:00+00'::timestamptz, '2023-06-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스티바A 효과는 얼마나 발라야 나타나나요?$AAQ$, $AAA$스티바A 효과를 보려면 적어도 6개월 이상 꾸준히 발라봐야 합니다. 트레티노인의 효과는 **천천히 그리고 장기간에 걸쳐서 나타나기** 때문이에요.

사용 초기에 약간의 붉은기나 각질이 올라오는 것은 정상 반응으로, 연고를 바름으로써 각질의 턴오버 주기가 빨라지기 때문에 당연한 증상입니다. 단, 증상이 너무 심해서 따갑고 후끈거리고 진물이 나면 당연히 중단해야 해요. 또한 레티노이드는 빛에 약하기 때문에 **LED 치료와 병행할 경우 LED를 먼저 사용한 후 스티바 연고를 바르는** 것이 효과 보존에 유리합니다. 리프팅 시술 전후에는 사용을 피하고, 예민한 피부라면 일주일 정도 쉬는 것이 안전해요. 그리고 스티바 연고는 전문의약품으로 반드시 처방이 필요하므로 직구 대신 전문의 처방을 받아 구매하시기 바랍니다.$AAA$, array['트레티노인효과', '사용기간', '각질턴오버', 'LED병행', '처방의약품']::text[], 2023, '_BpNOZ1RUSo-4', 'https://youtu.be/_BpNOZ1RUSo?t=481s', null, '2023-06-16 00:00:00+00'::timestamptz, '2023-06-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$모기에 물리면 왜 붓고 가려운가요?$AAQ$, $AAA$모기 타액 속 히루딘에 우리 몸이 반응해 히스타민을 분비하기 때문에 붓고 가려운 증상이 나타납니다. 가려움은 일종의 **방어기전**이라고 할 수 있어요.

모기는 우리 피를 빨아먹을 때 모세혈관에 침을 꽂는데, 그냥 피만 빨아먹는 게 아니라 타액도 함께 분비합니다. 가느다란 혈관에 구멍이 나면 응고작용이 일어나기 때문에, 모기는 피가 굳지 않게 하려고 히루딘이라는 물질을 주입해요. 그런데 **히루딘은 우리 몸 입장에서는 외부 물질이라 우리 몸이 히스타민을 분비해 대응**하게 됩니다. 이 히스타민이 혈관을 늘어나게 하고, 늘어난 혈관 안의 혈장이 밖으로 새면서 피부가 붓고 가려운 증상이 나타나는 것이죠. 참고로 모기는 침 끝의 감각모에 후각수용체가 있어 피 냄새를 맡아 모세혈관을 정확히 찾아내며, 한 번 물면 30초면 다 빨아먹는다고 합니다.$AAA$, array['모기물림', '히스타민', '히루딘', '가려움기전', '혈관확장']::text[], 2023, 'hH6enXo1fIU-1', 'https://youtu.be/hH6enXo1fIU?t=80s', null, '2023-06-22 00:00:00+00'::timestamptz, '2023-06-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$모기에 잘 물리는 사람은 정말 따로 있나요?$AAQ$, $AAA$땀이 많거나 체온이 높거나 술을 마신 사람이 실제로 모기에 더 잘 물립니다. 모기는 **20미터 밖에서도 냄새를 맡을 수 있고, 땀이나 암모니아 냄새에 강하게 반응**하기 때문이에요.

아이들이 어른보다 더 잘 물리는 것도 대사가 더 활발해서 모기들이 잘 찾아가기 때문이고, 술을 마시면 대사가 활발해지면서 열과 땀이 나고, 그 땀 속 알코올이 분해되면서 생기는 요산과 암모니아 성분 때문에 모기가 술 마신 사람을 잘 뭅니다. 한편 모기기피제는 **디에틸톨루아미드와 이카리딘** 두 가지 성분이 대표적이며, 디에틸톨루아미드는 신경독성 우려로 만 12세 이상에게 권고되고, **이카리딘은 만 6개월 이상부터 사용 가능하며 임산부와 수유부도 사용 가능합니다**. 모기퇴치 팔찌는 시트로넬라·오렌지 계열 향이 들어있어도 의약외품이 아닌 공산품이라 효과는 입증되지 않았습니다.$AAA$, array['모기기피제', '이카리딘', '디에틸톨루아미드', '땀냄새', '모기예방']::text[], 2023, 'hH6enXo1fIU-2', 'https://youtu.be/hH6enXo1fIU?t=218s', null, '2023-06-22 00:00:00+00'::timestamptz, '2023-06-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$모기에 물렸을 때 어떻게 해야 덜 가려운가요?$AAQ$, $AAA$모기 물린 부위를 차갑게 하면 가려움증을 효과적으로 완화할 수 있습니다. 얼음을 얇은 천에 싸서 대거나 아이스팩을 활용하면 **혈관이 수축하면서 히스타민 분비가 줄어들기** 때문이에요.

또한 피부를 차갑게 하면 차가운 감각을 느끼는 신경자극이 활성화돼서 가려운 느낌이 덜 느껴집니다. 어렸을 때 침을 발랐던 것도 침을 바르면 시원해져서 덜 가려운 원리이지만, 위생상 균이 들어갈 수 있으므로 얼음을 이용하는 것이 좋아요. 시중 약은 항히스타민제, 국소마취제, 피부발적제 세 가지 성분이 핵심이며, **항히스타민제는 히스타민 분비를 억제하고, 국소마취제는 피부를 마취시키며, 피부발적제는 화끈하게 만들어 가려움을 못 느끼게** 합니다. 흉터처럼 보이는 까만 자국은 사실 염증후 색소침착으로, 팔다리는 색소가 오래 가는 부위라 잘 안 빠지는 경우 피부과에서 레이저 토닝으로 치료할 수 있습니다.$AAA$, array['모기물림가려움', '냉찜질', '항히스타민', '피부발적제', '색소침착']::text[], 2023, 'hH6enXo1fIU-3', 'https://youtu.be/hH6enXo1fIU?t=481s', null, '2023-06-22 00:00:00+00'::timestamptz, '2023-06-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레이저를 받으면 피부가 얇아지고 예민해지나요?$AAQ$, $AAA$모든 레이저가 피부를 얇고 예민하게 만드는 것은 아니며, 일부 강한 레이저만 그럴 수 있습니다. **반은 맞고 반은 틀린 이야기**라고 할 수 있어요.

흉터나 모공 치료에 쓰는 프랙셔널 레이저, 흔히 프락셀이라고 하는 종류는 피부에 미세한 상처를 내서 재생되는 과정을 통해 효과를 내기 때문에 에너지가 강할 수밖에 없습니다. **너무 자주 하거나 강하게 하면 빨개지고 민감해지는 느낌**을 받을 수 있어요. 반면 레이저 토닝이나 브이빔 같은 레이저들은 그렇게 강하지도 않고 피부 속에 상처를 내는 레이저도 아니어서 예민해지지 않습니다. 만약 프랙셔널 레이저를 받는다면 시술 간격을 충분히 지켜 피부가 재생될 기회를 주고, 시술 후 재생크림이나 병원에서 권하는 스킨케어로 회복을 도우면 민감해지는 부작용을 예방할 수 있어요.$AAA$, array['프랙셔널레이저', '프락셀', '레이저토닝', '브이빔', '피부민감']::text[], 2023, 'lePADIgTkhQ-1', 'https://youtu.be/lePADIgTkhQ?t=47s', null, '2023-06-29 00:00:00+00'::timestamptz, '2023-06-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레이저 후 모낭염은 왜 생기고 어떻게 치료하나요?$AAQ$, $AAA$레이저 에너지가 솜털을 통해 모낭에 전달되며 염증이 일어나 모낭염이 발생합니다. 대부분 보습 잘하고 재생크림만 발라도 **2~3일이면 가라앉아요**.

레이저 빛이 피부 속에 들어가 열 에너지로 변환될 때, 피부의 솜털도 레이저 에너지를 흡수합니다. 그 솜털이 자기가 들어 있는 모낭에 열 에너지를 전달해 염증이 일어나는 것이 모낭염이에요. 가장 흔한 경우는 제모 시술 후이고, 레이저 토닝이나 브이빔 같은 홍조 레이저 후에도 발생할 수 있습니다. **농이 잡히거나 가려움이 심하면 염증을 가라앉히는 먹는 약을 처방**받으면 금방 가라앉아요. 또한 레이저 전에 피부 상태를 보고 트러블이 예상되면 미리 예방하는 약을 처방하기도 합니다. 시술 후 빨개지고 오도도도 뭐가 올라오거나 노랗게 농 같은 게 잡히고 가려운 증상이 대표적이에요.$AAA$, array['모낭염', '레이저부작용', '제모후', '솜털열에너지', '재생크림']::text[], 2023, 'lePADIgTkhQ-2', 'https://youtu.be/lePADIgTkhQ?t=168s', null, '2023-06-29 00:00:00+00'::timestamptz, '2023-06-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레이저 후 색소침착이 생기면 치료할 수 있나요?$AAQ$, $AAA$레이저 후 과색소 침착은 대부분 시간이 지나면 저절로 좋아지며, 필요시 레이저 토닝이나 미백 관리로 치료할 수 있습니다. 다만 **저색소 침착, 즉 점박이처럼 하얗게 빠진 경우는 치료가 잘 안 됩니다**.

저색소 침착은 레이저 토닝 같은 색소 레이저에서 에너지가 일부분에 너무 강하게 들어가 멜라닌 세포 자체가 없어져 버려 발생하는데, 한 번 생기면 세포가 죽어버린 것이라 치료가 어려워요. 반대로 더 까매지는 과색소 침착은 더 흔한 부작용이며, 특히 기미 치료 시 강하게 치료하면 색소 세포들이 화를 내며 색소를 더 만들어 오히려 짙어질 수 있습니다. IPL처럼 딱지가 강하게 생기는 레이저 후에는 보이지 않던 속 기미가 확 올라오는 경우도 있어, 레이저 전 **피부 촬영기로 속에 숨어 있는 기미가 있는지 확인**하는 것이 중요해요. 흑자나 잡티, CO2 레이저 후 색소침착도 대부분 시간이 지나면 해결됩니다.$AAA$, array['과색소침착', '저색소침착', '기미치료', 'IPL부작용', '레이저토닝']::text[], 2023, 'lePADIgTkhQ-3', 'https://youtu.be/lePADIgTkhQ?t=227s', null, '2023-06-29 00:00:00+00'::timestamptz, '2023-06-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부과에 가면 무조건 레이저를 받게 되나요?$AAQ$, $AAA$피부과에서 무조건 레이저를 권하는 것은 아니며, 피부 상태에 따라 시술이 어려울 때는 권하지 않습니다. **레이저가 무조건 답이 아니라는 점**을 알아두시는 것이 좋아요.

예를 들어 피부가 빨개서 레이저 치료를 원해 내원했지만 가렵거나 따갑거나 피부 장벽이 무너져 화끈거리는 증상이 동반된 경우, 이는 피부에 병이 있다는 의미입니다. **이 상태에서 레이저를 하면 피부가 더 확 뒤집어져 버려서** 아무리 환자가 원해도 시술을 하지 않습니다. 레이저는 피부 속에 에너지를 넣어주는 시술이라 피부가 그 에너지를 받아들일 컨디션이 되어야 하기 때문이에요. 이럴 때는 필요에 따라 약을 먹거나 연고를 바르고, 피부를 진정시키거나 건강하게 끌어올려 줄 스킨케어와 피부 관리를 진행합니다. 치료 전 의사와 상세히 상담해 자신의 피부 상태를 파악하는 과정이 꼭 필요합니다.$AAA$, array['피부과진료', '레이저적합성', '피부장벽', '시술금기', '맞춤치료']::text[], 2023, 'lePADIgTkhQ-4', 'https://youtu.be/lePADIgTkhQ?t=423s', null, '2023-06-29 00:00:00+00'::timestamptz, '2023-06-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$써마지는 리프팅 시술인가요, 타이트닝 시술인가요?$AAQ$, $AAA$써마지는 리프팅이 아닌 **타이트닝 장비**로, 주름과 탄력 개선이 주된 목적입니다. 처진 피부를 끌어올리는 시술이 아니라는 점을 알아두시는 것이 좋아요.

써마지는 피부가 흐물흐물하고 탄력이 없고 푸석푸석할 때 콜라겐을 재생시켜 피부 두께와 피부층의 탄탄함을 개선하는 고주파 장비입니다. 그 결과 모공이 좋아지고 피부가 쫀쫀해 보이며 화장도 잘 먹고 촉촉해지는 효과가 나타나요. **써마지의 대표적인 장점은 아큐랩 기술로 피부 저항값을 측정해 가장 최적의 고주파 값을 전달**하는 것입니다. 국산 모노폴라 RF 중에서는 덴서티가 매 샷마다 환자 피부를 체크해 보상이 들어가는 유일한 장비이고, 쿨링 1~5단계 조절과 오토샷 기능이 있어 빠른 시술이 가능합니다. 잔주름이 많은 40~50대 환자에게 적합한 시술이에요.$AAA$, array['써마지', '타이트닝', '고주파', '콜라겐재생', '아큐랩']::text[], 2023, 'mwN3RtM8jMI-1', 'https://youtu.be/mwN3RtM8jMI?t=187s', null, '2023-07-05 00:00:00+00'::timestamptz, '2023-07-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$미라젯은 일반 주사 시술과 어떻게 다른가요?$AAQ$, $AAA$미라젯은 주사기 없이 초당 40회씩 분사되는 방식이라 다운타임이 매우 적고 일상 복귀가 빠른 시술입니다. 당일 오전 시술 후 오후 세수까지 가능할 정도로 **일상으로의 복귀가 가장 빠르다는 점**이 환자에게 베네핏이에요.

초당 40회씩 주사가 되는 속도로 피부에 밀착시켜 문지르듯 시술하는 방식인데, 주사를 직접 놓으면 아무리 촘촘히 해도 골고루 놓기 어렵습니다. 특히 코 부위나 눈가는 주사로 놓기 어렵고 멍이 많이 들고 아프기도 한 부위인데, **미라젯으로는 눈가나 코 주변처럼 주사 놓기 어려운 부위도 꼼꼼하게 시술이 가능**합니다. 주사기 없이 분사 방식으로 들어가기 때문에 골고루 분포되고 멍·통증 부담이 낮으며, 시술 직후에도 세안과 일상 활동에 큰 제약이 없다는 점이 미라젯의 차별점이에요.$AAA$, array['미라젯', '노니들', '다운타임', '눈가시술', '분사주사']::text[], 2023, 'mwN3RtM8jMI-2', 'https://youtu.be/mwN3RtM8jMI?t=125s', null, '2023-07-05 00:00:00+00'::timestamptz, '2023-07-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$텐쎄라는 다른 하이푸 리프팅 장비와 무엇이 다른가요?$AAQ$, $AAA$텐쎄라는 한 샷에 두 줄씩 나오는 초음파 하이푸 장비로, 시술 시간과 통증이 절반으로 줄어든 점이 특징입니다. **한 번 아프고 효과는 두 번 받는** 것과 같은 효율을 제공해요.

기존의 하이푸 장비들은 보통 한 줄이 나가는 방식이라 시술 시간이 오래 걸렸지만, 텐쎄라는 한 번에 두 줄이 동시에 나가서 시간이 절반으로 줄어들고 그만큼 통증도 절반으로 줄어들어요. 함께 부스에 있는 텐써마는 써마지 유사 장비로 **써마지와 동일하게 400W 출력**을 제공하며, 타사 제품들은 이 정도 출력에 도달하지 못한다고 합니다. 텐써마는 쿨링 가스가 많이 나와 화상 위험을 줄였고, 콜라겐들이 노화로 얽힌 부분을 풀어주며 열에너지로 콜라겐을 다시 생성시키는 장비입니다. 두 장비 모두 편하게 시술받을 수 있는 점이 장점이에요.$AAA$, array['텐쎄라', '텐써마', '하이푸', '두줄동시', '고주파출력']::text[], 2023, 'mwN3RtM8jMI-3', 'https://youtu.be/mwN3RtM8jMI?t=379s', null, '2023-07-05 00:00:00+00'::timestamptz, '2023-07-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$브이올렛 주사는 기존 윤곽주사와 어떻게 다른가요?$AAQ$, $AAA$브이올렛은 국내 유일하게 허가받은 지방 파괴 주사로, 효과가 반영구적인 점이 기존 윤곽주사와 다릅니다. 기존 윤곽주사는 지방을 분해하는 기전이라 다시 차오르지만, **브이올렛은 지방을 파괴하는 기전이라 효과가 반영구적**이에요.

가장 큰 차이점은 의약품으로 허가를 받았는지 여부입니다. **의약품 허가는 안전성과 유효성을 입증받았다는 의미**이며, 브이올렛은 유일하게 안전성과 유효성을 입증받은 지방 파괴 주사라고 할 수 있어요. 또한 브이올렛은 데옥시콜릭애씨드라는 단일 성분으로 되어 있어 스테로이드로 인한 부작용은 전혀 걱정하지 않아도 됩니다. 데옥시콜산 단독 성분이고 스테로이드는 없습니다. 이중턱이나 살을 빼는 데 좋은 주사로, 기존 지방 분해 주사처럼 지방이 다시 차오르는 일이 없다는 점이 임상적으로 의미 있는 차별점이에요.$AAA$, array['브이올렛', '데옥시콜산', '지방파괴', '이중턱', '윤곽주사']::text[], 2023, 'mwN3RtM8jMI-4', 'https://youtu.be/mwN3RtM8jMI?t=443s', null, '2023-07-05 00:00:00+00'::timestamptz, '2023-07-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$아토피 피부염은 어떤 원인으로 생기나요?$AAQ$, $AAA$아토피 피부염은 여러 원인이 복합적으로 작용하는 만성 염증성 피부 질환입니다. **가려움증을 동반한 만성 염증성 피부 질환**으로, 단일 원인이 아닌 여러 요인이 함께 작용해 발생해요.

대표적인 원인으로는 유전적 소인, 환자의 면역학적 이상, 피부 장벽의 이상, 그리고 환경적인 영향이 있습니다. 유전적 소인의 경우 부모 중 한 명이라도 아토피 피부염이나 천식, 알레르기 비염 같은 아토피 관련 질환이 있으면 자녀에게 생길 확률이 높아져요. 환경적 요인으로는 **스트레스, 수면 부족, 건조한 기후, 덥거나 땀이 나는 환경, 자외선, 대기 오염, 음주 같은 악화 인자들**이 있습니다. 그래서 한창 공부하며 스트레스받고 잠 못 자는 중고등학생 시절에 심해지는 경우가 많고, 어른이 되어서도 겨울철 건조함이나 음주 후 피부가 건조해질 때 다시 올라오곤 합니다.$AAA$, array['아토피피부염', '유전적소인', '피부장벽이상', '환경요인', '악화인자']::text[], 2023, 'Y0Eeq3BQU5w-1', 'https://youtu.be/Y0Eeq3BQU5w?t=164s', null, '2023-07-11 00:00:00+00'::timestamptz, '2023-07-11 00:00:00+00'::timestamptz);
